# Allowed file extensions for various upload types
ALLOWED_VIDEO_EXTENSIONS = {".mp4", ".mov", ".avi", ".webm"}
ALLOWED_PDF_EXTENSIONS = {".pdf"}
ALLOWED_IMAGE_EXTENSIONS = {".jpg", ".jpeg", ".png", ".gif", ".webp"}
ALLOWED_DOCUMENT_EXTENSIONS = {".pdf", ".doc", ".docx", ".xls", ".xlsx"}
ALLOWED_ALL_EXTENSIONS = ALLOWED_VIDEO_EXTENSIONS | ALLOWED_PDF_EXTENSIONS | ALLOWED_IMAGE_EXTENSIONS | ALLOWED_DOCUMENT_EXTENSIONS
MAX_FILE_SIZE = 500 * 1024 * 1024  # 500MB max for videos
DEFAULT_MAX_FILE_SIZE = 15 * 1024 * 1024  # 15MB default

# File magic bytes for content validation (prevents extension spoofing)
FILE_MAGIC_BYTES = {
    ".pdf": [b"%PDF"],
    ".jpg": [b"\xff\xd8\xff"],
    ".jpeg": [b"\xff\xd8\xff"],
    ".png": [b"\x89PNG\r\n\x1a\n"],
    ".gif": [b"GIF87a", b"GIF89a"],
    ".webp": [b"RIFF"],
    ".mp4": [b"\x00\x00\x00\x18ftyp", b"\x00\x00\x00\x1cftyp", b"\x00\x00\x00\x20ftyp", b"ftyp"],
    ".mov": [b"\x00\x00\x00\x14ftyp", b"moov"],
    ".avi": [b"RIFF"],
    ".webm": [b"\x1a\x45\xdf\xa3"],
    ".doc": [b"\xd0\xcf\x11\xe0\xa1\xb1\x1a\xe1"],  # OLE compound document
    ".docx": [b"PK\x03\x04"],  # ZIP-based Office format
    ".xls": [b"\xd0\xcf\x11\xe0\xa1\xb1\x1a\xe1"],  # OLE compound document
    ".xlsx": [b"PK\x03\x04"],  # ZIP-based Office format
}

def validate_file_content(file_bytes: bytes, expected_extension: str) -> bool:
    """
    Validate file content matches expected extension using magic bytes.
    Returns True if valid, False if content doesn't match extension.
    """
    ext = expected_extension.lower()
    if ext not in FILE_MAGIC_BYTES:
        return True  # No magic bytes defined, allow
    
    magic_signatures = FILE_MAGIC_BYTES[ext]
    # Check first 20 bytes for magic signature
    header = file_bytes[:20]
    
    for signature in magic_signatures:
        if signature in header[:len(signature) + 10]:
            return True
    
    return False


async def validated_file_upload(
    file: UploadFile,
    allowed_extensions: set,
    max_size_bytes: int = DEFAULT_MAX_FILE_SIZE,
    validate_content: bool = True,
    context: str = "file"
) -> tuple:
    """
    Centralized file upload validation utility.
    
    Args:
        file: FastAPI UploadFile object
        allowed_extensions: Set of allowed extensions (e.g., {".pdf", ".jpg"})
        max_size_bytes: Maximum file size in bytes
        validate_content: Whether to validate magic bytes
        context: Context for error messages (e.g., "document", "image")
    
    Returns:
        tuple: (file_content: bytes, safe_filename: str, file_extension: str)
    
    Raises:
        HTTPException: If validation fails
    """
    if not file or not file.filename:
        raise HTTPException(status_code=400, detail=f"No {context} file provided")
    
    # Get and validate extension
    original_filename = file.filename
    file_ext = Path(original_filename).suffix.lower()
    
    if file_ext not in allowed_extensions:
        allowed_list = ", ".join(sorted(allowed_extensions))
        raise HTTPException(
            status_code=400, 
            detail=f"Invalid {context} type: {file_ext}. Allowed: {allowed_list}"
        )
    
    # Read file content
    content = await file.read()
    
    # Validate file size
    if len(content) > max_size_bytes:
        max_mb = max_size_bytes // (1024 * 1024)
        raise HTTPException(
            status_code=400, 
            detail=f"{context.capitalize()} too large. Maximum size is {max_mb}MB"
        )
    
    # Validate content matches extension (magic bytes check)
    if validate_content and not validate_file_content(content, file_ext):
        raise HTTPException(
            status_code=400, 
            detail=f"File content does not match extension {file_ext}. Possible file type spoofing detected."
        )
    
    # Generate safe filename
    safe_filename = f"{uuid.uuid4().hex}{file_ext}"
    
    return content, safe_filename, file_ext


