# ============ AUTH HELPERS ============

async def get_current_user(request: Request) -> User:
    """Get current user from session token (cookie or header)"""
    # Try cookie first
    session_token = request.cookies.get("session_token")
    
    # Fallback to Authorization header
    if not session_token:
        auth_header = request.headers.get("Authorization")
        if auth_header and auth_header.startswith("Bearer "):
            session_token = auth_header.split(" ")[1]
    
    if not session_token:
        raise HTTPException(status_code=401, detail="Not authenticated")
    
    # Find session
    session_doc = await db.user_sessions.find_one(
        {"session_token": session_token},
        {"_id": 0}
    )
    
    if not session_doc:
        raise HTTPException(status_code=401, detail="Invalid session")
    
    # Check expiry with timezone handling
    expires_at = session_doc["expires_at"]
    if isinstance(expires_at, str):
        expires_at = datetime.fromisoformat(expires_at)
    if expires_at.tzinfo is None:
        expires_at = expires_at.replace(tzinfo=timezone.utc)
    if expires_at < datetime.now(timezone.utc):
        raise HTTPException(status_code=401, detail="Session expired")
    
    # Get user
    user_doc = await db.users.find_one(
        {"user_id": session_doc["user_id"]},
        {"_id": 0}
    )
    
    if not user_doc:
        raise HTTPException(status_code=401, detail="User not found")
    
    # Handle datetime conversion
    if isinstance(user_doc.get("created_at"), str):
        user_doc["created_at"] = datetime.fromisoformat(user_doc["created_at"])
    elif user_doc.get("created_at") is None:
        user_doc["created_at"] = datetime.now(timezone.utc)
    
    return User(**user_doc)

async def require_admin(request: Request) -> User:
    """Require admin.system_settings permission (legacy helper - prefer direct has_permission checks)"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    if not has_permission(user_doc, "admin.system_settings"):
        raise HTTPException(status_code=403, detail="Admin access required - needs admin.system_settings permission")
    return user

# ============ AUTH ENDPOINTS ============

@api_router.post("/auth/session")
async def create_session(request: SessionRequest, response: Response):
    """Exchange session_id for session_token and create/update user"""
    try:
        # Call Emergent auth API to get user data
        async with httpx.AsyncClient() as client_http:
            auth_response = await client_http.get(
                "https://demobackend.emergentagent.com/auth/v1/env/oauth/session-data",
                headers={"X-Session-ID": request.session_id}
            )
            
            if auth_response.status_code != 200:
                raise HTTPException(status_code=401, detail="Invalid session_id")
            
            auth_data = auth_response.json()
        
        email = auth_data["email"]
        name = auth_data["name"]
        picture = auth_data.get("picture")
        session_token = auth_data["session_token"]
        
        now = datetime.now(timezone.utc)
        
        # Check if user exists
        existing_user = await db.users.find_one({"email": email}, {"_id": 0})
        
        if existing_user:
            user_id = existing_user["user_id"]
            
            # Check if user is inactive
            if existing_user.get("status") == "Inactive":
                raise HTTPException(status_code=403, detail="Your account is inactive. Please contact an administrator.")
            
            # Update user info and last_login
            initials = "".join([n[0].upper() for n in name.split()[:2]]) if name else "U"
            await db.users.update_one(
                {"user_id": user_id},
                {"$set": {
                    "name": name, 
                    "picture": picture,
                    "initials": initials,
                    "last_login": now.isoformat(),
                    "updated_at": now.isoformat()
                }}
            )
            role = existing_user["role"]
        else:
            # Check if this is the first user (becomes Admin)
            user_count = await db.users.count_documents({})
            role = "Admin" if user_count == 0 else "Designer"
            
            # Create new user
            user_id = f"user_{uuid.uuid4().hex[:12]}"
            initials = "".join([n[0].upper() for n in name.split()[:2]]) if name else "U"
            new_user = {
                "user_id": user_id,
                "email": email,
                "name": name,
                "picture": picture,
                "role": role,
                "phone": None,
                "status": "Active",
                "initials": initials,
                "created_at": now.isoformat(),
                "updated_at": now.isoformat(),
                "last_login": now.isoformat()
            }
            await db.users.insert_one(new_user)
        
        # Create session
        session_doc = {
            "user_id": user_id,
            "session_token": session_token,
            "expires_at": (datetime.now(timezone.utc) + timedelta(hours=24)).isoformat(),
            "created_at": datetime.now(timezone.utc).isoformat()
        }
        
        # Remove old sessions for this user
        await db.user_sessions.delete_many({"user_id": user_id})
        await db.user_sessions.insert_one(session_doc)
        
        # Set cookie
        response.set_cookie(
            key="session_token",
            value=session_token,
            httponly=True,
            secure=True,
            samesite="lax",  # Changed from "none" - prevents CSRF while allowing normal navigation
            path="/",
            max_age=24 * 60 * 60  # 24 hours (reduced from 7 days for security)
        )
        
        # Get fresh user data
        user_doc = await db.users.find_one({"user_id": user_id}, {"_id": 0})
        
        return {
            "user_id": user_doc["user_id"],
            "email": user_doc["email"],
            "name": user_doc["name"],
            "picture": user_doc.get("picture"),
            "role": user_doc["role"]
        }
        
    except httpx.RequestError as e:
        logger.error(f"Auth API request failed: {e}")
        raise HTTPException(status_code=500, detail="Authentication service error")

@api_router.get("/auth/me")
async def get_me(request: Request):
    """Get current authenticated user with permissions - includes auto-repair of missing permissions"""
    user = await get_current_user(request)
    
    # Get full user doc for permissions
    user_doc = await db.users.find_one({"user_id": user.user_id}, {"_id": 0})
    if not user_doc:
        user_doc = {"role": user.role, "user_id": user.user_id}
    
    # PERMISSION SAFETY NET: Repair permissions on every /auth/me call (session resume)
    # This ensures users with existing sessions also get fixed
    user_doc = await ensure_user_permissions(user.user_id, user_doc)
    
    effective_permissions = get_user_permissions(user_doc)
    
    # Check if user is the System Owner/Founder
    user_is_founder = is_founder(user_doc)
    
    return {
        "user_id": user.user_id,
        "email": user.email,
        "name": user.name,
        "picture": user.picture,
        "role": user.role,
        "is_founder": user_is_founder,  # True if this is the System Owner
        "custom_permissions": user_doc.get("custom_permissions", False),
        "permissions": user_doc.get("permissions", []),
        "effective_permissions": effective_permissions
    }

@api_router.post("/auth/logout")
async def logout(request: Request, response: Response):
    """Logout and clear session"""
    session_token = request.cookies.get("session_token")
    
    if session_token:
        await db.user_sessions.delete_one({"session_token": session_token})
    
    response.delete_cookie(key="session_token", path="/")
    return {"message": "Logged out successfully"}


# ============ DIRECT GOOGLE OAUTH ============

@api_router.get("/auth/google/login")
async def google_login(request: Request):
    """
    Initiates Google OAuth flow.
    Redirects user to Google's consent screen.
    """
    if not GOOGLE_CLIENT_ID or not GOOGLE_CLIENT_SECRET:
        raise HTTPException(
            status_code=500, 
            detail="Google OAuth not configured. Set GOOGLE_CLIENT_ID and GOOGLE_CLIENT_SECRET."
        )
    
    # Build the Google OAuth URL
    params = {
        "client_id": GOOGLE_CLIENT_ID,
        "redirect_uri": GOOGLE_REDIRECT_URI,
        "response_type": "code",
        "scope": "openid email profile",
        "access_type": "offline",
        "prompt": "select_account"
    }
    
    auth_url = f"{GOOGLE_AUTH_URL}?{urlencode(params)}"
    logger.info(f"Redirecting to Google OAuth: {auth_url}")
    
    return RedirectResponse(url=auth_url)


@api_router.get("/auth/google/callback")
async def google_callback(request: Request, response: Response, code: str = None, error: str = None):
    """
    Handles Google OAuth callback.
    Exchanges authorization code for tokens, creates/updates user, sets session cookie.
    """
    if error:
        logger.error(f"Google OAuth error: {error}")
        return RedirectResponse(url=f"{FRONTEND_URL}/login?error={error}")
    
    if not code:
        logger.error("No authorization code received from Google")
        return RedirectResponse(url=f"{FRONTEND_URL}/login?error=no_code")
    
    try:
        # Exchange authorization code for tokens
        async with httpx.AsyncClient() as client_http:
            token_response = await client_http.post(
                GOOGLE_TOKEN_URL,
                data={
                    "client_id": GOOGLE_CLIENT_ID,
                    "client_secret": GOOGLE_CLIENT_SECRET,
                    "code": code,
                    "grant_type": "authorization_code",
                    "redirect_uri": GOOGLE_REDIRECT_URI
                },
                headers={"Content-Type": "application/x-www-form-urlencoded"}
            )
            
            if token_response.status_code != 200:
                logger.error(f"Token exchange failed: {token_response.text}")
                return RedirectResponse(url=f"{FRONTEND_URL}/login?error=token_exchange_failed")
            
            tokens = token_response.json()
            id_token_jwt = tokens.get("id_token")
            access_token = tokens.get("access_token")
            
            if not id_token_jwt:
                logger.error("No ID token in response")
                return RedirectResponse(url=f"{FRONTEND_URL}/login?error=no_id_token")
        
        # Verify the ID token using Google's public keys
        try:
            idinfo = id_token.verify_oauth2_token(
                id_token_jwt,
                google_requests.Request(),
                GOOGLE_CLIENT_ID
            )
            
            # Extract user info from verified token
            email = idinfo.get("email")
            name = idinfo.get("name", email.split("@")[0])
            picture = idinfo.get("picture")
            google_sub = idinfo.get("sub")  # Google's unique user ID
            
            if not email:
                logger.error("No email in ID token")
                return RedirectResponse(url=f"{FRONTEND_URL}/login?error=no_email")
                
        except ValueError as e:
            logger.error(f"ID token verification failed: {e}")
            return RedirectResponse(url=f"{FRONTEND_URL}/login?error=invalid_token")
        
        now = datetime.now(timezone.utc)
        
        # Check if user exists by email
        existing_user = await db.users.find_one({"email": email}, {"_id": 0})
        
        if existing_user:
            user_id = existing_user["user_id"]
            
            # Check if user is inactive
            if existing_user.get("status") == "Inactive":
                logger.warning(f"Inactive user attempted login: {email}")
                return RedirectResponse(url=f"{FRONTEND_URL}/login?error=account_inactive")
            
            # Update user info and last_login (also add google_sub if missing)
            initials = "".join([n[0].upper() for n in name.split()[:2]]) if name else "U"
            await db.users.update_one(
                {"user_id": user_id},
                {"$set": {
                    "name": name,
                    "picture": picture,
                    "initials": initials,
                    "google_sub": google_sub,
                    "last_login": now.isoformat(),
                    "updated_at": now.isoformat()
                }}
            )
            
            # PERMISSION SAFETY NET: Ensure user has valid permissions
            existing_user = await ensure_user_permissions(user_id, existing_user)
            
            role = existing_user["role"]
            logger.info(f"Existing user logged in via Google: {email}")
        else:
            # Determine role for new user:
            # 1. If email matches FOUNDER_EMAIL -> Founder role
            # 2. If first user -> Admin role
            # 3. Otherwise -> Designer role
            user_count = await db.users.count_documents({})
            
            if email == FOUNDER_EMAIL:
                role = "Founder"
                logger.info(f"SYSTEM OWNER: {email} assigned Founder role")
            elif user_count == 0:
                role = "Admin"
            else:
                role = "Designer"
            
            # Get default permissions for the role (MANDATORY - never empty)
            default_perms = DEFAULT_ROLE_PERMISSIONS.get(role, DEFAULT_ROLE_PERMISSIONS.get("Designer", []))
            
            # Create new user with GUARANTEED permissions
            user_id = f"user_{uuid.uuid4().hex[:12]}"
            initials = "".join([n[0].upper() for n in name.split()[:2]]) if name else "U"
            new_user = {
                "user_id": user_id,
                "email": email,
                "name": name,
                "picture": picture,
                "role": role,
                "phone": None,
                "status": "Active",
                "initials": initials,
                "google_sub": google_sub,
                "auth_provider": "google",
                "permissions": default_perms,  # MANDATORY: Never empty
                "created_at": now.isoformat(),
                "updated_at": now.isoformat(),
                "last_login": now.isoformat()
            }
            await db.users.insert_one(new_user)
            
            if role == "Founder":
                logger.info(f"SYSTEM OWNER CREATED: {email} with {len(default_perms)} permissions")
            elif role == "Admin":
                logger.info(f"FIRST USER: {email} created as Admin with {len(default_perms)} permissions")
            else:
                logger.info(f"New user created via Google OAuth: {email} (role: {role}, permissions: {len(default_perms)})")
        
        # Create session token
        session_token = secrets.token_urlsafe(32)
        expires_at = datetime.now(timezone.utc) + timedelta(hours=24)
        
        # Remove old sessions for this user
        await db.user_sessions.delete_many({"user_id": user_id})
        
        # Create new session
        await db.user_sessions.insert_one({
            "user_id": user_id,
            "session_token": session_token,
            "expires_at": expires_at.isoformat(),
            "created_at": now.isoformat(),
            "login_type": "google"
        })
        
        # Create redirect response with cookie
        redirect_response = RedirectResponse(url=f"{FRONTEND_URL}/dashboard", status_code=302)
        
        # Set session cookie (same flags as local login)
        redirect_response.set_cookie(
            key="session_token",
            value=session_token,
            httponly=True,
            secure=True,
            samesite="lax",  # Changed from "none" - prevents CSRF while allowing normal navigation
            max_age=24 * 60 * 60,  # 24 hours (reduced from 7 days for security)
            path="/"
        )
        
        logger.info(f"Google OAuth successful for: {email}")
        return redirect_response
        
    except Exception as e:
        logger.error(f"Google OAuth callback error: {str(e)}")
        return RedirectResponse(url=f"{FRONTEND_URL}/login?error=callback_failed")


# ============ LOCAL LOGIN SYSTEM ============

@api_router.post("/auth/local-login")
@limiter.limit("5/minute")  # Rate limit: 5 login attempts per minute per IP
async def local_login(request: Request, credentials: LocalLoginRequest, response: Response):
    """
    Local login for testing outside Emergent environment.
    This does NOT replace Google OAuth - it's an additional option for local testing.
    Includes automatic migration of legacy SHA-256 passwords to bcrypt.
    
    Rate limited: 5 attempts per minute per IP address.
    """
    # Find user by email with local password
    user_doc = await db.users.find_one(
        {"email": credentials.email, "local_password": {"$exists": True}},
        {"_id": 0}
    )
    
    if not user_doc:
        raise HTTPException(status_code=401, detail="Authentication failed")
    
    stored_hash = user_doc.get("local_password", "")
    
    # Verify password
    if not verify_password(credentials.password, stored_hash):
        raise HTTPException(status_code=401, detail="Authentication failed")
    
    # Auto-migrate legacy SHA-256 passwords to bcrypt
    if stored_hash and not stored_hash.startswith('$2'):
        await migrate_legacy_password(user_doc["user_id"], credentials.password)
        logger.info(f"Auto-migrated legacy password for user: {credentials.email}")
    
    # Check if user is active
    if user_doc.get("status") != "Active":
        raise HTTPException(status_code=403, detail="Account is not active")
    
    # PERMISSION SAFETY NET: Ensure user has valid permissions before proceeding
    user_doc = await ensure_user_permissions(user_doc["user_id"], user_doc)
    
    # Create session
    session_token = secrets.token_urlsafe(32)
    expires_at = datetime.now(timezone.utc) + timedelta(hours=24)
    
    await db.user_sessions.insert_one({
        "user_id": user_doc["user_id"],
        "session_token": session_token,
        "expires_at": expires_at,
        "created_at": datetime.now(timezone.utc),
        "login_type": "local"
    })
    
    # Update last login
    await db.users.update_one(
        {"user_id": user_doc["user_id"]},
        {"$set": {"last_login": datetime.now(timezone.utc)}}
    )
    
    # Set session cookie
    response.set_cookie(
        key="session_token",
        value=session_token,
        httponly=True,
        secure=True,
        samesite="lax",  # Changed from "none" - prevents CSRF while allowing normal navigation
        max_age=24 * 60 * 60,  # 24 hours (reduced from 7 days for security)
        path="/"
    )
    
    logger.info(f"Local login successful for user: {credentials.email}")
    
    return {
        "success": True,
        "message": "Login successful",
        "user": {
            "user_id": user_doc["user_id"],
            "email": user_doc["email"],
            "name": user_doc["name"],
            "role": user_doc["role"],
            "picture": user_doc.get("picture"),
            "permissions_count": len(user_doc.get("permissions", []))
        }
    }


@api_router.post("/auth/setup-local-admin")
@limiter.limit("3/hour")  # Rate limit: 3 attempts per hour per IP
async def setup_local_admin(request: Request):
    """
    Setup a local admin user - REQUIRES FOUNDER AUTHENTICATION or first-time setup.
    
    Security:
    - If any admin exists, requires founder authentication
    - If no users exist, allows first-time setup with provided credentials
    - Credentials must be provided in request body (not hardcoded)
    - Rate limited: 3 attempts per hour
    """
    body = await request.json()
    
    # Validate required fields
    admin_email = body.get("email")
    admin_password = body.get("password")
    admin_name = body.get("name", "Admin User")
    
    if not admin_email or not admin_password:
        raise HTTPException(status_code=400, detail="Email and password are required")
    
    if len(admin_password) < 8:
        raise HTTPException(status_code=400, detail="Password must be at least 8 characters")
    
    # Check if any admin users exist
    existing_admins = await db.users.count_documents({"role": {"$in": ["Admin", "Founder"]}})
    
    if existing_admins > 0:
        # Require founder authentication for subsequent admin creation
        user = await get_current_user(request)
        if not user:
            raise HTTPException(status_code=401, detail="Authentication required to create admin users")
        
        user_doc = await db.users.find_one({"user_id": user.user_id})
        if not user_doc or (user_doc.get("role") != "Founder" and user_doc.get("email") != FOUNDER_EMAIL):
            raise HTTPException(status_code=403, detail="Only Founder can create admin users")
    
    # Check if user already exists
    existing_user = await db.users.find_one({"email": admin_email}, {"_id": 0})
    
    now = datetime.now(timezone.utc)
    hashed_password = hash_password(admin_password)
    
    if existing_user:
        # Update existing user with local password
        await db.users.update_one(
            {"email": admin_email},
            {"$set": {
                "local_password": hashed_password,
                "role": "Admin",
                "status": "Active",
                "updated_at": now.isoformat()
            }}
        )
        logger.info(f"Updated local admin: {admin_email}")
        return {
            "success": True,
            "message": "Local admin updated successfully",
            "email": admin_email,
            "role": "Admin"
        }
    else:
        # Create new admin user
        user_id = f"local_admin_{uuid.uuid4().hex[:8]}"
        user_doc = {
            "user_id": user_id,
            "email": admin_email,
            "name": admin_name,
            "picture": "https://ui-avatars.com/api/?name=Thaha+Pakayil&background=2563eb&color=fff",
            "role": "Admin",
            "status": "Active",
            "local_password": hashed_password,
            "created_at": now.isoformat(),
            "updated_at": now.isoformat()
        }
        
        await db.users.insert_one(user_doc)
        logger.info(f"Created local admin: {admin_email}")
        
        return {
            "success": True,
            "message": "Local admin created successfully",
            "email": admin_email,
            "role": "Admin",
            "user_id": user_id
        }


@api_router.get("/auth/check-local-admin")
async def check_local_admin():
    """Check if any local admin is set up (does not reveal specific email)"""
    # Check if any admin with local password exists
    admin_count = await db.users.count_documents({
        "role": {"$in": ["Admin", "Founder"]},
        "local_password": {"$exists": True}
    })
    
    if admin_count > 0:
        return {
            "exists": True,
            "admin_count": admin_count,
            "message": "Admin user(s) configured"
        }
    return {
        "exists": False,
        "message": "No admin users configured - first-time setup available"
    }

