def get_all_substages():
    """Get flat list of all sub-stages in order"""
    all_substages = []
    for group in MILESTONE_GROUPS:
        for sub in group["subStages"]:
            all_substages.append({
                **sub,
                "group_id": group["id"],
                "group_name": group["name"]
            })
    return all_substages


