# ============ PROJECT VALUE LIFECYCLE ============

@api_router.post("/projects/{project_id}/quotation-history")
async def add_project_quotation_history(project_id: str, entry: QuotationHistoryEntry, request: Request):
    """Append a quotation entry to project's quotation history. Append-only, no edit/delete."""
    user = await get_current_user(request)
    
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    # Validate status
    if entry.status not in QUOTATION_STATUSES:
        raise HTTPException(status_code=400, detail=f"Invalid status. Must be one of: {', '.join(QUOTATION_STATUSES)}")
    
    current_history = project.get("quotation_history", [])
    new_version = len(current_history) + 1
    
    now = datetime.now(timezone.utc)
    
    # Build new quotation entry with line items support
    new_entry = {
        "version": new_version,
        "quoted_value": entry.quoted_value,
        "status": entry.status,
        "created_at": now.isoformat(),
        "created_by": user.user_id,
        "created_by_name": user.name,
        "note": entry.note,
        # Line items for detailed scope breakdown
        "line_items": [item.model_dump() for item in entry.line_items] if entry.line_items else None
    }
    
    # If new entry is "Approved", mark all previous entries as "Superseded"
    if entry.status == "Approved" and current_history:
        for i, hist in enumerate(current_history):
            if hist.get("status") not in ["Superseded"]:
                current_history[i]["status"] = "Superseded"
        await db.projects.update_one(
            {"project_id": project_id},
            {"$set": {"quotation_history": current_history}}
        )
    
    # Update current_quotation_value for quick access
    await db.projects.update_one(
        {"project_id": project_id},
        {
            "$push": {"quotation_history": new_entry},
            "$set": {
                "current_quotation_value": entry.quoted_value,
                "updated_at": now.isoformat()
            }
        }
    )
    
    # Add audit comment
    await db.projects.update_one(
        {"project_id": project_id},
        {
            "$push": {
                "comments": {
                    "id": f"comment_{uuid.uuid4().hex[:8]}",
                    "user_id": user.user_id,
                    "user_name": user.name,
                    "message": f"💼 Quotation v{new_version} added: ₹{entry.quoted_value:,.0f} ({entry.status})" + 
                              (f" - {entry.note}" if entry.note else ""),
                    "is_system": True,
                    "created_at": now.isoformat(),
                    "metadata": {
                        "type": "quotation_added",
                        "version": new_version,
                        "quoted_value": entry.quoted_value,
                        "status": entry.status
                    }
                }
            }
        }
    )
    
    return {"success": True, "entry": new_entry}


class ConfirmSignoffValueRequest(BaseModel):
    signoff_value: float


@api_router.post("/projects/{project_id}/confirm-signoff-value")
async def confirm_signoff_value(project_id: str, data: ConfirmSignoffValueRequest, request: Request):
    """
    Confirm and lock sign-off value with user-provided amount.
    This endpoint is called when KWS Sign-Off milestone is completed,
    allowing user to review/adjust the value before final lock.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    if project.get("signoff_locked"):
        raise HTTPException(status_code=400, detail="Sign-off value is already locked")
    
    if data.signoff_value <= 0:
        raise HTTPException(status_code=400, detail="Sign-off value must be greater than 0")
    
    now = datetime.now(timezone.utc)
    
    await db.projects.update_one(
        {"project_id": project_id},
        {
            "$set": {
                "signoff_value": data.signoff_value,
                "signoff_locked": True,
                "signoff_locked_at": now.isoformat(),
                "signoff_locked_by": user.user_id,
                "signoff_locked_by_name": user.name,
                # Legacy compatibility
                "contract_value": data.signoff_value,
                "contract_value_locked": True,
                "contract_value_locked_at": now.isoformat(),
                "contract_value_locked_by": user.user_id,
                "contract_value_locked_by_name": user.name,
                "updated_at": now.isoformat()
            }
        }
    )
    
    # Add audit comment
    await db.projects.update_one(
        {"project_id": project_id},
        {
            "$push": {
                "comments": {
                    "id": str(uuid.uuid4()),
                    "user_id": "system",
                    "user_name": "System",
                    "role": "System",
                    "message": f"💰 SIGN-OFF VALUE CONFIRMED: ₹{data.signoff_value:,.0f} - Locked by {user.name}. This is now the single source of truth for all financial calculations.",
                    "is_system": True,
                    "created_at": now.isoformat()
                },
                "timeline": {
                    "type": "signoff_value_confirmed",
                    "signoff_value": data.signoff_value,
                    "confirmed_by": user.user_id,
                    "confirmed_by_name": user.name,
                    "timestamp": now.isoformat()
                }
            }
        }
    )
    
    return {
        "success": True,
        "signoff_value": data.signoff_value,
        "locked_at": now.isoformat(),
        "locked_by": user.name
    }


@api_router.post("/projects/{project_id}/lock-contract-value")
async def lock_contract_value(project_id: str, request: Request):
    """
    DEPRECATED: Use the automatic sign-off lock via KWS Sign-Off milestone.
    This endpoint is kept for backwards compatibility.
    Lock signoff_value after design sign-off. Once locked, only Admin/Founder can override.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    if project.get("signoff_locked") or project.get("contract_value_locked"):
        raise HTTPException(status_code=400, detail="Sign-off value is already locked")
    
    now = datetime.now(timezone.utc)
    
    # Get signoff_value from latest quotation or fallback
    quotation_history = project.get("quotation_history", [])
    if quotation_history:
        approved = [q for q in quotation_history if q.get("status") == "Approved"]
        signoff_value = approved[-1].get("quoted_value", 0) if approved else quotation_history[-1].get("quoted_value", 0)
    else:
        signoff_value = project.get("booked_value") or project.get("inquiry_value") or project.get("budget") or 0
    
    await db.projects.update_one(
        {"project_id": project_id},
        {
            "$set": {
                "signoff_value": signoff_value,
                "signoff_locked": True,
                "signoff_locked_at": now.isoformat(),
                "signoff_locked_by": user.user_id,
                "signoff_locked_by_name": user.name,
                # Legacy compatibility
                "contract_value": signoff_value,
                "contract_value_locked": True,
                "contract_value_locked_at": now.isoformat(),
                "contract_value_locked_by": user.user_id,
                "contract_value_locked_by_name": user.name,
                "updated_at": now.isoformat()
            }
        }
    )
    
    # Add audit comment
    await db.projects.update_one(
        {"project_id": project_id},
        {
            "$push": {
                "comments": {
                    "id": f"comment_{uuid.uuid4().hex[:8]}",
                    "user_id": user.user_id,
                    "user_name": user.name,
                    "message": f"🔒 SIGNOFF VALUE LOCKED: ₹{signoff_value:,.0f} - Manual lock by {user.name}",
                    "is_system": True,
                    "created_at": now.isoformat(),
                    "metadata": {
                        "type": "signoff_value_locked_manual",
                        "signoff_value": signoff_value
                    }
                },
                "timeline": {
                    "type": "signoff_value_locked",
                    "signoff_value": signoff_value,
                    "triggered_by": "manual_lock",
                    "locked_by": user.user_id,
                    "locked_by_name": user.name,
                    "timestamp": now.isoformat()
                }
            }
        }
    )
    
    return {"success": True, "signoff_value": signoff_value, "locked_at": now.isoformat()}


class ContractValueOverride(BaseModel):
    new_value: float
    reason: str


@api_router.post("/projects/{project_id}/override-contract-value")
async def override_contract_value(project_id: str, override: ContractValueOverride, request: Request):
    """Override locked contract value. Admin/Founder only with mandatory reason."""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # Only Admin/Founder can override
    if user_doc.get("role") not in ["Admin", "Founder"]:
        raise HTTPException(status_code=403, detail="Only Admin/Founder can override contract value")
    
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    old_value = project.get("signoff_value") or project.get("contract_value") or project.get("project_value") or 0
    now = datetime.now(timezone.utc)
    
    await db.projects.update_one(
        {"project_id": project_id},
        {
            "$set": {
                "signoff_value": override.new_value,
                "contract_value": override.new_value,  # Legacy compatibility
                "updated_at": now.isoformat()
            },
            "$push": {
                "signoff_value_overrides": {
                    "old_value": old_value,
                    "new_value": override.new_value,
                    "reason": override.reason,
                    "overridden_by": user.user_id,
                    "overridden_by_name": user.name,
                    "overridden_by_role": user_doc.get("role"),
                    "overridden_at": now.isoformat()
                },
                "comments": {
                    "id": f"comment_{uuid.uuid4().hex[:8]}",
                    "user_id": user.user_id,
                    "user_name": user.name,
                    "message": f"⚠️ ADMIN OVERRIDE - SIGNOFF VALUE: ₹{old_value:,.0f} → ₹{override.new_value:,.0f}. Reason: {override.reason}",
                    "is_system": True,
                    "created_at": now.isoformat(),
                    "metadata": {
                        "type": "signoff_value_override",
                        "old_value": old_value,
                        "new_value": override.new_value,
                        "reason": override.reason
                    }
                },
                "timeline": {
                    "type": "signoff_value_override",
                    "old_value": old_value,
                    "new_value": override.new_value,
                    "reason": override.reason,
                    "overridden_by": user.user_id,
                    "overridden_by_name": user.name,
                    "timestamp": now.isoformat()
                }
            }
        }
    )
    
    return {
        "success": True,
        "old_value": old_value,
        "new_value": override.new_value,
        "reason": override.reason
    }


class DiscountApplication(BaseModel):
    discount_amount: float
    reason: str


@api_router.post("/projects/{project_id}/apply-discount")
async def apply_discount(project_id: str, discount: DiscountApplication, request: Request):
    """Apply discount to project. Admin/Founder only. Tracked with reason."""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # Only Admin/Founder can apply discounts
    if user_doc.get("role") not in ["Admin", "Founder"]:
        raise HTTPException(status_code=403, detail="Only Admin/Founder can apply discounts")
    
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    if discount.discount_amount < 0:
        raise HTTPException(status_code=400, detail="Discount amount cannot be negative")
    
    contract_value = project.get("contract_value") or project.get("project_value") or 0
    if discount.discount_amount > contract_value:
        raise HTTPException(status_code=400, detail="Discount cannot exceed contract value")
    
    now = datetime.now(timezone.utc)
    
    await db.projects.update_one(
        {"project_id": project_id},
        {
            "$set": {
                "discount_amount": discount.discount_amount,
                "discount_reason": discount.reason,
                "discount_approved_by": user.user_id,
                "discount_approved_by_name": user.name,
                "discount_approved_at": now.isoformat(),
                "updated_at": now.isoformat()
            },
            "$push": {
                "comments": {
                    "id": f"comment_{uuid.uuid4().hex[:8]}",
                    "user_id": user.user_id,
                    "user_name": user.name,
                    "message": f"💰 Discount applied: ₹{discount.discount_amount:,.0f}. Reason: {discount.reason}. Final value: ₹{contract_value - discount.discount_amount:,.0f}",
                    "is_system": True,
                    "created_at": now.isoformat()
                }
            }
        }
    )
    
    return {
        "success": True,
        "contract_value": contract_value,
        "discount_amount": discount.discount_amount,
        "final_value": contract_value - discount.discount_amount,
        "reason": discount.reason
    }


@api_router.get("/projects/{project_id}/value-lifecycle")
async def get_project_value_lifecycle(project_id: str, request: Request):
    """
    Get complete 4-stage value lifecycle data for a project.
    
    Stages:
    1. INQUIRY_VALUE - Pre-Sales estimate (for forecasting only)
    2. BOOKED_VALUE - Auto-captured at first payment (immutable)
    3. QUOTATION_HISTORY - Versioned quotations (append-only)
    4. SIGNOFF_VALUE - Final contract value (locked at Design Sign-Off)
    
    IMPORTANT: Only signoff_value is used for financial calculations.
    """
    user = await get_current_user(request)
    
    project = await db.projects.find_one({"project_id": project_id}, {"_id": 0})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    # Get values from each stage
    inquiry_value = project.get("inquiry_value") or project.get("budget") or 0
    booked_value = project.get("booked_value") or 0
    quotation_history = project.get("quotation_history", [])
    current_quotation_value = quotation_history[-1].get("quoted_value", 0) if quotation_history else 0
    signoff_value = project.get("signoff_value")
    discount = project.get("discount_amount") or 0
    
    # Final value for financials (ONLY signoff_value if locked)
    financial_value = signoff_value if project.get("signoff_locked") else None
    
    return {
        "project_id": project_id,
        "pid": project.get("pid"),
        
        # ========== 4-STAGE VALUE LIFECYCLE ==========
        # Stage 1: INQUIRY VALUE (Pre-Sales)
        "inquiry_value": inquiry_value,
        
        # Stage 2: BOOKED VALUE (Auto-captured at first payment)
        "booked_value": booked_value,
        "booked_value_locked": project.get("booked_value_locked", False),
        "booked_value_locked_at": project.get("booked_value_locked_at"),
        "booked_value_source": project.get("booked_value_source", "unknown"),
        
        # Stage 3: QUOTATION HISTORY (Versioned)
        "quotation_history": quotation_history,
        "current_quotation_value": current_quotation_value,
        "quotation_revisions_count": len(quotation_history),
        
        # Stage 4: SIGNOFF VALUE (Final - Single Source of Truth for Finance)
        "signoff_value": signoff_value,
        "signoff_locked": project.get("signoff_locked", False),
        "signoff_locked_at": project.get("signoff_locked_at"),
        "signoff_locked_by_name": project.get("signoff_locked_by_name"),
        "signoff_value_overrides": project.get("signoff_value_overrides", []),
        
        # ========== FINANCIAL CALCULATIONS ==========
        # IMPORTANT: Use ONLY this value for revenue, cash flow, reports
        "financial_value": financial_value,  # None if not locked yet
        "discount_amount": discount,
        "discount_reason": project.get("discount_reason"),
        "final_financial_value": (financial_value - discount) if financial_value else None,
        
        # ========== ANALYTICS ==========
        "value_progression": {
            "inquiry_to_booked": booked_value - inquiry_value if booked_value else None,
            "booked_to_quotation": current_quotation_value - booked_value if current_quotation_value and booked_value else None,
            "quotation_to_signoff": (signoff_value - current_quotation_value) if signoff_value and current_quotation_value else None
        },
        
        # ========== STATUS FLAGS ==========
        "status": {
            "has_inquiry_value": inquiry_value > 0,
            "has_booked_value": booked_value > 0,
            "has_quotations": len(quotation_history) > 0,
            "has_signoff_value": signoff_value is not None and signoff_value > 0,
            "is_finance_ready": project.get("signoff_locked", False)  # Can be used in financial reports
        },
        
        # Legacy compatibility
        "contract_value": project.get("contract_value"),
        "contract_value_locked": project.get("contract_value_locked", False)
    }


@api_router.post("/admin/migrate-project-values")
async def migrate_project_values(request: Request):
    """
    Migration endpoint: Convert existing projects to new 4-stage value model.
    
    Rules:
    - If contract_value_locked=True → migrate to signoff_value and lock
    - If contract_value_locked=False → leave signoff_value blank (force manual sign-off)
    - Preserve all existing values for audit
    
    Admin/Founder only.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # Only Admin/Founder can run migration
    if user_doc.get("role") not in ["Admin", "Founder"] and not user_doc.get("is_founder"):
        raise HTTPException(status_code=403, detail="Only Admin/Founder can run migration")
    
    now = datetime.now(timezone.utc)
    migrated_count = 0
    skipped_count = 0
    migration_results = []
    
    # Get all projects
    projects = await db.projects.find({}).to_list(None)
    
    for project in projects:
        project_id = project.get("project_id")
        
        # Skip if already migrated
        if project.get("signoff_value") is not None:
            skipped_count += 1
            continue
        
        update_fields = {
            "updated_at": now.isoformat()
        }
        
        # Set inquiry_value if not exists
        if not project.get("inquiry_value"):
            update_fields["inquiry_value"] = project.get("budget") or 0
        
        # Set booked_value if not exists but has booking confirmation
        if not project.get("booked_value") and project.get("booked_value_locked"):
            # Already has booked_value_locked, preserve it
            pass
        elif not project.get("booked_value"):
            # Try to infer from payments or quotation history
            quotation_history = project.get("quotation_history", [])
            if quotation_history:
                update_fields["booked_value"] = quotation_history[0].get("quoted_value", 0)
            else:
                update_fields["booked_value"] = project.get("budget") or 0
        
        # Migration rule: If contract_value_locked=True, migrate to signoff_value
        if project.get("contract_value_locked"):
            contract_value = project.get("contract_value") or project.get("project_value") or 0
            update_fields["signoff_value"] = contract_value
            update_fields["signoff_locked"] = True
            update_fields["signoff_locked_at"] = project.get("contract_value_locked_at") or now.isoformat()
            update_fields["signoff_locked_by"] = project.get("contract_value_locked_by")
            update_fields["signoff_locked_by_name"] = project.get("contract_value_locked_by_name") or "Migration"
            
            migration_results.append({
                "project_id": project_id,
                "action": "migrated_locked",
                "signoff_value": contract_value
            })
        else:
            # Leave signoff_value as None - requires manual sign-off
            update_fields["signoff_value"] = None
            update_fields["signoff_locked"] = False
            
            migration_results.append({
                "project_id": project_id,
                "action": "requires_manual_signoff",
                "signoff_value": None
            })
        
        # Add migration audit comment
        migration_comment = {
            "id": f"comment_{uuid.uuid4().hex[:8]}",
            "user_id": "system",
            "user_name": "System",
            "role": "System",
            "message": f"📊 Value Lifecycle Migration: Project migrated to 4-stage value model. "
                       f"Signoff: {'₹{:,.0f} (locked)'.format(update_fields.get('signoff_value')) if update_fields.get('signoff_locked') else 'Requires manual sign-off'}",
            "is_system": True,
            "created_at": now.isoformat(),
            "metadata": {
                "type": "value_lifecycle_migration",
                "migrated_by": user.user_id,
                "migration_date": now.isoformat()
            }
        }
        
        await db.projects.update_one(
            {"project_id": project_id},
            {
                "$set": update_fields,
                "$push": {"comments": migration_comment}
            }
        )
        
        migrated_count += 1
    
    return {
        "success": True,
        "message": f"Migration complete. Migrated: {migrated_count}, Skipped (already migrated): {skipped_count}",
        "migrated_count": migrated_count,
        "skipped_count": skipped_count,
        "results": migration_results[:50]  # Limit results to first 50
    }


# ============ PROJECT CANCELLATION ============

class ProjectCancellationRequest(BaseModel):
    """Cancel a project with mandatory reason"""
    reason: str  # From CANCELLATION_REASONS dropdown
    notes: Optional[str] = None


@api_router.post("/projects/{project_id}/cancel")
async def cancel_project(project_id: str, data: ProjectCancellationRequest, request: Request):
    """
    Cancel a project. Requires mandatory reason.
    
    Rules:
    - Captures cancelled_value = booked_value (for funnel analysis)
    - Cancelled projects NEVER appear in Finance Dashboard
    - Cancelled projects ALWAYS appear in Funnel & Designer dashboards
    - This action is audited and cannot be silently undone
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # Only certain roles can cancel
    allowed_roles = ["Admin", "Founder", "DesignManager", "Manager"]
    if user_doc.get("role") not in allowed_roles and not user_doc.get("is_founder"):
        raise HTTPException(status_code=403, detail="Only Managers/Admin can cancel projects")
    
    # Validate reason
    if data.reason not in CANCELLATION_REASONS:
        raise HTTPException(status_code=400, detail=f"Invalid cancellation reason. Must be one of: {CANCELLATION_REASONS}")
    
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    if project.get("stage") == "Cancelled":
        raise HTTPException(status_code=400, detail="Project is already cancelled")
    
    now = datetime.now(timezone.utc)
    
    # Capture cancelled_value = booked_value (for funnel analysis)
    cancelled_value = project.get("booked_value") or project.get("signoff_value") or project.get("inquiry_value") or 0
    
    cancel_comment = {
        "id": f"comment_{uuid.uuid4().hex[:8]}",
        "user_id": user.user_id,
        "user_name": user.name,
        "role": user_doc.get("role"),
        "message": f"❌ PROJECT CANCELLED\n"
                   f"Reason: {data.reason}\n"
                   f"Cancelled Value: ₹{cancelled_value:,.0f}\n"
                   f"Notes: {data.notes or 'None'}",
        "is_system": True,
        "created_at": now.isoformat(),
        "metadata": {
            "type": "project_cancelled",
            "reason": data.reason,
            "notes": data.notes,
            "cancelled_value": cancelled_value,
            "previous_stage": project.get("stage")
        }
    }
    
    await db.projects.update_one(
        {"project_id": project_id},
        {
            "$set": {
                "stage": "Cancelled",
                "previous_stage": project.get("stage"),
                "cancelled_at": now.isoformat(),
                "cancelled_by": user.user_id,
                "cancelled_by_name": user.name,
                "cancellation_reason": data.reason,
                "cancellation_notes": data.notes,
                "cancelled_value": cancelled_value,  # For funnel analysis
                "updated_at": now.isoformat()
            },
            "$push": {
                "comments": cancel_comment,
                "timeline": {
                    "type": "project_cancelled",
                    "reason": data.reason,
                    "cancelled_value": cancelled_value,
                    "cancelled_by": user.user_id,
                    "cancelled_by_name": user.name,
                    "timestamp": now.isoformat()
                }
            }
        }
    )
    
    return {
        "success": True,
        "message": f"Project cancelled. Reason: {data.reason}",
        "cancelled_value": cancelled_value
    }


@api_router.get("/cancellation-reasons")
async def get_cancellation_reasons():
    """Get available cancellation reasons for dropdown"""
    return {"reasons": CANCELLATION_REASONS}


# ============ DESIGNER ASSIGNMENT TRACKING ============

@api_router.get("/projects/{project_id}/designer-assignments")
async def get_project_designer_assignments(request: Request, project_id: str):
    """
    Get all designer assignments for a project (full history).
    Shows active and ended assignments for accountability tracking.
    """
    user = await get_current_user(request)
    
    # Verify project exists
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    # Get all assignments for this project
    assignments = await db.designer_assignments.find(
        {"project_id": project_id},
        {"_id": 0}
    ).sort("assigned_from", -1).to_list(None)
    
    # Get user names for each assignment
    user_ids = set()
    for a in assignments:
        user_ids.add(a.get("designer_id"))
        user_ids.add(a.get("assigned_by"))
    
    users = await db.users.find(
        {"user_id": {"$in": list(user_ids)}},
        {"_id": 0, "user_id": 1, "name": 1}
    ).to_list(None)
    user_map = {u["user_id"]: u.get("name", "Unknown") for u in users}
    
    # Enrich assignments with names
    result = []
    for a in assignments:
        result.append({
            "assignment_id": a.get("assignment_id"),
            "project_id": a.get("project_id"),
            "designer_id": a.get("designer_id"),
            "designer_name": user_map.get(a.get("designer_id"), "Unknown"),
            "role": a.get("role"),
            "assigned_from": a.get("assigned_from"),
            "assigned_to": a.get("assigned_to"),
            "assignment_reason": a.get("assignment_reason"),
            "end_reason": a.get("end_reason"),
            "assigned_by": a.get("assigned_by"),
            "assigned_by_name": user_map.get(a.get("assigned_by"), "Unknown"),
            "notes": a.get("notes"),
            "is_active": a.get("assigned_to") is None
        })
    
    # Get current primary designer
    current_primary = next((a for a in result if a["role"] == "Primary" and a["is_active"]), None)
    
    return {
        "project_id": project_id,
        "current_primary": current_primary,
        "assignments": result,
        "total_assignments": len(result),
        "active_count": sum(1 for a in result if a["is_active"])
    }


@api_router.post("/projects/{project_id}/designer-assignments")
async def assign_designer_to_project(
    request: Request, 
    project_id: str, 
    data: DesignerAssignmentCreate
):
    """
    Assign or reassign a designer to a project.
    
    Rules:
    - Only one active Primary designer allowed at a time
    - When assigning a new Primary, the previous Primary's assignment is ended
    - Assignments are never deleted, only ended (for accountability)
    - Support designers can be added without affecting Primary
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    now = datetime.now(timezone.utc)
    
    # Access control: Admin, Founder, or project.manage_team permission
    allowed_roles = ["Admin", "Founder", "DesignManager"]
    if user_doc.get("role") not in allowed_roles and not user_doc.get("is_founder"):
        if not has_permission(user_doc, "projects.manage_team"):
            raise HTTPException(
                status_code=403, 
                detail="Access denied. Requires Admin, Design Manager, or team management permission."
            )
    
    # Verify project exists
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    # Verify designer exists and is a designer role
    designer = await db.users.find_one({"user_id": data.designer_id})
    if not designer:
        raise HTTPException(status_code=404, detail="Designer not found")
    
    designer_roles = ["Designer", "SeniorDesigner", "DesignManager"]
    if designer.get("role") not in designer_roles:
        raise HTTPException(
            status_code=400, 
            detail=f"User {designer.get('name')} is not a designer role"
        )
    
    # Validate role
    if data.role not in DESIGNER_ROLES:
        raise HTTPException(
            status_code=400, 
            detail=f"Invalid role. Must be one of: {DESIGNER_ROLES}"
        )
    
    # Validate assignment reason
    if data.assignment_reason not in ASSIGNMENT_REASONS:
        raise HTTPException(
            status_code=400, 
            detail=f"Invalid reason. Must be one of: {ASSIGNMENT_REASONS}"
        )
    
    # Check if designer already has an active assignment on this project
    existing_active = await db.designer_assignments.find_one({
        "project_id": project_id,
        "designer_id": data.designer_id,
        "assigned_to": None  # Active assignment
    })
    
    if existing_active:
        raise HTTPException(
            status_code=400,
            detail=f"Designer {designer.get('name')} already has an active assignment on this project"
        )
    
    # If assigning as Primary, end current Primary's assignment
    previous_primary = None
    if data.role == "Primary":
        current_primary = await db.designer_assignments.find_one({
            "project_id": project_id,
            "role": "Primary",
            "assigned_to": None
        })
        
        if current_primary:
            # End the current primary's assignment
            await db.designer_assignments.update_one(
                {"assignment_id": current_primary["assignment_id"]},
                {
                    "$set": {
                        "assigned_to": now.isoformat(),
                        "end_reason": "reassigned",
                        "ended_by": user.user_id,
                        "ended_by_name": user.name
                    }
                }
            )
            previous_primary = current_primary.get("designer_id")
            
            # Get previous designer name for comment
            prev_designer = await db.users.find_one({"user_id": previous_primary})
            prev_name = prev_designer.get("name", "Unknown") if prev_designer else "Unknown"
    
    # Create new assignment
    assignment_id = str(uuid.uuid4())
    assignment = {
        "assignment_id": assignment_id,
        "project_id": project_id,
        "designer_id": data.designer_id,
        "role": data.role,
        "assigned_from": now.isoformat(),
        "assigned_to": None,  # Active
        "assignment_reason": data.assignment_reason,
        "end_reason": None,
        "assigned_by": user.user_id,
        "notes": data.notes,
        "created_at": now.isoformat()
    }
    
    await db.designer_assignments.insert_one(assignment)
    
    # Update project's current primary designer fields (computed from assignments)
    if data.role == "Primary":
        await db.projects.update_one(
            {"project_id": project_id},
            {
                "$set": {
                    "primary_designer_id": data.designer_id,
                    "primary_designer_name": designer.get("name"),
                    "primary_designer_assignment_id": assignment_id,
                    "updated_at": now.isoformat()
                }
            }
        )
        
        # Add timeline entry
        timeline_entry = {
            "type": "designer_assigned",
            "role": "Primary",
            "designer_id": data.designer_id,
            "designer_name": designer.get("name"),
            "reason": data.assignment_reason,
            "assigned_by": user.user_id,
            "assigned_by_name": user.name,
            "previous_designer_id": previous_primary,
            "timestamp": now.isoformat()
        }
        
        # Add comment
        comment_text = f"Primary Designer assigned: {designer.get('name')}"
        if previous_primary:
            comment_text += f" (replacing {prev_name})"
        comment_text += f". Reason: {data.assignment_reason}"
        
        comment = {
            "id": str(uuid.uuid4()),
            "user_id": "system",
            "user_name": "System",
            "role": "System",
            "message": comment_text,
            "is_system": True,
            "created_at": now.isoformat()
        }
        
        await db.projects.update_one(
            {"project_id": project_id},
            {
                "$push": {
                    "timeline": timeline_entry,
                    "comments": comment
                }
            }
        )
    
    return {
        "success": True,
        "message": f"Designer {designer.get('name')} assigned as {data.role}",
        "assignment_id": assignment_id,
        "previous_primary_ended": previous_primary is not None
    }


@api_router.put("/projects/{project_id}/designer-assignments/{assignment_id}/end")
async def end_designer_assignment(
    request: Request,
    project_id: str,
    assignment_id: str,
    data: DesignerAssignmentEnd
):
    """
    End a designer assignment (soft delete - preserves history).
    
    Note: If ending a Primary assignment, a new Primary should be assigned.
    Projects should not be left without a Primary designer.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    now = datetime.now(timezone.utc)
    
    # Access control
    allowed_roles = ["Admin", "Founder", "DesignManager"]
    if user_doc.get("role") not in allowed_roles and not user_doc.get("is_founder"):
        if not has_permission(user_doc, "projects.manage_team"):
            raise HTTPException(
                status_code=403,
                detail="Access denied. Requires Admin, Design Manager, or team management permission."
            )
    
    # Find the assignment
    assignment = await db.designer_assignments.find_one({
        "assignment_id": assignment_id,
        "project_id": project_id
    })
    
    if not assignment:
        raise HTTPException(status_code=404, detail="Assignment not found")
    
    if assignment.get("assigned_to") is not None:
        raise HTTPException(status_code=400, detail="Assignment already ended")
    
    # End the assignment
    await db.designer_assignments.update_one(
        {"assignment_id": assignment_id},
        {
            "$set": {
                "assigned_to": now.isoformat(),
                "end_reason": data.end_reason,
                "end_notes": data.notes,
                "ended_by": user.user_id,
                "ended_by_name": user.name
            }
        }
    )
    
    # If this was the Primary, update project and warn
    warning = None
    if assignment.get("role") == "Primary":
        # Clear project's current primary
        await db.projects.update_one(
            {"project_id": project_id},
            {
                "$set": {
                    "primary_designer_id": None,
                    "primary_designer_name": None,
                    "primary_designer_assignment_id": None,
                    "updated_at": now.isoformat()
                }
            }
        )
        warning = "Primary designer removed. Please assign a new Primary designer."
        
        # Get designer name for comment
        designer = await db.users.find_one({"user_id": assignment.get("designer_id")})
        designer_name = designer.get("name", "Unknown") if designer else "Unknown"
        
        # Add comment
        comment = {
            "id": str(uuid.uuid4()),
            "user_id": "system",
            "user_name": "System",
            "role": "System",
            "message": f"Primary Designer {designer_name} assignment ended. Reason: {data.end_reason}",
            "is_system": True,
            "created_at": now.isoformat()
        }
        
        await db.projects.update_one(
            {"project_id": project_id},
            {"$push": {"comments": comment}}
        )
    
    return {
        "success": True,
        "message": "Assignment ended",
        "warning": warning
    }


