async def get_primary_designer_at_event(project_id: str, event_timestamp: str) -> Optional[dict]:
    """
    Get the Primary designer who was active at a specific timestamp.
    Used for attribution in dashboards.
    
    Returns: {designer_id, designer_name, assignment_id} or None
    """
    # Find assignment where:
    # - role = Primary
    # - assigned_from <= event_timestamp
    # - assigned_to is None OR assigned_to > event_timestamp
    
    assignments = await db.designer_assignments.find({
        "project_id": project_id,
        "role": "Primary"
    }).to_list(None)
    
    for a in assignments:
        assigned_from = a.get("assigned_from", "")
        assigned_to = a.get("assigned_to")
        
        # Check if event falls within assignment period
        if assigned_from <= event_timestamp:
            if assigned_to is None or assigned_to > event_timestamp:
                designer = await db.users.find_one({"user_id": a.get("designer_id")})
                return {
                    "designer_id": a.get("designer_id"),
                    "designer_name": designer.get("name") if designer else "Unknown",
                    "assignment_id": a.get("assignment_id")
                }
    
    return None


# ============ ROLE-BASED DASHBOARDS ============

def get_financial_year_range():
    """Get current financial year date range (Apr-Mar)"""
    today = datetime.now(timezone.utc)
    if today.month >= 4:  # Apr onwards = current year is FY start
        fy_start = datetime(today.year, 4, 1, tzinfo=timezone.utc)
        fy_end = datetime(today.year + 1, 3, 31, 23, 59, 59, tzinfo=timezone.utc)
    else:  # Jan-Mar = previous year is FY start
        fy_start = datetime(today.year - 1, 4, 1, tzinfo=timezone.utc)
        fy_end = datetime(today.year, 3, 31, 23, 59, 59, tzinfo=timezone.utc)
    return fy_start.strftime("%Y-%m-%d"), fy_end.strftime("%Y-%m-%d")


@api_router.get("/dashboards/finance")
async def get_finance_dashboard(
    request: Request,
    period: str = "fy",  # fy (default), mtd, qtd, custom
    from_date: Optional[str] = None,
    to_date: Optional[str] = None
):
    """
    FINANCE DASHBOARD - Sign-Off Value ONLY (Audit-Safe)
    
    Access: Finance roles + Admin + Founder
    
    Rules:
    - Uses ONLY signoff_value (where signoff_locked=True)
    - Ignores inquiry_value and booked_value completely
    - Excludes cancelled projects
    
    Metrics:
    - Total Sign-Off Value
    - Amount Collected
    - Pending Collection
    - Collection % against Sign-Off
    - Project-wise payment status
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # Access control: Finance roles + Admin + Founder
    finance_roles = ["Admin", "Founder", "Accountant", "SeniorAccountant", "JuniorAccountant", 
                     "CharteredAccountant", "FinanceManager"]
    if user_doc.get("role") not in finance_roles and not user_doc.get("is_founder"):
        if not has_permission(user_doc, "finance.view_cashbook"):
            raise HTTPException(status_code=403, detail="Access denied. Finance Dashboard requires finance permissions.")
    
    # Determine date range based on period
    if period == "mtd":
        today = datetime.now(timezone.utc)
        start_date = datetime(today.year, today.month, 1).strftime("%Y-%m-%d")
        end_date = today.strftime("%Y-%m-%d")
        period_label = "Month to Date"
    elif period == "qtd":
        today = datetime.now(timezone.utc)
        quarter_month = ((today.month - 1) // 3) * 3 + 1
        start_date = datetime(today.year, quarter_month, 1).strftime("%Y-%m-%d")
        end_date = today.strftime("%Y-%m-%d")
        period_label = "Quarter to Date"
    elif period == "custom" and from_date and to_date:
        start_date = from_date
        end_date = to_date
        period_label = f"{from_date} to {to_date}"
    else:  # Default: Financial Year
        start_date, end_date = get_financial_year_range()
        period_label = f"FY {start_date[:4]}-{int(start_date[:4])+1}"
    
    # Query projects with LOCKED signoff_value (finance-ready only)
    # IMPORTANT: Excludes cancelled projects
    query = {
        "signoff_locked": True,
        "stage": {"$ne": "Cancelled"}
    }
    
    projects = await db.projects.find(query, {"_id": 0}).to_list(None)
    
    # Get all receipts for collection data
    receipts = await db.finance_receipts.find({}, {"_id": 0}).to_list(None)
    
    # Build project-wise collection map
    project_collections = {}
    for receipt in receipts:
        proj_id = receipt.get("project_id")
        if proj_id:
            project_collections[proj_id] = project_collections.get(proj_id, 0) + (receipt.get("amount") or 0)
    
    # Calculate metrics
    total_signoff_value = 0
    total_collected = 0
    project_details = []
    
    for project in projects:
        signoff_value = project.get("signoff_value") or 0
        discount = project.get("discount_amount") or 0
        net_signoff = signoff_value - discount
        
        collected = project_collections.get(project.get("project_id"), 0)
        pending = max(0, net_signoff - collected)
        collection_pct = (collected / net_signoff * 100) if net_signoff > 0 else 0
        
        total_signoff_value += net_signoff
        total_collected += collected
        
        project_details.append({
            "project_id": project.get("project_id"),
            "pid": project.get("pid"),
            "client_name": project.get("client_name"),
            "stage": project.get("stage"),
            "signoff_value": signoff_value,
            "discount": discount,
            "net_signoff_value": net_signoff,
            "amount_collected": collected,
            "amount_pending": pending,
            "collection_percentage": round(collection_pct, 1),
            "signoff_date": project.get("signoff_locked_at"),
            "primary_designer": project.get("primary_designer_name")
        })
    
    # Sort by pending amount (highest first)
    project_details.sort(key=lambda x: -x.get("amount_pending", 0))
    
    total_pending = total_signoff_value - total_collected
    overall_collection_pct = (total_collected / total_signoff_value * 100) if total_signoff_value > 0 else 0
    
    return {
        "dashboard_type": "finance",
        "value_source": "signoff_value ONLY",  # Clear label for users
        "value_source_tooltip": "This dashboard uses ONLY Sign-Off Value (locked final contract value). Inquiry and Booked values are excluded.",
        
        "period": {
            "type": period,
            "label": period_label,
            "from_date": start_date,
            "to_date": end_date
        },
        
        "summary": {
            "total_signoff_value": total_signoff_value,
            "amount_collected": total_collected,
            "amount_pending": total_pending,
            "collection_percentage": round(overall_collection_pct, 1),
            "project_count": len(project_details)
        },
        
        "projects": project_details,
        
        "generated_at": datetime.now(timezone.utc).isoformat()
    }


# ============ SALES & FUNNEL ANALYSIS DASHBOARD ============

@api_router.get("/dashboards/sales")
async def get_sales_funnel_dashboard(
    request: Request,
    period: str = "fy",  # fy (default), mtd, qtd, custom
    from_date: Optional[str] = None,
    to_date: Optional[str] = None,
    designer_id: Optional[str] = None  # NEW: Filter by designer
):
    """
    SALES & FUNNEL ANALYSIS DASHBOARD
    
    Access: Admin, Founder, SalesManager
    
    Purpose: Track value lifecycle from Inquiry → Booked → Sign-Off
    Analyze conversions, value changes (drop/gain), and cancellation impact.
    
    Metrics (with counts alongside values):
    - Total Inquiry Value (count of inquiries)
    - Total Booked Value (count of booked projects)
    - Total Sign-Off Value (count of signed-off projects)
    - Total Cancelled Value (count of cancelled projects)
    - Conversion rates: Inquiry→Booked, Booked→Sign-Off
    - Value drop/gain analysis between stages
    - Stage-wise project breakdown
    
    Filters:
    - period: fy, mtd, qtd, custom
    - designer_id: Filter by primary_designer_id
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # Access control: Admin, Founder, SalesManager, or admin permissions
    allowed_roles = ["Admin", "Founder", "SalesManager"]
    if user_doc.get("role") not in allowed_roles and not user_doc.get("is_founder"):
        if not has_permission(user_doc, "admin.view_reports"):
            raise HTTPException(status_code=403, detail="Access denied. Sales Dashboard requires Sales Manager or Admin permissions.")
    
    # Determine date range based on period
    if period == "mtd":
        today = datetime.now(timezone.utc)
        start_date = datetime(today.year, today.month, 1).strftime("%Y-%m-%d")
        end_date = today.strftime("%Y-%m-%d")
        period_label = "Month to Date"
    elif period == "qtd":
        today = datetime.now(timezone.utc)
        quarter_month = ((today.month - 1) // 3) * 3 + 1
        start_date = datetime(today.year, quarter_month, 1).strftime("%Y-%m-%d")
        end_date = today.strftime("%Y-%m-%d")
        period_label = "Quarter to Date"
    elif period == "custom" and from_date and to_date:
        start_date = from_date
        end_date = to_date
        period_label = f"{from_date} to {to_date}"
    else:  # Default: Financial Year
        start_date, end_date = get_financial_year_range()
        period_label = f"FY {start_date[:4]}-{int(start_date[:4])+1}"
    
    # Build query filter for designer
    project_filter = {}
    lead_filter = {}
    if designer_id:
        project_filter["primary_designer_id"] = designer_id
        lead_filter["assigned_to"] = designer_id  # leads use assigned_to
    
    # Get projects (filtered by designer if specified)
    projects = await db.projects.find(project_filter, {"_id": 0}).to_list(None)
    
    # Get leads for inquiry value tracking (filtered by designer if specified)
    leads = await db.leads.find(lead_filter, {"_id": 0}).to_list(None)
    
    # Get designer name for display
    designer_name = None
    if designer_id:
        designer_doc = await db.users.find_one({"user_id": designer_id})
        if designer_doc:
            designer_name = designer_doc.get("name")
    
    # Initialize counters
    total_inquiry_value = 0
    total_booked_value = 0
    total_signoff_value = 0
    total_cancelled_value = 0
    
    inquiry_count = 0
    booked_count = 0
    signoff_count = 0
    cancelled_count = 0
    
    # Stage-wise breakdown
    stage_breakdown = {}
    
    # Value changes tracking
    inquiry_to_booked_changes = []
    booked_to_signoff_changes = []
    
    # Cancelled projects detail
    cancelled_projects = []
    
    # Process leads for inquiry values (leads that haven't converted yet)
    for lead in leads:
        if not lead.get("is_converted"):
            inquiry_value = lead.get("budget") or lead.get("inquiry_value") or 0
            if inquiry_value > 0:
                total_inquiry_value += inquiry_value
                inquiry_count += 1
    
    # Process projects
    for project in projects:
        # Get all value types
        inquiry_value = project.get("inquiry_value") or project.get("budget") or 0
        booked_value = project.get("booked_value") or 0
        signoff_value = project.get("signoff_value") or 0
        cancelled_value = project.get("cancelled_value") or 0
        
        # Add to inquiry totals (converted leads)
        if inquiry_value > 0:
            total_inquiry_value += inquiry_value
            inquiry_count += 1
        
        stage = project.get("stage", "Unknown")
        
        # Handle cancelled projects
        if stage == "Cancelled":
            cancelled_count += 1
            total_cancelled_value += cancelled_value
            cancelled_projects.append({
                "project_id": project.get("project_id"),
                "pid": project.get("pid"),
                "client_name": project.get("client_name"),
                "cancelled_value": cancelled_value,
                "cancellation_reason": project.get("cancellation_reason"),
                "cancelled_at": project.get("cancelled_at"),
                "primary_designer": project.get("primary_designer_name")
            })
            continue
        
        # Track booked values (where booked_value_locked=True)
        if project.get("booked_value_locked") and booked_value > 0:
            total_booked_value += booked_value
            booked_count += 1
            
            # Track inquiry to booked change
            if inquiry_value > 0:
                change = booked_value - inquiry_value
                change_pct = (change / inquiry_value * 100) if inquiry_value > 0 else 0
                inquiry_to_booked_changes.append({
                    "project_id": project.get("project_id"),
                    "pid": project.get("pid"),
                    "inquiry_value": inquiry_value,
                    "booked_value": booked_value,
                    "change": change,
                    "change_percent": round(change_pct, 1)
                })
        
        # Track signoff values (where signoff_locked=True)
        if project.get("signoff_locked") and signoff_value > 0:
            total_signoff_value += signoff_value
            signoff_count += 1
            
            # Track booked to signoff change
            if booked_value > 0:
                change = signoff_value - booked_value
                change_pct = (change / booked_value * 100) if booked_value > 0 else 0
                booked_to_signoff_changes.append({
                    "project_id": project.get("project_id"),
                    "pid": project.get("pid"),
                    "booked_value": booked_value,
                    "signoff_value": signoff_value,
                    "change": change,
                    "change_percent": round(change_pct, 1)
                })
        
        # Stage breakdown
        if stage not in stage_breakdown:
            stage_breakdown[stage] = {"count": 0, "inquiry_value": 0, "booked_value": 0, "signoff_value": 0}
        stage_breakdown[stage]["count"] += 1
        stage_breakdown[stage]["inquiry_value"] += inquiry_value
        stage_breakdown[stage]["booked_value"] += booked_value
        stage_breakdown[stage]["signoff_value"] += signoff_value
    
    # Calculate conversion rates
    inquiry_to_booked_rate = (booked_count / inquiry_count * 100) if inquiry_count > 0 else 0
    booked_to_signoff_rate = (signoff_count / booked_count * 100) if booked_count > 0 else 0
    
    # Calculate value retention/loss
    inquiry_to_booked_value_change = total_booked_value - total_inquiry_value
    inquiry_to_booked_value_pct = ((total_booked_value / total_inquiry_value - 1) * 100) if total_inquiry_value > 0 else 0
    
    booked_to_signoff_value_change = total_signoff_value - total_booked_value
    booked_to_signoff_value_pct = ((total_signoff_value / total_booked_value - 1) * 100) if total_booked_value > 0 else 0
    
    # Aggregate drop/gain analysis
    positive_changes_inquiry_to_booked = sum(1 for c in inquiry_to_booked_changes if c["change"] > 0)
    negative_changes_inquiry_to_booked = sum(1 for c in inquiry_to_booked_changes if c["change"] < 0)
    
    positive_changes_booked_to_signoff = sum(1 for c in booked_to_signoff_changes if c["change"] > 0)
    negative_changes_booked_to_signoff = sum(1 for c in booked_to_signoff_changes if c["change"] < 0)
    
    # Sort stage breakdown by order
    sorted_stages = []
    for stage in ALL_PROJECT_STAGES:
        if stage in stage_breakdown:
            sorted_stages.append({
                "stage": stage,
                **stage_breakdown[stage]
            })
    
    return {
        "dashboard_type": "sales_funnel",
        "value_sources_tooltip": "This dashboard tracks the value lifecycle: Inquiry Value → Booked Value → Sign-Off Value. All values are shown for complete funnel analysis.",
        
        "filter": {
            "designer_id": designer_id,
            "designer_name": designer_name
        },
        
        "period": {
            "type": period,
            "label": period_label,
            "from_date": start_date,
            "to_date": end_date
        },
        
        "funnel_summary": {
            "inquiry": {
                "label": "Inquiry Value",
                "tooltip": "Initial estimated project value from customer inquiry/budget",
                "total_value": total_inquiry_value,
                "count": inquiry_count
            },
            "booked": {
                "label": "Booked Value",
                "tooltip": "Value locked at first payment (quotation value when booking received)",
                "total_value": total_booked_value,
                "count": booked_count
            },
            "signoff": {
                "label": "Sign-Off Value",
                "tooltip": "Final contracted value locked at design sign-off milestone",
                "total_value": total_signoff_value,
                "count": signoff_count
            },
            "cancelled": {
                "label": "Cancelled Value",
                "tooltip": "Total value lost from cancelled projects (captured at cancellation)",
                "total_value": total_cancelled_value,
                "count": cancelled_count
            }
        },
        
        "conversion_rates": {
            "inquiry_to_booked": {
                "rate": round(inquiry_to_booked_rate, 1),
                "label": "Inquiry → Booked"
            },
            "booked_to_signoff": {
                "rate": round(booked_to_signoff_rate, 1),
                "label": "Booked → Sign-Off"
            }
        },
        
        "value_changes": {
            "inquiry_to_booked": {
                "absolute_change": inquiry_to_booked_value_change,
                "percent_change": round(inquiry_to_booked_value_pct, 1),
                "projects_with_increase": positive_changes_inquiry_to_booked,
                "projects_with_decrease": negative_changes_inquiry_to_booked,
                "label": "Inquiry → Booked"
            },
            "booked_to_signoff": {
                "absolute_change": booked_to_signoff_value_change,
                "percent_change": round(booked_to_signoff_value_pct, 1),
                "projects_with_increase": positive_changes_booked_to_signoff,
                "projects_with_decrease": negative_changes_booked_to_signoff,
                "label": "Booked → Sign-Off"
            }
        },
        
        "stage_breakdown": sorted_stages,
        
        "cancelled_projects": cancelled_projects,
        
        "generated_at": datetime.now(timezone.utc).isoformat()
    }


# ============ DESIGNER PERFORMANCE DASHBOARD ============

@api_router.get("/dashboards/designer")
async def get_designer_performance_dashboard(
    request: Request,
    period: str = "fy",  # fy (default), mtd, qtd, custom
    from_date: Optional[str] = None,
    to_date: Optional[str] = None
):
    """
    DESIGNER PERFORMANCE DASHBOARD
    
    Access: Admin, Founder, DesignManager
    
    Purpose: Track designer value contribution and performance.
    
    ATTRIBUTION RULES (Fair Accountability):
    - Sign-Off Value: Attributed to Primary designer at time of sign-off
    - Cancelled Value: Attributed to Primary designer at time of cancellation
    - Booked Value: Attributed to Primary designer at time of booking
    - Active Projects: Attributed to current Primary designer
    
    Per Designer Metrics:
    - Total Booked Value handled
    - Total Sign-Off Value achieved
    - Net value change (booked → signoff)
    - Project count (active, completed, cancelled)
    - Retention rate (non-cancelled)
    
    Time-based performance with custom date filters.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # Access control: Admin, Founder, DesignManager
    allowed_roles = ["Admin", "Founder", "DesignManager"]
    if user_doc.get("role") not in allowed_roles and not user_doc.get("is_founder"):
        if not has_permission(user_doc, "admin.view_reports"):
            raise HTTPException(status_code=403, detail="Access denied. Designer Dashboard requires Design Manager or Admin permissions.")
    
    # Determine date range based on period
    if period == "mtd":
        today = datetime.now(timezone.utc)
        start_date = datetime(today.year, today.month, 1).strftime("%Y-%m-%d")
        end_date = today.strftime("%Y-%m-%d")
        period_label = "Month to Date"
    elif period == "qtd":
        today = datetime.now(timezone.utc)
        quarter_month = ((today.month - 1) // 3) * 3 + 1
        start_date = datetime(today.year, quarter_month, 1).strftime("%Y-%m-%d")
        end_date = today.strftime("%Y-%m-%d")
        period_label = "Quarter to Date"
    elif period == "custom" and from_date and to_date:
        start_date = from_date
        end_date = to_date
        period_label = f"{from_date} to {to_date}"
    else:  # Default: Financial Year
        start_date, end_date = get_financial_year_range()
        period_label = f"FY {start_date[:4]}-{int(start_date[:4])+1}"
    
    # Get ALL projects (including cancelled) for designer analysis
    projects = await db.projects.find({}, {"_id": 0}).to_list(None)
    
    # Get all designer assignments for attribution lookup
    all_assignments = await db.designer_assignments.find({}, {"_id": 0}).to_list(None)
    
    # Build assignment lookup by project
    project_assignments = {}
    for a in all_assignments:
        pid = a.get("project_id")
        if pid not in project_assignments:
            project_assignments[pid] = []
        project_assignments[pid].append(a)
    
    # Get all users for designer names
    users = await db.users.find({}, {"_id": 0, "user_id": 1, "name": 1, "role": 1}).to_list(None)
    user_map = {u["user_id"]: u for u in users}
    
    def get_primary_at_timestamp(project_id: str, timestamp: str) -> Optional[str]:
        """Get Primary designer_id active at given timestamp"""
        assignments = project_assignments.get(project_id, [])
        for a in assignments:
            if a.get("role") != "Primary":
                continue
            assigned_from = a.get("assigned_from", "")
            assigned_to = a.get("assigned_to")
            if assigned_from <= timestamp:
                if assigned_to is None or assigned_to > timestamp:
                    return a.get("designer_id")
        return None
    
    def get_current_primary(project_id: str) -> Optional[str]:
        """Get current active Primary designer_id"""
        assignments = project_assignments.get(project_id, [])
        for a in assignments:
            if a.get("role") == "Primary" and a.get("assigned_to") is None:
                return a.get("designer_id")
        return None
    
    # Designer metrics dictionary
    designer_metrics = {}
    
    # Totals for comparison
    total_booked_all = 0
    total_signoff_all = 0
    total_projects = 0
    
    for project in projects:
        project_id = project.get("project_id")
        stage = project.get("stage", "Unknown")
        
        # Determine attribution based on project status
        if stage == "Cancelled":
            # Cancelled: Attribute to Primary at cancellation time
            cancelled_at = project.get("cancelled_at", project.get("updated_at", ""))
            attributed_designer = get_primary_at_timestamp(project_id, cancelled_at)
        elif project.get("signoff_locked"):
            # Signed-off: Attribute to Primary at sign-off time
            signoff_at = project.get("signoff_locked_at", project.get("updated_at", ""))
            attributed_designer = get_primary_at_timestamp(project_id, signoff_at)
        else:
            # Active/In-progress: Attribute to current Primary
            attributed_designer = get_current_primary(project_id)
        
        # Fallback to project's primary_designer_id if no assignment found
        if not attributed_designer:
            attributed_designer = project.get("primary_designer_id")
        
        if not attributed_designer:
            attributed_designer = "unassigned"
        
        # Initialize designer entry if not exists
        if attributed_designer not in designer_metrics:
            designer_name = user_map.get(attributed_designer, {}).get("name")
            if not designer_name and attributed_designer != "unassigned":
                designer_name = project.get("primary_designer_name", "Unknown")
            designer_metrics[attributed_designer] = {
                "designer_id": attributed_designer,
                "designer_name": designer_name or "Unassigned",
                "total_booked_value": 0,
                "total_signoff_value": 0,
                "net_value_change": 0,
                "project_count": 0,
                "active_projects": 0,
                "completed_projects": 0,
                "cancelled_projects": 0,
                "cancelled_value": 0,
                "projects": [],
                # Monthly breakdown for trend analysis
                "monthly_breakdown": {}
            }
        
        dm = designer_metrics[attributed_designer]
        
        # Get values
        booked_value = project.get("booked_value") or 0
        signoff_value = project.get("signoff_value") or 0
        cancelled_value = project.get("cancelled_value") or 0
        
        # Track totals
        dm["project_count"] += 1
        total_projects += 1
        
        # Handle cancelled projects
        if stage == "Cancelled":
            dm["cancelled_projects"] += 1
            dm["cancelled_value"] += cancelled_value
        elif stage in ["Handover", "Completed"]:
            dm["completed_projects"] += 1
        else:
            dm["active_projects"] += 1
        
        # Add values (only from booked projects)
        if project.get("booked_value_locked") and booked_value > 0:
            dm["total_booked_value"] += booked_value
            total_booked_all += booked_value
        
        if project.get("signoff_locked") and signoff_value > 0:
            dm["total_signoff_value"] += signoff_value
            total_signoff_all += signoff_value
        
        # Monthly breakdown for trend
        created_at = project.get("created_at")
        if created_at:
            try:
                if isinstance(created_at, str):
                    created_dt = datetime.fromisoformat(created_at.replace("Z", "+00:00"))
                else:
                    created_dt = created_at
                month_key = created_dt.strftime("%Y-%m")
                
                if month_key not in dm["monthly_breakdown"]:
                    dm["monthly_breakdown"][month_key] = {
                        "month": month_key,
                        "booked_value": 0,
                        "signoff_value": 0,
                        "project_count": 0
                    }
                dm["monthly_breakdown"][month_key]["project_count"] += 1
                if project.get("booked_value_locked"):
                    dm["monthly_breakdown"][month_key]["booked_value"] += booked_value
                if project.get("signoff_locked"):
                    dm["monthly_breakdown"][month_key]["signoff_value"] += signoff_value
            except (ValueError, TypeError):
                pass
        
        # Project detail
        dm["projects"].append({
            "project_id": project.get("project_id"),
            "pid": project.get("pid"),
            "client_name": project.get("client_name"),
            "stage": stage,
            "booked_value": booked_value,
            "signoff_value": signoff_value,
            "status": "Cancelled" if stage == "Cancelled" else ("Completed" if stage in ["Handover", "Completed"] else "Active")
        })
    
    # Calculate net value change and retention for each designer
    designer_list = []
    for designer_id, dm in designer_metrics.items():
        dm["net_value_change"] = dm["total_signoff_value"] - dm["total_booked_value"]
        dm["net_value_change_percent"] = round(
            (dm["net_value_change"] / dm["total_booked_value"] * 100) if dm["total_booked_value"] > 0 else 0, 1
        )
        
        # Retention rate (non-cancelled / total)
        non_cancelled = dm["project_count"] - dm["cancelled_projects"]
        dm["retention_rate"] = round(
            (non_cancelled / dm["project_count"] * 100) if dm["project_count"] > 0 else 0, 1
        )
        
        # Convert monthly_breakdown dict to sorted list
        dm["monthly_breakdown"] = sorted(
            dm["monthly_breakdown"].values(), 
            key=lambda x: x["month"]
        )
        
        # Contribution percentage
        dm["booked_value_contribution"] = round(
            (dm["total_booked_value"] / total_booked_all * 100) if total_booked_all > 0 else 0, 1
        )
        dm["signoff_value_contribution"] = round(
            (dm["total_signoff_value"] / total_signoff_all * 100) if total_signoff_all > 0 else 0, 1
        )
        
        designer_list.append(dm)
    
    # Sort by signoff value (top performers first)
    designer_list.sort(key=lambda x: -x["total_signoff_value"])
    
    # Calculate team totals
    team_totals = {
        "total_booked_value": total_booked_all,
        "total_signoff_value": total_signoff_all,
        "net_value_change": total_signoff_all - total_booked_all,
        "net_value_change_percent": round(
            ((total_signoff_all / total_booked_all - 1) * 100) if total_booked_all > 0 else 0, 1
        ),
        "total_projects": total_projects,
        "active_designers": len([d for d in designer_list if d["project_count"] > 0 and d["designer_id"] != "unassigned"])
    }
    
    return {
        "dashboard_type": "designer_performance",
        "value_sources_tooltip": "This dashboard tracks designer performance: Booked Value (at first payment) and Sign-Off Value (final contract). Net change shows value gained/lost during design process.",
        
        "attribution_rules": {
            "sign_off": "Primary designer at time of sign-off",
            "cancelled": "Primary designer at time of cancellation",
            "active": "Current Primary designer",
            "note": "Designer assignments track full history - mid-project changes preserve accountability"
        },
        
        "period": {
            "type": period,
            "label": period_label,
            "from_date": start_date,
            "to_date": end_date
        },
        
        "team_summary": team_totals,
        
        "designers": designer_list,
        
        "generated_at": datetime.now(timezone.utc).isoformat()
    }


# ============ PROJECT FINANCIALS ============

# Default payment schedule - Arki Dots business rules
# Stage 1: Design Booking - Fixed ₹25,000 (can be changed to percentage)
# Stage 2: Production Start - 50% of project value
# Stage 3: Before Installation - Remaining amount
DEFAULT_PAYMENT_SCHEDULE = [
    {
        "stage": "Design Booking",
        "type": "fixed",  # fixed, percentage, or remaining
        "fixedAmount": 25000,
        "percentage": 10  # Used if type is changed to percentage
    },
    {
        "stage": "Production Start",
        "type": "percentage",
        "percentage": 50
    },
    {
        "stage": "Before Installation",
        "type": "remaining"
    }
]

class ProjectFinancialsUpdate(BaseModel):
    project_value: Optional[float] = None
    payment_schedule: Optional[List[dict]] = None
    custom_payment_schedule_enabled: Optional[bool] = None
    custom_payment_schedule: Optional[List[dict]] = None

class ProjectSettingsUpdate(BaseModel):
    """Update project settings (GST, etc.)"""
    gst_applicable: Optional[bool] = None
    gst_number: Optional[str] = None

class PaymentCreate(BaseModel):
    amount: float
    mode: str  # Cash, Bank, UPI, Other
    reference: Optional[str] = ""
    date: Optional[str] = None

PAYMENT_MODES = ["Cash", "Bank", "UPI", "Other"]
PAYMENT_SCHEDULE_TYPES = ["fixed", "percentage", "remaining"]

def calculate_schedule_amounts(payment_schedule, project_value):
    """Calculate amounts for each payment schedule stage"""
    milestone_amounts = []
    total_fixed_and_percentage = 0
    remaining_index = -1
    
    for i, schedule in enumerate(payment_schedule):
        stage_type = schedule.get("type", "percentage")
        stage = schedule.get("stage", f"Stage {i+1}")
        
        if stage_type == "fixed":
            amount = schedule.get("fixedAmount", 0)
            total_fixed_and_percentage += amount
            milestone_amounts.append({
                "stage": stage,
                "type": "fixed",
                "fixedAmount": schedule.get("fixedAmount", 0),
                "percentage": schedule.get("percentage", 0),
                "amount": amount
            })
        elif stage_type == "percentage":
            percentage = schedule.get("percentage", 0)
            amount = (project_value * percentage) / 100
            total_fixed_and_percentage += amount
            milestone_amounts.append({
                "stage": stage,
                "type": "percentage",
                "percentage": percentage,
                "amount": amount
            })
        elif stage_type == "remaining":
            remaining_index = i
            milestone_amounts.append({
                "stage": stage,
                "type": "remaining",
                "amount": 0  # Will be calculated after
            })
    
    # Calculate remaining amount
    if remaining_index >= 0:
        remaining_amount = max(0, project_value - total_fixed_and_percentage)
        milestone_amounts[remaining_index]["amount"] = remaining_amount
    
    return milestone_amounts

def validate_payment_schedule(schedule):
    """Validate payment schedule"""
    errors = []
    remaining_count = 0
    total_percentage = 0
    
    for i, item in enumerate(schedule):
        stage_type = item.get("type", "percentage")
        
        if stage_type not in PAYMENT_SCHEDULE_TYPES:
            errors.append(f"Stage {i+1}: Invalid type '{stage_type}'")
        
        if stage_type == "remaining":
            remaining_count += 1
        
        if stage_type == "percentage":
            percentage = item.get("percentage", 0)
            if percentage < 0 or percentage > 100:
                errors.append(f"Stage {i+1}: Percentage must be between 0 and 100")
            total_percentage += percentage
        
        if stage_type == "fixed":
            fixed_amount = item.get("fixedAmount", 0)
            if fixed_amount < 0:
                errors.append(f"Stage {i+1}: Fixed amount cannot be negative")
        
        if not item.get("stage"):
            errors.append(f"Stage {i+1}: Stage name is required")
    
    if remaining_count > 1:
        errors.append("Only one 'remaining' stage is allowed")
    
    if total_percentage > 100:
        errors.append(f"Total percentage ({total_percentage}%) cannot exceed 100%")
    
    return errors

@api_router.get("/projects/{project_id}/financials")
async def get_project_financials(project_id: str, request: Request):
    """Get project financial details - payments derived from CashBook/Receipts
    
    GOVERNANCE RULE: Execution Revenue Baseline = signoff_value ONLY
    - No fallback to presales budget, booked_value, or contract_value
    - If signoff_value not set, show "Sign-off Pending" status
    """
    user = await get_current_user(request)
    
    # PreSales cannot access financials
    if user.role == "PreSales":
        raise HTTPException(status_code=403, detail="Access denied")
    
    project = await db.projects.find_one({"project_id": project_id}, {"_id": 0})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    # Designer can only view projects they're part of
    if user.role == "Designer" and user.user_id not in project.get("collaborators", []):
        raise HTTPException(status_code=403, detail="Access denied")
    
    # GOVERNANCE: Use signoff_value ONLY for financial calculations - NO FALLBACKS
    signoff_value = project.get("signoff_value") or 0
    signoff_locked = project.get("signoff_locked", False)
    
    # Keep project_value as informational only (presales estimate)
    presales_budget = project.get("project_value", 0)
    
    custom_enabled = project.get("custom_payment_schedule_enabled", False)
    custom_schedule = project.get("custom_payment_schedule", [])
    default_schedule = project.get("payment_schedule", DEFAULT_PAYMENT_SCHEDULE)
    
    # ============ SINGLE SOURCE OF TRUTH: Fetch payments from CashBook ============
    # Payments are now derived from accounting_transactions (inflow) linked to this project
    cashbook_payments = await db.accounting_transactions.find(
        {"project_id": project_id, "transaction_type": "inflow"},
        {"_id": 0}
    ).sort("date", -1).to_list(500)
    
    # Get user details for payments
    user_ids = list(set([p.get("created_by") for p in cashbook_payments if p.get("created_by")]))
    users_map = {}
    if user_ids:
        users_list = await db.users.find(
            {"user_id": {"$in": user_ids}},
            {"_id": 0, "user_id": 1, "name": 1}
        ).to_list(100)
        users_map = {u["user_id"]: u.get("name", "Unknown") for u in users_list}
    
    # Transform CashBook transactions to payment format for frontend compatibility
    enriched_payments = []
    for txn in cashbook_payments:
        enriched = {
            "id": txn.get("transaction_id"),
            "date": txn.get("date"),
            "amount": txn.get("amount", 0),
            "mode": txn.get("mode", "Bank"),
            "reference": txn.get("remarks", ""),
            "added_by": txn.get("created_by"),
            "added_by_name": users_map.get(txn.get("created_by"), "Unknown"),
            "created_at": txn.get("created_at"),
            "source": "cashbook"  # Indicates this came from CashBook
        }
        enriched_payments.append(enriched)
    
    # Calculate totals from CashBook data
    total_collected = sum(p.get("amount", 0) for p in enriched_payments)
    
    # GOVERNANCE: Balance calculated from signoff_value ONLY (no fallbacks)
    balance_pending = signoff_value - total_collected if signoff_value > 0 else 0
    
    # Calculate milestone amounts using signoff_value as base (GOVERNANCE)
    active_schedule = custom_schedule if (custom_enabled and custom_schedule) else default_schedule
    
    # Only calculate milestones if signoff_value is set
    if signoff_value > 0:
        milestone_amounts = calculate_schedule_amounts(active_schedule, signoff_value)
    else:
        # Return empty milestones if signoff not locked
        milestone_amounts = []
    
    # Determine finance status
    finance_status = "active" if signoff_value > 0 else "signoff_pending"
    
    return {
        "project_id": project_id,
        "project_name": project.get("project_name"),
        # Governance-safe revenue baseline
        "finance_status": finance_status,
        "signoff_value": signoff_value,
        "signoff_locked": signoff_locked,
        # Informational only (NOT for financial calculations)
        "presales_budget": presales_budget,
        "project_value": presales_budget,  # Deprecated alias - kept for backward compatibility
        # Schedule configuration
        "custom_payment_schedule_enabled": custom_enabled,
        "custom_payment_schedule": custom_schedule,
        "default_payment_schedule": default_schedule,
        "payment_schedule": milestone_amounts,
        # Payment data
        "payments": enriched_payments,
        "total_collected": total_collected,
        "balance_pending": balance_pending,
        "can_edit": False,  # DISABLED: No manual payment entry - use CashBook
        "can_delete_payments": False  # DISABLED: Delete via CashBook
    }

@api_router.put("/projects/{project_id}/financials")
async def update_project_financials(project_id: str, data: ProjectFinancialsUpdate, request: Request):
    """Update project financial details (requires finance.project.allocate_funds)"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.project.allocate_funds"):
        raise HTTPException(status_code=403, detail="Permission denied: finance.project.allocate_funds required")
    
    project = await db.projects.find_one({"project_id": project_id}, {"_id": 0})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    update_dict = {"updated_at": datetime.now(timezone.utc).isoformat()}
    
    if data.project_value is not None:
        if data.project_value < 0:
            raise HTTPException(status_code=400, detail="Project value cannot be negative")
        update_dict["project_value"] = data.project_value
    
    # Handle default payment schedule update (for changing Design Booking type)
    if data.payment_schedule is not None:
        errors = validate_payment_schedule(data.payment_schedule)
        if errors:
            raise HTTPException(status_code=400, detail="; ".join(errors))
        update_dict["payment_schedule"] = data.payment_schedule
    
    # Handle custom payment schedule toggle
    if data.custom_payment_schedule_enabled is not None:
        update_dict["custom_payment_schedule_enabled"] = data.custom_payment_schedule_enabled
    
    # Handle custom payment schedule update
    if data.custom_payment_schedule is not None:
        if data.custom_payment_schedule:  # If not empty, validate
            errors = validate_payment_schedule(data.custom_payment_schedule)
            if errors:
                raise HTTPException(status_code=400, detail="; ".join(errors))
        update_dict["custom_payment_schedule"] = data.custom_payment_schedule
    
    await db.projects.update_one(
        {"project_id": project_id},
        {"$set": update_dict}
    )
    
    return {"message": "Project financials updated successfully"}

@api_router.put("/projects/{project_id}/settings")
async def update_project_settings(project_id: str, data: ProjectSettingsUpdate, request: Request):
    """Update project settings (GST applicable, GST number, etc.)"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # Only Admin, Founder, ProjectManager can update settings
    allowed_roles = ["Admin", "Founder", "ProjectManager"]
    if user_doc.get("role") not in allowed_roles:
        raise HTTPException(status_code=403, detail="Access denied - requires Admin, Founder, or Project Manager role")
    
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    update_dict = {"updated_at": datetime.now(timezone.utc).isoformat()}
    
    if data.gst_applicable is not None:
        update_dict["gst_applicable"] = data.gst_applicable
        # Also update old field for backward compatibility
        update_dict["is_gst_applicable"] = data.gst_applicable
    
    if data.gst_number is not None:
        # Validate GST number format if provided
        if data.gst_number:
            gst_pattern = r'^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z]{1}[1-9A-Z]{1}Z[0-9A-Z]{1}$'
            if not re.match(gst_pattern, data.gst_number.upper()):
                raise HTTPException(status_code=400, detail="Invalid GST number format. Expected format: 22AAAAA0000A1Z5")
        update_dict["gst_number"] = data.gst_number.upper() if data.gst_number else None
    
    await db.projects.update_one(
        {"project_id": project_id},
        {"$set": update_dict}
    )
    
    return {"success": True, "message": "Project settings updated successfully"}

