@api_router.post("/academy/upload")
async def upload_academy_file(request: Request, file: UploadFile = File(...)):
    """
    Upload a file (video, PDF, image) for Academy lessons.
    Requires academy.manage permission.
    Files are stored locally and served to authenticated users only.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "academy.manage"):
        raise HTTPException(status_code=403, detail="Permission denied: academy.manage required")
    
    # Academy allows videos, PDFs, and images
    academy_allowed = ALLOWED_VIDEO_EXTENSIONS | ALLOWED_PDF_EXTENSIONS | ALLOWED_IMAGE_EXTENSIONS
    
    # Use centralized file validation
    content, safe_filename, file_ext = await validated_file_upload(
        file=file,
        allowed_extensions=academy_allowed,
        max_size_bytes=MAX_FILE_SIZE,  # 500MB for videos
        validate_content=True,
        context="academy file"
    )
    
    # Determine file type for response
    if file_ext in ALLOWED_VIDEO_EXTENSIONS:
        file_type = "video"
    elif file_ext in ALLOWED_PDF_EXTENSIONS:
        file_type = "pdf"
    else:
        file_type = "image"
    
    # Save file
    file_path = UPLOADS_DIR / safe_filename
    async with aiofiles.open(file_path, 'wb') as out_file:
        await out_file.write(content)
    
    # Return the URL to access the file
    file_url = f"/api/academy/files/{safe_filename}"
    
    return {
        "success": True,
        "file_url": file_url,
        "file_type": file_type,
        "file_name": file.filename,
        "file_size": len(content),
        "uploaded_by": user.name
    }


@api_router.get("/academy/files/{filename}")
async def serve_academy_file(filename: str, request: Request):
    """
    Serve Academy files to authenticated users only.
    This ensures internal training content is not publicly accessible.
    """
    # Authenticate user
    user = await get_current_user(request)
    
    # Validate filename (prevent directory traversal)
    if ".." in filename or "/" in filename or "\\" in filename:
        raise HTTPException(status_code=400, detail="Invalid filename")
    
    file_path = UPLOADS_DIR / filename
    
    if not file_path.exists():
        raise HTTPException(status_code=404, detail="File not found")
    
    # Determine content type based on extension
    ext = Path(filename).suffix.lower()
    content_types = {
        ".mp4": "video/mp4",
        ".mov": "video/quicktime",
        ".avi": "video/x-msvideo",
        ".webm": "video/webm",
        ".pdf": "application/pdf",
        ".jpg": "image/jpeg",
        ".jpeg": "image/jpeg",
        ".png": "image/png",
        ".gif": "image/gif",
        ".webp": "image/webp"
    }
    
    content_type = content_types.get(ext, "application/octet-stream")
    
    return FileResponse(
        path=file_path,
        media_type=content_type,
        filename=filename
    )


@api_router.delete("/academy/files/{filename}")
async def delete_academy_file(filename: str, request: Request):
    """Delete an Academy file (requires academy.manage)"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "academy.manage"):
        raise HTTPException(status_code=403, detail="Permission denied: academy.manage required")
    
    # Validate filename
    if ".." in filename or "/" in filename or "\\" in filename:
        raise HTTPException(status_code=400, detail="Invalid filename")
    
    file_path = UPLOADS_DIR / filename
    
    if not file_path.exists():
        raise HTTPException(status_code=404, detail="File not found")
    
    # Delete the file
    file_path.unlink()
    
    return {"success": True, "message": "File deleted"}



