@api_router.get("/accounting/accounts")
async def list_accounting_accounts(request: Request, include_archived: bool = False):
    """List all accounting accounts (bank/cash)
    
    P1-FIX: Option to include/exclude archived accounts
    - Default: exclude archived accounts
    - include_archived=True: show all accounts including archived
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.view_dashboard") and not has_permission(user_doc, "finance.view_cashbook"):
        raise HTTPException(status_code=403, detail="Access denied - no finance view permission")
    
    query = {}
    if not include_archived:
        # Exclude archived accounts by default
        query["$or"] = [
            {"is_archived": {"$ne": True}},
            {"is_archived": {"$exists": False}}
        ]
    
    accounts = await db.accounting_accounts.find(query, {"_id": 0}).to_list(100)
    return accounts


@api_router.post("/accounting/accounts")
async def create_accounting_account(account: AccountCreate, request: Request):
    """Create a new accounting account (Admin only) with P1-FIX: duplicate detection"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.manage_accounts"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.manage_accounts permission")
    
    # P1-FIX: Check for duplicate account by name (case-insensitive)
    existing_by_name = await db.accounting_accounts.find_one({
        "account_name": {"$regex": f"^{account.account_name}$", "$options": "i"}
    })
    if existing_by_name:
        raise HTTPException(
            status_code=409,
            detail=f"Account with name '{account.account_name}' already exists"
        )
    
    # P1-FIX: Check for duplicate bank account number (if provided)
    if account.bank_name and account.branch:
        existing_by_bank = await db.accounting_accounts.find_one({
            "bank_name": {"$regex": f"^{account.bank_name}$", "$options": "i"},
            "branch": {"$regex": f"^{account.branch}$", "$options": "i"},
            "account_type": account.account_type
        })
        if existing_by_bank:
            raise HTTPException(
                status_code=409,
                detail=f"Account with same bank, branch and type already exists"
            )
    
    now = datetime.now(timezone.utc)
    account_id = f"acc_{uuid.uuid4().hex[:8]}"
    
    new_account = {
        "account_id": account_id,
        "account_name": account.account_name,
        "account_type": account.account_type,
        "bank_name": account.bank_name,
        "branch": account.branch,
        "category": account.category,
        "opening_balance": account.opening_balance,
        "current_balance": account.opening_balance,
        "is_active": account.is_active,
        "is_archived": False,  # P1-FIX: Archive support
        "created_at": now.isoformat(),
        "created_by": user.user_id,
        "updated_at": now.isoformat()
    }
    
    await db.accounting_accounts.insert_one(new_account)
    
    # Log audit entry
    audit_entry = {
        "audit_id": f"audit_{uuid.uuid4().hex[:8]}",
        "action": "account_created",
        "entity_type": "accounting_account",
        "entity_id": account_id,
        "user_id": user.user_id,
        "user_name": user.name,
        "details": f"Created account: {account.account_name}",
        "timestamp": now.isoformat()
    }
    await db.accounting_audit_log.insert_one(audit_entry)
    
    return {**new_account, "_id": None}


@api_router.put("/accounting/accounts/{account_id}")
async def update_accounting_account(account_id: str, account: AccountUpdate, request: Request):
    """Update an accounting account"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.manage_accounts"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.manage_accounts permission")
    
    existing = await db.accounting_accounts.find_one({"account_id": account_id})
    if not existing:
        raise HTTPException(status_code=404, detail="Account not found")
    
    now = datetime.now(timezone.utc)
    update_dict = {"updated_at": now.isoformat()}
    
    for field in ["account_name", "bank_name", "branch", "category", "is_active"]:
        value = getattr(account, field, None)
        if value is not None:
            update_dict[field] = value
    
    await db.accounting_accounts.update_one(
        {"account_id": account_id},
        {"$set": update_dict}
    )
    
    updated = await db.accounting_accounts.find_one({"account_id": account_id}, {"_id": 0})
    return updated


@api_router.put("/accounting/accounts/{account_id}/opening-balance")
async def set_opening_balance(account_id: str, request: Request):
    """Set opening balance for an account (Admin only, with audit log)"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.set_opening_balance"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.set_opening_balance permission")
    
    body = await request.json()
    new_balance = body.get("opening_balance")
    
    if new_balance is None:
        raise HTTPException(status_code=400, detail="opening_balance is required")
    
    existing = await db.accounting_accounts.find_one({"account_id": account_id})
    if not existing:
        raise HTTPException(status_code=404, detail="Account not found")
    
    old_balance = existing.get("opening_balance", 0)
    now = datetime.now(timezone.utc)
    
    # Calculate balance difference and update current balance
    balance_diff = new_balance - old_balance
    new_current = existing.get("current_balance", old_balance) + balance_diff
    
    await db.accounting_accounts.update_one(
        {"account_id": account_id},
        {"$set": {
            "opening_balance": new_balance,
            "current_balance": new_current,
            "updated_at": now.isoformat()
        }}
    )
    
    # Audit log
    audit_entry = {
        "audit_id": f"audit_{uuid.uuid4().hex[:8]}",
        "action": "opening_balance_set",
        "entity_type": "accounting_account",
        "entity_id": account_id,
        "user_id": user.user_id,
        "user_name": user.name,
        "details": f"Changed opening balance from {old_balance} to {new_balance}",
        "old_value": old_balance,
        "new_value": new_balance,
        "timestamp": now.isoformat()
    }
    await db.accounting_audit_log.insert_one(audit_entry)
    
    updated = await db.accounting_accounts.find_one({"account_id": account_id}, {"_id": 0})
    return {"success": True, "account": updated}


# P1-FIX: Account Archive/Delete endpoint
@api_router.delete("/accounting/accounts/{account_id}")
async def archive_or_delete_account(account_id: str, request: Request, force_delete: bool = False):
    """Archive or delete an accounting account
    
    P1-FIX: Account deletion/archive control
    - Default behavior: Archive (soft delete) - account remains but is_archived=True
    - force_delete=True: Hard delete (only if no transactions exist)
    
    Archived accounts:
    - Cannot be used for new transactions
    - Still visible in historical reports
    - Can be restored if needed
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.manage_accounts"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.manage_accounts permission")
    
    existing = await db.accounting_accounts.find_one({"account_id": account_id})
    if not existing:
        raise HTTPException(status_code=404, detail="Account not found")
    
    # Check if account has any transactions
    txn_count = await db.accounting_transactions.count_documents({"account_id": account_id})
    
    now = datetime.now(timezone.utc)
    
    if force_delete:
        # Hard delete - only allowed if no transactions
        if txn_count > 0:
            raise HTTPException(
                status_code=400,
                detail=f"Cannot delete account with {txn_count} transactions. Archive it instead."
            )
        
        await db.accounting_accounts.delete_one({"account_id": account_id})
        
        # Audit log
        audit_entry = {
            "audit_id": f"audit_{uuid.uuid4().hex[:8]}",
            "action": "account_deleted",
            "entity_type": "accounting_account",
            "entity_id": account_id,
            "user_id": user.user_id,
            "user_name": user.name,
            "details": f"Permanently deleted account: {existing.get('account_name')}",
            "timestamp": now.isoformat()
        }
        await db.accounting_audit_log.insert_one(audit_entry)
        
        return {"success": True, "action": "deleted", "message": "Account permanently deleted"}
    else:
        # Soft delete (archive)
        await db.accounting_accounts.update_one(
            {"account_id": account_id},
            {"$set": {
                "is_archived": True,
                "is_active": False,
                "archived_at": now.isoformat(),
                "archived_by": user.user_id,
                "updated_at": now.isoformat()
            }}
        )
        
        # Audit log
        audit_entry = {
            "audit_id": f"audit_{uuid.uuid4().hex[:8]}",
            "action": "account_archived",
            "entity_type": "accounting_account",
            "entity_id": account_id,
            "user_id": user.user_id,
            "user_name": user.name,
            "details": f"Archived account: {existing.get('account_name')} (had {txn_count} transactions)",
            "timestamp": now.isoformat()
        }
        await db.accounting_audit_log.insert_one(audit_entry)
        
        return {"success": True, "action": "archived", "message": "Account archived successfully", "transaction_count": txn_count}


@api_router.post("/accounting/accounts/{account_id}/restore")
async def restore_archived_account(account_id: str, request: Request):
    """Restore an archived account
    
    P1-FIX: Allow restoring archived accounts
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.manage_accounts"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.manage_accounts permission")
    
    existing = await db.accounting_accounts.find_one({"account_id": account_id})
    if not existing:
        raise HTTPException(status_code=404, detail="Account not found")
    
    if not existing.get("is_archived"):
        raise HTTPException(status_code=400, detail="Account is not archived")
    
    now = datetime.now(timezone.utc)
    
    await db.accounting_accounts.update_one(
        {"account_id": account_id},
        {"$set": {
            "is_archived": False,
            "is_active": True,
            "restored_at": now.isoformat(),
            "restored_by": user.user_id,
            "updated_at": now.isoformat()
        }}
    )
    
    # Audit log
    audit_entry = {
        "audit_id": f"audit_{uuid.uuid4().hex[:8]}",
        "action": "account_restored",
        "entity_type": "accounting_account",
        "entity_id": account_id,
        "user_id": user.user_id,
        "user_name": user.name,
        "details": f"Restored archived account: {existing.get('account_name')}",
        "timestamp": now.isoformat()
    }
    await db.accounting_audit_log.insert_one(audit_entry)
    
    updated = await db.accounting_accounts.find_one({"account_id": account_id}, {"_id": 0})
    return {"success": True, "account": updated}


