@api_router.get("/accounting/vendors")
async def list_vendors(request: Request, vendor_type: Optional[str] = None, is_active: Optional[bool] = None):
    """List all vendors with optional filters"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.view_vendors"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.view_vendors permission")
    
    query = {}
    if vendor_type:
        query["vendor_type"] = vendor_type
    if is_active is not None:
        query["is_active"] = is_active
    
    vendors = await db.accounting_vendors.find(query, {"_id": 0}).sort("vendor_name", 1).to_list(500)
    return vendors


@api_router.get("/accounting/vendors/{vendor_id}")
async def get_vendor(vendor_id: str, request: Request):
    """Get a single vendor"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.view_vendors"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    vendor = await db.accounting_vendors.find_one({"vendor_id": vendor_id}, {"_id": 0})
    if not vendor:
        raise HTTPException(status_code=404, detail="Vendor not found")
    
    return vendor


@api_router.post("/accounting/vendors")
async def create_vendor(vendor: VendorCreate, request: Request):
    """Create a new vendor"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.manage_vendors"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.manage_vendors permission")
    
    now = datetime.now(timezone.utc)
    vendor_id = f"vendor_{uuid.uuid4().hex[:8]}"
    
    new_vendor = {
        "vendor_id": vendor_id,
        "vendor_name": vendor.vendor_name,
        "vendor_type": vendor.vendor_type,
        "contact_person": vendor.contact_person,
        "phone": vendor.phone,
        "email": vendor.email,
        "address": vendor.address,
        "gstin": vendor.gstin,
        "pan": vendor.pan,
        "bank_account_name": vendor.bank_account_name,
        "bank_account_number": vendor.bank_account_number,
        "bank_ifsc": vendor.bank_ifsc,
        "notes": vendor.notes,
        "is_active": vendor.is_active,
        "created_at": now,
        "created_by": user.user_id,
        "created_by_name": user.name
    }
    
    await db.accounting_vendors.insert_one(new_vendor)
    
    # Auto-create party sub-ledger account for this vendor
    try:
        subledger_account = await create_party_subledger_account(
            party_type="vendor",
            party_id=vendor_id,
            party_name=vendor.vendor_name,
            user_id=user.user_id,
            user_name=user.name
        )
        new_vendor["subledger_account_id"] = subledger_account.get("account_id")
        # Update vendor with linked account
        await db.accounting_vendors.update_one(
            {"vendor_id": vendor_id},
            {"$set": {"subledger_account_id": subledger_account.get("account_id")}}
        )
    except Exception as e:
        logger.warning(f"Failed to create sub-ledger for vendor {vendor_id}: {e}")
    
    # Audit log
    await db.accounting_audit_log.insert_one({
        "action": "vendor_created",
        "entity_type": "vendor",
        "entity_id": vendor_id,
        "user_id": user.user_id,
        "user_name": user.name,
        "details": f"Created vendor: {vendor.vendor_name} ({vendor.vendor_type})",
        "timestamp": now
    })
    
    new_vendor.pop("_id", None)
    return new_vendor


@api_router.put("/accounting/vendors/{vendor_id}")
async def update_vendor(vendor_id: str, vendor: VendorUpdate, request: Request):
    """Update a vendor"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.manage_vendors"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.manage_vendors permission")
    
    existing = await db.accounting_vendors.find_one({"vendor_id": vendor_id})
    if not existing:
        raise HTTPException(status_code=404, detail="Vendor not found")
    
    now = datetime.now(timezone.utc)
    update_dict = {"updated_at": now, "updated_by": user.user_id}
    
    changes = []
    for field, value in vendor.dict(exclude_unset=True).items():
        if value is not None and existing.get(field) != value:
            changes.append(f"{field}: {existing.get(field)} → {value}")
            update_dict[field] = value
    
    if len(update_dict) > 2:  # Has actual changes beyond timestamps
        await db.accounting_vendors.update_one(
            {"vendor_id": vendor_id},
            {"$set": update_dict}
        )
        
        # Audit log
        await db.accounting_audit_log.insert_one({
            "action": "vendor_updated",
            "entity_type": "vendor",
            "entity_id": vendor_id,
            "user_id": user.user_id,
            "user_name": user.name,
            "details": f"Updated vendor: {existing.get('vendor_name')}. Changes: {'; '.join(changes)}",
            "changes": changes,
            "timestamp": now
        })
    
    updated = await db.accounting_vendors.find_one({"vendor_id": vendor_id}, {"_id": 0})
    return updated


@api_router.delete("/accounting/vendors/{vendor_id}")
async def deactivate_vendor(vendor_id: str, request: Request):
    """Soft delete (deactivate) a vendor"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.manage_vendors"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    existing = await db.accounting_vendors.find_one({"vendor_id": vendor_id})
    if not existing:
        raise HTTPException(status_code=404, detail="Vendor not found")
    
    now = datetime.now(timezone.utc)
    await db.accounting_vendors.update_one(
        {"vendor_id": vendor_id},
        {"$set": {"is_active": False, "deactivated_at": now, "deactivated_by": user.user_id}}
    )
    
    # Audit log
    await db.accounting_audit_log.insert_one({
        "action": "vendor_deactivated",
        "entity_type": "vendor",
        "entity_id": vendor_id,
        "user_id": user.user_id,
        "user_name": user.name,
        "details": f"Deactivated vendor: {existing.get('vendor_name')}",
        "timestamp": now
    })
    
    return {"success": True, "message": "Vendor deactivated"}


@api_router.post("/accounting/vendors/quick-create")
async def quick_create_vendor(vendor: VendorQuickCreate, request: Request):
    """Quick-create a vendor with just a name - for use in dropdowns"""
    user = await get_current_user(request)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")
    
    # Normalize vendor name
    normalized_name = vendor.vendor_name.strip()
    if not normalized_name:
        raise HTTPException(status_code=400, detail="Vendor name is required")
    
    # Check if vendor already exists (case-insensitive)
    existing = await db.accounting_vendors.find_one(
        {"vendor_name": {"$regex": f"^{re.escape(normalized_name)}$", "$options": "i"}},
        {"_id": 0}
    )
    
    if existing:
        # Return existing vendor instead of creating duplicate
        return existing
    
    # Create new vendor with minimal info
    now = datetime.now(timezone.utc)
    vendor_id = f"vendor_{uuid.uuid4().hex[:8]}"
    
    new_vendor = {
        "vendor_id": vendor_id,
        "vendor_name": normalized_name,
        "vendor_type": vendor.vendor_type or "material",
        "contact_person": None,
        "phone": None,
        "email": None,
        "address": None,
        "gstin": None,
        "pan": None,
        "bank_account_name": None,
        "bank_account_number": None,
        "bank_ifsc": None,
        "notes": None,
        "is_active": True,
        "auto_created": True,  # Flag to identify quick-created vendors
        "created_at": now,
        "created_by": user.user_id,
        "created_by_name": user.name
    }
    
    await db.accounting_vendors.insert_one(new_vendor)
    new_vendor.pop("_id", None)
    
    return new_vendor


async def get_or_create_unified_vendor(vendor_name: str, user_id: str = None, user_name: str = None) -> dict:
    """Get existing vendor or create new one in the unified vendor master (accounting_vendors)"""
    normalized_name = vendor_name.strip()
    
    # Check if vendor exists (case-insensitive)
    existing = await db.accounting_vendors.find_one(
        {"vendor_name": {"$regex": f"^{re.escape(normalized_name)}$", "$options": "i"}},
        {"_id": 0}
    )
    
    if existing:
        return existing
    
    # Create new vendor
    now = datetime.now(timezone.utc)
    vendor_id = f"vendor_{uuid.uuid4().hex[:8]}"
    
    new_vendor = {
        "vendor_id": vendor_id,
        "vendor_name": normalized_name,
        "vendor_type": "material",
        "is_active": True,
        "auto_created": True,
        "created_at": now,
        "created_by": user_id,
        "created_by_name": user_name
    }
    
    await db.accounting_vendors.insert_one(new_vendor)
    return {k: v for k, v in new_vendor.items() if k != "_id"}


# ============ AUDIT LOG ENDPOINT ============

@api_router.get("/accounting/audit-log")
async def get_audit_log(
    request: Request,
    entity_type: Optional[str] = None,
    entity_id: Optional[str] = None,
    user_id: Optional[str] = None,
    start_date: Optional[str] = None,
    end_date: Optional[str] = None,
    limit: int = 100
):
    """Get audit log entries - Admin only"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if user_doc.get("role") != "Admin":
        raise HTTPException(status_code=403, detail="Admin only")
    
    query = {}
    if entity_type:
        query["entity_type"] = entity_type
    if entity_id:
        query["entity_id"] = entity_id
    if user_id:
        query["user_id"] = user_id
    if start_date or end_date:
        date_filter = {}
        if start_date:
            date_filter["$gte"] = datetime.fromisoformat(start_date.replace('Z', '+00:00'))
        if end_date:
            date_filter["$lte"] = datetime.fromisoformat(end_date.replace('Z', '+00:00'))
        if date_filter:
            query["timestamp"] = date_filter
    
    logs = await db.accounting_audit_log.find(query, {"_id": 0}).sort("timestamp", -1).to_list(limit)
    
    # Convert datetime to ISO string
    for log in logs:
        if isinstance(log.get("timestamp"), datetime):
            log["timestamp"] = log["timestamp"].isoformat()
    
    return logs


# ============ ACCOUNTING: TRANSACTIONS (CASH BOOK / DAY BOOK) ============

@api_router.get("/accounting/transactions")
async def list_transactions(
    request: Request,
    date: Optional[str] = None,
    account_id: Optional[str] = None,
    category_id: Optional[str] = None,
    project_id: Optional[str] = None,
    start_date: Optional[str] = None,
    end_date: Optional[str] = None,
    needs_review: Optional[bool] = None,
    include_non_cashbook: bool = False  # P0-FIX: Option to include non-cashbook entries
):
    """List transactions (Cash Book view) - excludes credit purchases by default"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.view_cashbook") and not has_permission(user_doc, "finance.view_bankbook"):
        raise HTTPException(status_code=403, detail="Access denied - no finance view permission")
    
    query = {}
    
    # P0-FIX: Exclude non-cashbook entries (like unpaid credit purchases) from cashbook view
    # Cashbook should only show entries with actual cash movement (has account_id)
    # Credit purchases create daybook entries without account_id until payment is made
    if not include_non_cashbook:
        # Filter out entries that are explicitly marked as non-cashbook
        # OR entries that have no account_id (meaning no actual cash movement)
        query["$and"] = [
            {"is_cashbook_entry": {"$ne": False}},  # Not explicitly marked as non-cashbook
            {"$or": [
                {"account_id": {"$ne": None}},  # Has account = real transaction
                {"entry_type": {"$nin": ["purchase_invoice_credit", "purchase_invoice"]}}  # Not a credit purchase
            ]}
        ]
    
    if date:
        query["transaction_date"] = {"$regex": f"^{date}"}
    elif start_date or end_date:
        date_filter = {}
        if start_date:
            date_filter["$gte"] = start_date
        if end_date:
            date_filter["$lte"] = end_date
        if date_filter:
            query["transaction_date"] = date_filter
    
    if account_id:
        query["account_id"] = account_id
    if category_id:
        query["category_id"] = category_id
    if project_id:
        query["project_id"] = project_id
    if needs_review is not None:
        query["needs_review"] = needs_review
    
    transactions = await db.accounting_transactions.find(query, {"_id": 0}).sort("created_at", -1).to_list(1000)
    
    accounts = {a["account_id"]: a for a in await db.accounting_accounts.find({}, {"_id": 0}).to_list(100)}
    categories = {c["category_id"]: c for c in await db.accounting_categories.find({}, {"_id": 0}).to_list(100)}
    
    for txn in transactions:
        txn["account_name"] = accounts.get(txn.get("account_id"), {}).get("account_name", "Unknown")
        txn["category_name"] = categories.get(txn.get("category_id"), {}).get("name", "Unknown")
        
        if txn.get("project_id"):
            project = await db.projects.find_one(
                {"project_id": txn["project_id"]},
                {"_id": 0, "pid": 1, "project_name": 1, "client_name": 1}
            )
            if project:
                txn["project_pid"] = project.get("pid", "").replace("ARKI-", "")
                txn["project_name"] = project.get("project_name", "")
                txn["client_name"] = project.get("client_name", "")
    
    return transactions


@api_router.post("/accounting/transactions")
async def create_transaction(txn: TransactionCreate, request: Request):
    """Create a new transaction entry with guardrails"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.add_transaction"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.add_transaction permission")
    
    if not txn.remarks or not txn.remarks.strip():
        raise HTTPException(status_code=400, detail="Remarks is required")
    
    if txn.amount <= 0:
        raise HTTPException(status_code=400, detail="Amount must be greater than 0")
    
    txn_date = txn.transaction_date[:10]
    daily_closing = await db.accounting_daily_closings.find_one({"date": txn_date, "is_locked": True})
    if daily_closing:
        raise HTTPException(status_code=400, detail=f"Day {txn_date} is locked. Cannot add transactions.")
    
    account = await db.accounting_accounts.find_one({"account_id": txn.account_id})
    if not account:
        raise HTTPException(status_code=400, detail="Invalid account")
    
    # Static income categories for inflow transactions
    INCOME_CATEGORIES = [
        'income_project_payment',
        'income_advance_booking', 
        'income_design_fee',
        'income_refund_reversal',
        'income_other'
    ]
    
    # For inflows, accept static income categories OR database categories
    # For outflows, only accept database categories (expense categories)
    if txn.transaction_type == "inflow" and txn.category_id in INCOME_CATEGORIES:
        category = {"category_id": txn.category_id, "name": txn.category_id.replace('income_', '').replace('_', ' ').title()}
    else:
        category = await db.accounting_categories.find_one({"category_id": txn.category_id})
        if not category:
            raise HTTPException(status_code=400, detail="Invalid category")
    
    if txn.project_id:
        project = await db.projects.find_one({"project_id": txn.project_id})
        if not project:
            raise HTTPException(status_code=400, detail="Invalid project ID")
    
    # ============ GUARDRAILS FOR OUTFLOWS ============
    needs_review = False
    approval_status = "not_required"  # not_required, needs_review, approved, pending_approval
    
    if txn.transaction_type == "outflow":
        # Determine approval status based on amount thresholds
        if txn.amount <= CASHBOOK_THRESHOLDS["petty_cash_max"]:
            # Petty cash - direct entry allowed
            approval_status = "not_required"
        elif txn.amount <= CASHBOOK_THRESHOLDS["review_threshold"]:
            # Mid-range - allow entry but flag for review
            needs_review = True
            approval_status = "needs_review"
        else:
            # High value - require approver or expense request link
            if txn.expense_request_id:
                # Verify expense request is approved
                expense_req = await db.finance_expense_requests.find_one({"request_id": txn.expense_request_id})
                if not expense_req:
                    raise HTTPException(status_code=400, detail="Invalid expense request ID")
                if expense_req.get("status") != "approved":
                    raise HTTPException(status_code=400, detail="Expense request is not approved")
                approval_status = "approved"
            elif txn.approved_by:
                # Has approver selected
                approver = await db.users.find_one({"user_id": txn.approved_by})
                if not approver:
                    raise HTTPException(status_code=400, detail="Invalid approver")
                approval_status = "approved"
            else:
                # No approval - must still be allowed but flagged strongly
                needs_review = True
                approval_status = "pending_approval"
    
    now = datetime.now(timezone.utc)
    txn_id = f"txn_{uuid.uuid4().hex[:8]}"
    
    # Handle vendor_id - if provided, get vendor name
    vendor_id = txn.vendor_id
    paid_to = txn.paid_to
    
    if vendor_id:
        vendor = await db.accounting_vendors.find_one({"vendor_id": vendor_id}, {"_id": 0})
        if vendor:
            paid_to = paid_to or vendor.get("vendor_name")
    
    new_txn = {
        "transaction_id": txn_id,
        "transaction_date": txn.transaction_date,
        "transaction_type": txn.transaction_type,
        "amount": txn.amount,
        "mode": txn.mode,
        "category_id": txn.category_id,
        "account_id": txn.account_id,
        "project_id": txn.project_id,
        "vendor_id": vendor_id,
        "paid_to": paid_to,
        "remarks": txn.remarks,
        "attachment_url": txn.attachment_url,
        "is_verified": False,
        "verified_by": None,
        "verified_at": None,
        # Accountability fields
        "requested_by": txn.requested_by or user.user_id,
        "requested_by_name": txn.requested_by_name or user.name,
        "paid_by": user.user_id,  # Person creating entry = person who paid
        "paid_by_name": user.name,
        "paid_from_account": account.get("account_name", "Unknown"),
        "approved_by": txn.approved_by,
        "approved_by_name": txn.approved_by_name,
        "expense_request_id": txn.expense_request_id,
        # Guardrail flags
        "needs_review": needs_review,
        "approval_status": approval_status,
        "reviewed_by": None,
        "reviewed_at": None,
        # Metadata
        "created_at": now.isoformat(),
        "created_by": user.user_id,
        "created_by_name": user.name,
        "updated_at": now.isoformat()
    }
    
    await db.accounting_transactions.insert_one(new_txn)
    
    balance_change = txn.amount if txn.transaction_type == "inflow" else -txn.amount
    await db.accounting_accounts.update_one(
        {"account_id": txn.account_id},
        {"$inc": {"current_balance": balance_change}}
    )
    
    # ============ PARTY SUB-LEDGER POSTING ============
    # Post to vendor sub-ledger if vendor_id provided (outflow = credit vendor, later payment debits)
    if vendor_id and txn.transaction_type == "outflow":
        try:
            vendor_account = await get_party_subledger_account("vendor", vendor_id)
            if vendor_account:
                # Outflow to vendor = Credit vendor account (increase payable)
                await post_party_transaction(
                    party_account_id=vendor_account["account_id"],
                    transaction_type="credit",
                    amount=txn.amount,
                    transaction_id=txn_id,
                    remarks=f"Purchase: {txn.remarks[:100] if txn.remarks else 'No remarks'}",
                    transaction_date=txn.transaction_date,
                    user_id=user.user_id,
                    user_name=user.name,
                    source_module="cashbook"
                )
        except Exception as e:
            logger.warning(f"Failed to post vendor sub-ledger for txn {txn_id}: {e}")
    
    # Post to customer sub-ledger if project_id provided (inflow = credit customer, reduces receivable)
    if txn.project_id and txn.transaction_type == "inflow":
        try:
            customer_account = await get_party_subledger_account("customer", txn.project_id)
            if customer_account:
                # Inflow from customer = Credit customer account (reduces receivable)
                await post_party_transaction(
                    party_account_id=customer_account["account_id"],
                    transaction_type="credit",
                    amount=txn.amount,
                    transaction_id=txn_id,
                    remarks=f"Payment received: {txn.remarks[:100] if txn.remarks else 'No remarks'}",
                    transaction_date=txn.transaction_date,
                    user_id=user.user_id,
                    user_name=user.name,
                    source_module="cashbook"
                )
        except Exception as e:
            logger.warning(f"Failed to post customer sub-ledger for txn {txn_id}: {e}")
    
    # Audit log for cashbook create
    await create_audit_log(
        entity_type="cashbook",
        entity_id=txn_id,
        action="create",
        user_id=user.user_id,
        user_name=user.name,
        new_value={"amount": txn.amount, "type": txn.transaction_type, "remarks": txn.remarks[:100] if txn.remarks else ""},
        details=f"Created {txn.transaction_type} of ₹{txn.amount:,.0f}"
    )
    
    return {**new_txn, "_id": None}


# ============ SELF-TRANSFER / INTERNAL TRANSFER ============
class SelfTransferCreate(BaseModel):
    from_account_id: str
    to_account_id: str
    amount: float
    transfer_date: str
    notes: Optional[str] = None


@api_router.post("/accounting/self-transfer")
async def create_self_transfer(transfer: SelfTransferCreate, request: Request):
    """Create an internal transfer between two accounts (Bank→Bank, Bank→Petty Cash, etc.)
    This creates TWO linked transactions: one outflow, one inflow, with a shared transfer_id.
    No P&L impact, no vendor, no receipt."""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # Permission check - same as regular transactions
    if not has_permission(user_doc, "finance.add_transaction") and not has_permission(user_doc, "finance.cashbook.create"):
        raise HTTPException(status_code=403, detail="Access denied - no permission to create transactions")
    
    # Validate accounts
    if transfer.from_account_id == transfer.to_account_id:
        raise HTTPException(status_code=400, detail="From and To accounts must be different")
    
    from_account = await db.accounting_accounts.find_one({"account_id": transfer.from_account_id})
    if not from_account:
        raise HTTPException(status_code=404, detail="Source account not found")
    
    to_account = await db.accounting_accounts.find_one({"account_id": transfer.to_account_id})
    if not to_account:
        raise HTTPException(status_code=404, detail="Destination account not found")
    
    if transfer.amount <= 0:
        raise HTTPException(status_code=400, detail="Amount must be positive")
    
    # Check sufficient balance in source account
    if from_account.get("current_balance", 0) < transfer.amount:
        raise HTTPException(
            status_code=400, 
            detail=f"Insufficient balance in {from_account.get('account_name')}. Available: ₹{from_account.get('current_balance', 0):,.0f}"
        )
    
    now = datetime.now(timezone.utc)
    transfer_id = f"trf_{uuid.uuid4().hex[:8]}"
    
    # Create OUTFLOW from source account
    outflow_txn_id = f"txn_{uuid.uuid4().hex[:8]}"
    outflow_txn = {
        "transaction_id": outflow_txn_id,
        "transaction_date": transfer.transfer_date,
        "transaction_type": "outflow",
        "amount": transfer.amount,
        "mode": "bank_transfer",
        "category_id": "internal_transfer",
        "account_id": transfer.from_account_id,
        "project_id": None,
        "vendor_id": None,
        "paid_to": f"Transfer to {to_account.get('account_name')}",
        "remarks": f"Internal Transfer to {to_account.get('account_name')}" + (f" - {transfer.notes}" if transfer.notes else ""),
        "is_verified": True,  # Auto-verified as it's a controlled transfer
        "is_internal_transfer": True,
        "transfer_id": transfer_id,
        "paired_transaction_id": None,  # Will update after creating inflow
        "transfer_direction": "out",
        "created_at": now.isoformat(),
        "created_by": user.user_id,
        "created_by_name": user.name,
        "updated_at": now.isoformat()
    }
    
    # Create INFLOW to destination account
    inflow_txn_id = f"txn_{uuid.uuid4().hex[:8]}"
    inflow_txn = {
        "transaction_id": inflow_txn_id,
        "transaction_date": transfer.transfer_date,
        "transaction_type": "inflow",
        "amount": transfer.amount,
        "mode": "bank_transfer",
        "category_id": "internal_transfer",
        "account_id": transfer.to_account_id,
        "project_id": None,
        "vendor_id": None,
        "received_from": f"Transfer from {from_account.get('account_name')}",
        "remarks": f"Internal Transfer from {from_account.get('account_name')}" + (f" - {transfer.notes}" if transfer.notes else ""),
        "is_verified": True,
        "is_internal_transfer": True,
        "transfer_id": transfer_id,
        "paired_transaction_id": outflow_txn_id,
        "transfer_direction": "in",
        "created_at": now.isoformat(),
        "created_by": user.user_id,
        "created_by_name": user.name,
        "updated_at": now.isoformat()
    }
    
    # Update outflow with paired transaction ID
    outflow_txn["paired_transaction_id"] = inflow_txn_id
    
    # Insert both transactions
    await db.accounting_transactions.insert_one(outflow_txn)
    await db.accounting_transactions.insert_one(inflow_txn)
    
    # Update account balances
    await db.accounting_accounts.update_one(
        {"account_id": transfer.from_account_id},
        {"$inc": {"current_balance": -transfer.amount}}
    )
    await db.accounting_accounts.update_one(
        {"account_id": transfer.to_account_id},
        {"$inc": {"current_balance": transfer.amount}}
    )
    
    # Audit log
    await create_audit_log(
        entity_type="self_transfer",
        entity_id=transfer_id,
        action="create",
        user_id=user.user_id,
        user_name=user.name,
        new_value={
            "from_account": from_account.get("account_name"),
            "to_account": to_account.get("account_name"),
            "amount": transfer.amount
        },
        details=f"Internal transfer of ₹{transfer.amount:,.0f} from {from_account.get('account_name')} to {to_account.get('account_name')}"
    )
    
    return {
        "success": True,
        "transfer_id": transfer_id,
        "outflow_transaction_id": outflow_txn_id,
        "inflow_transaction_id": inflow_txn_id,
        "from_account": from_account.get("account_name"),
        "to_account": to_account.get("account_name"),
        "amount": transfer.amount,
        "message": f"Successfully transferred ₹{transfer.amount:,.0f} from {from_account.get('account_name')} to {to_account.get('account_name')}"
    }


@api_router.put("/accounting/transactions/{transaction_id}")
async def update_transaction(transaction_id: str, txn: TransactionUpdate, request: Request):
    """Update a transaction (only if day is not locked)"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.edit_transaction"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.edit_transaction permission")
    
    existing = await db.accounting_transactions.find_one({"transaction_id": transaction_id})
    if not existing:
        raise HTTPException(status_code=404, detail="Transaction not found")
    
    txn_date = existing.get("transaction_date", "")[:10]
    daily_closing = await db.accounting_daily_closings.find_one({"date": txn_date, "is_locked": True})
    if daily_closing:
        raise HTTPException(status_code=400, detail=f"Day {txn_date} is locked. Cannot edit transactions.")
    
    now = datetime.now(timezone.utc)
    update_dict = {"updated_at": now.isoformat()}
    
    old_amount = existing.get("amount", 0)
    old_type = existing.get("transaction_type")
    old_account_id = existing.get("account_id")
    
    for field in ["transaction_type", "amount", "mode", "category_id", "account_id", "project_id", "paid_to", "remarks", "attachment_url"]:
        value = getattr(txn, field, None)
        if value is not None:
            update_dict[field] = value
    
    await db.accounting_transactions.update_one(
        {"transaction_id": transaction_id},
        {"$set": update_dict}
    )
    
    new_amount = update_dict.get("amount", old_amount)
    new_type = update_dict.get("transaction_type", old_type)
    new_account_id = update_dict.get("account_id", old_account_id)
    
    old_balance_change = old_amount if old_type == "inflow" else -old_amount
    await db.accounting_accounts.update_one(
        {"account_id": old_account_id},
        {"$inc": {"current_balance": -old_balance_change}}
    )
    
    new_balance_change = new_amount if new_type == "inflow" else -new_amount
    await db.accounting_accounts.update_one(
        {"account_id": new_account_id},
        {"$inc": {"current_balance": new_balance_change}}
    )
    
    # Audit log for cashbook edit
    await create_audit_log(
        entity_type="cashbook",
        entity_id=transaction_id,
        action="edit",
        user_id=user.user_id,
        user_name=user.name,
        old_value={"amount": old_amount, "type": old_type, "account_id": old_account_id},
        new_value=update_dict,
        details=f"Edited transaction"
    )
    
    updated = await db.accounting_transactions.find_one({"transaction_id": transaction_id}, {"_id": 0})
    return updated


