@api_router.post("/finance/party-subledger/migrate-existing")
async def migrate_existing_to_subledgers(request: Request):
    """
    Data migration endpoint to create sub-ledger accounts for existing vendors, projects, and employees.
    This is a one-time migration operation.
    """
    user = await get_current_user(request)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")
    
    user_doc = await db.users.find_one({"user_id": user.user_id})
    if not has_permission(user_doc, "finance.party_subledger.manage") and user_doc.get("role") not in ["Founder", "Admin"]:
        raise HTTPException(status_code=403, detail="Access denied - Admin only")
    
    # Ensure control accounts exist
    await ensure_control_accounts_exist()
    
    migration_stats = {
        "vendors_created": 0,
        "vendors_skipped": 0,
        "customers_created": 0,
        "customers_skipped": 0,
        "employees_created": 0,
        "employees_skipped": 0,
        "errors": []
    }
    
    # Migrate vendors
    vendors = await db.accounting_vendors.find({"is_active": {"$ne": False}}, {"_id": 0}).to_list(1000)
    for vendor in vendors:
        try:
            existing = await db.party_subledger_accounts.find_one({
                "party_type": "vendor",
                "party_id": vendor.get("vendor_id"),
                "is_control": {"$ne": True}
            })
            if existing:
                migration_stats["vendors_skipped"] += 1
            else:
                await create_party_subledger_account(
                    party_type="vendor",
                    party_id=vendor.get("vendor_id"),
                    party_name=vendor.get("vendor_name", "Unknown"),
                    user_id=user.user_id,
                    user_name=user.name
                )
                migration_stats["vendors_created"] += 1
        except Exception as e:
            migration_stats["errors"].append(f"Vendor {vendor.get('vendor_id')}: {str(e)}")
    
    # Migrate projects (customers)
    projects = await db.projects.find({"stage": {"$ne": "Cancelled"}}, {"_id": 0, "project_id": 1, "project_name": 1, "client_name": 1, "pid": 1}).to_list(5000)
    for proj in projects:
        try:
            existing = await db.party_subledger_accounts.find_one({
                "party_type": "customer",
                "party_id": proj.get("project_id"),
                "is_control": {"$ne": True}
            })
            if existing:
                migration_stats["customers_skipped"] += 1
            else:
                customer_name = f"{proj.get('client_name', 'Unknown')} ({proj.get('pid', proj.get('project_id'))})"
                await create_party_subledger_account(
                    party_type="customer",
                    party_id=proj.get("project_id"),
                    party_name=customer_name,
                    user_id=user.user_id,
                    user_name=user.name
                )
                migration_stats["customers_created"] += 1
        except Exception as e:
            migration_stats["errors"].append(f"Project {proj.get('project_id')}: {str(e)}")
    
    # Migrate employees
    employees = await db.users.find({"status": "Active"}, {"_id": 0, "user_id": 1, "name": 1}).to_list(500)
    for emp in employees:
        try:
            existing = await db.party_subledger_accounts.find_one({
                "party_type": "employee",
                "party_id": emp.get("user_id"),
                "is_control": {"$ne": True}
            })
            if existing:
                migration_stats["employees_skipped"] += 1
            else:
                await create_party_subledger_account(
                    party_type="employee",
                    party_id=emp.get("user_id"),
                    party_name=emp.get("name", "Unknown"),
                    user_id=user.user_id,
                    user_name=user.name
                )
                migration_stats["employees_created"] += 1
        except Exception as e:
            migration_stats["errors"].append(f"Employee {emp.get('user_id')}: {str(e)}")
    
    # Log migration
    await db.finance_audit_log.insert_one({
        "audit_id": f"aud_{uuid.uuid4().hex[:12]}",
        "entity_type": "party_subledger_migration",
        "entity_id": "migration",
        "action": "bulk_migrate",
        "details": f"Migrated existing entities to sub-ledgers",
        "user_id": user.user_id,
        "user_name": user.name,
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "migration_stats": migration_stats
    })
    
    return {
        "success": True,
        "message": "Migration completed",
        "stats": migration_stats
    }


# ============================================================================
# ============ PROJECT PROFIT VISIBILITY =====================================
# ============================================================================
# Enhanced project finance metrics - projected vs realised profit

@api_router.get("/finance/project-profit/{project_id}")
async def get_project_profit(project_id: str, request: Request):
    """Get profit metrics for a project
    
    GOVERNANCE RULE: Revenue baseline must be signoff_value ONLY.
    No fallback to presales budget, contract_value, or booked_value.
    
    If signoff_value is not locked:
    - Return status: "signoff_not_locked"
    - Show 0 for all profit calculations
    """
    user = await get_current_user(request)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")
    
    # Get project with value lifecycle fields
    project = await db.projects.find_one(
        {"project_id": project_id}, 
        {"_id": 0, "project_id": 1, "project_name": 1, "name": 1,
         "signoff_value": 1, "signoff_locked": 1}
    )
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    # GOVERNANCE: Strict signoff_value enforcement - NO FALLBACKS
    signoff_value = project.get("signoff_value") or 0
    signoff_locked = project.get("signoff_locked", False)
    
    # Block profit calculations if signoff not locked
    if signoff_value <= 0:
        return {
            "project_id": project_id,
            "project_name": project.get("name") or project.get("project_name"),
            "status": "signoff_not_locked",
            "message": "Profit projections require sign-off lock.",
            "signoff_value": 0,
            "signoff_locked": False,
            # Zero out all profit metrics
            "planned_cost": 0,
            "actual_cost": 0,
            "total_received": 0,
            "projected_profit": 0,
            "projected_profit_pct": 0,
            "realised_profit": 0,
            "realised_profit_pct": 0,
            "execution_margin_remaining": 0
        }
    
    # Get planned cost from vendor mappings (check both collection names)
    vendor_mappings = await db.vendor_mappings.find(
        {"project_id": project_id},
        {"_id": 0, "planned_cost": 1, "planned_amount": 1}
    ).to_list(1000)
    if not vendor_mappings:
        vendor_mappings = await db.finance_vendor_mappings.find(
            {"project_id": project_id},
            {"_id": 0, "planned_cost": 1, "planned_amount": 1}
        ).to_list(1000)
    planned_cost = sum(vm.get("planned_cost") or vm.get("planned_amount", 0) for vm in vendor_mappings)
    
    # Get actual cost (ONLY cashbook entries - exclude credit purchase daybook entries)
    actual_outflows = await db.accounting_transactions.find({
        "project_id": project_id,
        "transaction_type": "outflow",
        # Exclude non-cashbook entries (credit purchases that haven't been paid)
        "$or": [
            {"is_cashbook_entry": {"$ne": False}},
            {"is_cashbook_entry": {"$exists": False}}
        ],
        "entry_type": {"$nin": ["purchase_invoice", "purchase_invoice_credit"]}
    }, {"_id": 0, "amount": 1}).to_list(10000)
    actual_cost = sum(t.get("amount", 0) for t in actual_outflows)
    
    # Get total received (Sign-off Collected Amount)
    receipts = await db.finance_receipts.find(
        {"project_id": project_id},
        {"_id": 0, "amount": 1}
    ).to_list(1000)
    receipts_total = sum(r.get("amount", 0) for r in receipts)
    
    inflows = await db.accounting_transactions.find({
        "project_id": project_id,
        "transaction_type": "inflow"
    }, {"_id": 0, "amount": 1}).to_list(10000)
    inflows_total = sum(t.get("amount", 0) for t in inflows)
    
    total_received = max(receipts_total, inflows_total)  # Avoid double-counting
    
    # Calculate profits based on Sign-off Locked BOQ Value (NO FALLBACKS)
    # Projected Profit = Sign-off Locked Value – Planned Cost
    projected_profit = signoff_value - planned_cost
    projected_profit_pct = (projected_profit / signoff_value * 100) if signoff_value > 0 else 0
    
    # Realised Profit = Sign-off Collected Amount – Actual Cost
    realised_profit = total_received - actual_cost
    realised_profit_pct = (realised_profit / total_received * 100) if total_received > 0 else 0
    
    # Execution Margin = Based only on Sign-off Locked Value
    execution_margin_remaining = projected_profit - realised_profit
    
    return {
        "project_id": project_id,
        "project_name": project.get("name") or project.get("project_name"),
        "status": "active",
        # Governance-safe revenue baseline
        "signoff_value": signoff_value,
        "signoff_locked": signoff_locked,
        # Costs
        "planned_cost": planned_cost,
        "actual_cost": actual_cost,
        "total_received": total_received,
        # Projected Profit (Sign-off Value - Planned Cost)
        "projected_profit": projected_profit,
        "projected_profit_pct": round(projected_profit_pct, 1),
        # Realised Profit (Received - Actual Cost)
        "realised_profit": realised_profit,
        "realised_profit_pct": round(realised_profit_pct, 1),
        # Execution Margin
        "execution_margin_remaining": execution_margin_remaining
    }


# ============================================================================
# ============ PAYMENT & RECEIPT SYSTEM (PHASE 4) ============================
# ============================================================================
# Flexible payment schedules, receipts, invoices, refunds, cancellations
# ALL permission-based via Admin checkboxes - NO hardcoded role logic

# Default payment stages (can be customized per project)
DEFAULT_PAYMENT_STAGES = [
    {"stage_name": "Booking Amount", "percentage": None, "fixed_amount": 25000, "trigger": "booking", "order": 1, "stage_type": "fixed"},
    {"stage_name": "After Design Finalization", "percentage": 50, "fixed_amount": None, "trigger": "design_complete", "order": 2, "stage_type": "percentage"},
    {"stage_name": "After Production Completion", "percentage": None, "fixed_amount": None, "trigger": "production_complete", "order": 3, "stage_type": "remaining"}
]

# Payment modes
PAYMENT_MODES = ["cash", "bank_transfer", "upi", "cheque", "card", "other"]


class PaymentStageCreate(BaseModel):
    stage_name: str
    percentage: Optional[float] = None  # Either percentage or fixed_amount
    fixed_amount: Optional[float] = None
    trigger: Optional[str] = None  # booking, design_complete, production_complete, custom
    order: int = 1

class PaymentScheduleUpdate(BaseModel):
    stages: List[dict]  # List of payment stages

class ReceiptCreate(BaseModel):
    project_id: str
    amount: float
    payment_mode: str
    account_id: str
    stage_name: Optional[str] = None  # Which payment stage this is for
    notes: Optional[str] = None
    payment_date: Optional[str] = None  # ISO date string
    idempotency_key: Optional[str] = None  # Client-provided key to prevent duplicates

class RefundCreate(BaseModel):
    project_id: str
    amount: float
    refund_type: str  # full, partial, forfeited
    reason: str
    account_id: str
    notes: Optional[str] = None
    idempotency_key: Optional[str] = None  # Client-provided key to prevent duplicates
    status: str = "initiated"  # Status lifecycle: initiated -> pending -> completed


# ============ PAYMENT SCHEDULE ============

@api_router.get("/finance/payment-schedule/{project_id}")
async def get_payment_schedule(project_id: str, request: Request):
    """Get payment schedule for a project
    
    GOVERNANCE RULE: Revenue baseline must be signoff_value ONLY.
    No fallback to presales budget, contract_value, or booked_value.
    
    If signoff_value is not locked (missing or 0):
    - Return status: "signoff_not_locked"
    - Do NOT generate schedule
    
    Default Stage Calculation (when is_custom=false):
    - Stage 1: Booking (fixed amount)
    - Stage 2: 50% of signoff_value
    - Stage 3: Remaining balance = signoff_value - booking - stage2
    
    Custom schedules are preserved as-is but still require signoff_value.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.view_project_finance"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    # Get project
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    # GOVERNANCE: Strict signoff_value enforcement - NO FALLBACKS
    signoff_value = project.get("signoff_value") or 0
    signoff_locked = project.get("signoff_locked", False)
    
    # Block schedule generation if signoff not locked
    if signoff_value <= 0:
        return {
            "project_id": project_id,
            "status": "signoff_not_locked",
            "message": "Payment schedule cannot be generated before sign-off lock.",
            "signoff_value": 0,
            "signoff_locked": False,
            "is_custom": False,
            "stages": [],
            "total_expected": 0,
            "total_received": 0,
            "balance_remaining": 0
        }
    
    # Check if custom schedule exists
    schedule = await db.finance_payment_schedules.find_one(
        {"project_id": project_id},
        {"_id": 0}
    )
    
    # Revenue baseline: signoff_value ONLY (no fallbacks)
    base_value = signoff_value
    is_custom = schedule is not None
    
    if is_custom:
        # Custom schedules: Preserve existing stage structure as-is
        stages = schedule.get("stages", [])
        
        # For custom schedules, recalculate amounts based on stored structure
        # anchored strictly to signoff_value
        for stage in stages:
            if stage.get("percentage") and stage.get("percentage") > 0:
                stage["calculated_amount"] = round(base_value * stage["percentage"] / 100, 0)
            elif stage.get("fixed_amount") and stage.get("fixed_amount") > 0:
                stage["calculated_amount"] = stage["fixed_amount"]
            elif stage.get("stage_type") == "remaining":
                # Will be calculated after all other stages
                pass
        
        # Calculate remaining stage if exists
        total_non_remaining = sum(
            s.get("calculated_amount", 0) 
            for s in stages 
            if s.get("stage_type") != "remaining"
        )
        for stage in stages:
            if stage.get("stage_type") == "remaining":
                stage["calculated_amount"] = max(0, base_value - total_non_remaining)
                
    else:
        # Default schedule: Apply correct calculation logic
        # Stage 1: Fixed booking
        # Stage 2: 50% of signoff_value
        # Stage 3: Remaining balance (signoff_value - booking - stage2)
        
        stages = []
        total_fixed_and_percentage = 0
        remaining_stage_index = -1
        
        for i, s in enumerate(DEFAULT_PAYMENT_STAGES):
            stage = s.copy()
            stage_type = stage.get("stage_type", "percentage")
            
            if stage_type == "fixed":
                # Fixed amount (e.g., Booking = ₹25,000)
                stage["calculated_amount"] = stage.get("fixed_amount", 0)
                total_fixed_and_percentage += stage["calculated_amount"]
            elif stage_type == "percentage" and stage.get("percentage"):
                # Percentage of signoff_value (e.g., 50% of signoff_value)
                stage["calculated_amount"] = round(base_value * stage["percentage"] / 100, 0)
                total_fixed_and_percentage += stage["calculated_amount"]
            elif stage_type == "remaining":
                # Mark for later calculation
                remaining_stage_index = len(stages)
                stage["calculated_amount"] = 0  # Placeholder
            
            stages.append(stage)
        
        # Calculate remaining stage: signoff_value - all other stages
        if remaining_stage_index >= 0:
            remaining_amount = max(0, base_value - total_fixed_and_percentage)
            stages[remaining_stage_index]["calculated_amount"] = remaining_amount
    
    # Get receipts for this project to determine paid status
    receipts = await db.finance_receipts.find(
        {"project_id": project_id, "status": {"$ne": "cancelled"}},
        {"_id": 0}
    ).to_list(100)
    
    total_received = sum(r.get("amount", 0) for r in receipts)
    
    # Mark stages as paid based on received amounts
    running_total = 0
    for stage in stages:
        stage_amount = stage.get("calculated_amount", 0)
        if running_total + stage_amount <= total_received:
            stage["status"] = "paid"
            stage["paid_amount"] = stage_amount
        elif running_total < total_received:
            stage["status"] = "partial"
            stage["paid_amount"] = total_received - running_total
        else:
            stage["status"] = "pending"
            stage["paid_amount"] = 0
        running_total += stage_amount
    
    total_expected = sum(s.get("calculated_amount", 0) for s in stages)
    
    return {
        "project_id": project_id,
        "status": "active",
        "signoff_value": signoff_value,
        "signoff_locked": signoff_locked,
        "is_custom": is_custom,
        "stages": stages,
        "total_expected": total_expected,
        "total_received": total_received,
        "balance_remaining": signoff_value - total_received
    }


@api_router.put("/finance/payment-schedule/{project_id}")
@api_router.post("/finance/payment-schedule/{project_id}")
async def update_payment_schedule(project_id: str, update: PaymentScheduleUpdate, request: Request):
    """Update payment schedule for a project - permission controlled"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # Check permission - NOT role
    if not has_permission(user_doc, "finance.edit_payment_schedule"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.edit_payment_schedule permission")
    
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    now = datetime.now(timezone.utc)
    
    schedule_doc = {
        "project_id": project_id,
        "stages": update.stages,
        "is_custom": True,
        "updated_by": user.user_id,
        "updated_by_name": user.name,
        "updated_at": now
    }
    
    await db.finance_payment_schedules.update_one(
        {"project_id": project_id},
        {"$set": schedule_doc, "$setOnInsert": {"created_at": now}},
        upsert=True
    )
    
    return {"success": True, "message": "Payment schedule updated"}


@api_router.post("/finance/payment-schedule/{project_id}/reset")
async def reset_payment_schedule(project_id: str, request: Request):
    """Reset to default payment schedule"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.edit_payment_schedule"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    await db.finance_payment_schedules.delete_one({"project_id": project_id})
    return {"success": True, "message": "Payment schedule reset to default"}


# ============ RECEIPTS ============

@api_router.get("/finance/receipts")
async def list_receipts(
    request: Request,
    project_id: Optional[str] = None,
    from_date: Optional[str] = None,
    to_date: Optional[str] = None,
    limit: int = 100
):
    """List receipts with optional filters"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.view_receipts"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.view_receipts permission")
    
    query = {"status": {"$ne": "cancelled"}}
    if project_id:
        query["project_id"] = project_id
    if from_date:
        query["payment_date"] = {"$gte": from_date}
    if to_date:
        if "payment_date" in query:
            query["payment_date"]["$lte"] = to_date
        else:
            query["payment_date"] = {"$lte": to_date}
    
    receipts = await db.finance_receipts.find(query, {"_id": 0}).sort("created_at", -1).limit(limit).to_list(limit)
    
    # Enrich with project and account info
    for r in receipts:
        project = await db.projects.find_one({"project_id": r.get("project_id")}, {"_id": 0, "pid": 1, "project_name": 1, "client_name": 1})
        if project:
            r["pid"] = (project.get("pid") or "").replace("ARKI-", "")
            r["project_name"] = project.get("project_name")
            r["client_name"] = project.get("client_name")
        account = await db.accounting_accounts.find_one({"account_id": r.get("account_id")}, {"_id": 0, "account_name": 1})
        if account:
            r["account_name"] = account.get("account_name")
    
    return receipts


@api_router.get("/finance/receipts/{receipt_id}")
async def get_receipt(receipt_id: str, request: Request):
    """Get a single receipt"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.view_receipts"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    receipt = await db.finance_receipts.find_one({"receipt_id": receipt_id}, {"_id": 0})
    if not receipt:
        raise HTTPException(status_code=404, detail="Receipt not found")
    
    # Enrich
    project = await db.projects.find_one({"project_id": receipt.get("project_id")}, {"_id": 0})
    if project:
        receipt["project"] = {
            "pid": (project.get("pid") or "").replace("ARKI-", ""),
            "project_name": project.get("project_name"),
            "client_name": project.get("client_name"),
            "contract_value": project.get("project_value", 0)
        }
    
    account = await db.accounting_accounts.find_one({"account_id": receipt.get("account_id")}, {"_id": 0})
    if account:
        receipt["account_name"] = account.get("account_name")
    
    # Get total received for this project
    all_receipts = await db.finance_receipts.find(
        {"project_id": receipt.get("project_id"), "status": {"$ne": "cancelled"}},
        {"_id": 0, "amount": 1}
    ).to_list(100)
    total_received = sum(r.get("amount", 0) for r in all_receipts)
    receipt["total_received"] = total_received
    receipt["balance_remaining"] = (project.get("project_value", 0) or 0) - total_received
    
    return receipt


@api_router.post("/finance/receipts")
async def create_receipt(receipt: ReceiptCreate, request: Request):
    """Create a payment receipt - permission controlled with idempotency protection"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.add_receipt"):
        raise HTTPException(status_code=403, detail="Access denied - no finance.add_receipt permission")
    
    # P0-FIX: Idempotency check to prevent duplicate receipts
    # Check 1: If idempotency_key provided, check for existing receipt with same key
    if receipt.idempotency_key:
        existing_by_key = await db.finance_receipts.find_one({
            "idempotency_key": receipt.idempotency_key,
            "status": {"$ne": "cancelled"}
        }, {"_id": 0})
        if existing_by_key:
            # Return existing receipt instead of creating duplicate
            return existing_by_key
    
    # Check 2: Duplicate detection - same project, amount, payment_mode within 60 seconds
    recent_cutoff = datetime.now(timezone.utc) - timedelta(seconds=60)
    duplicate_check = await db.finance_receipts.find_one({
        "project_id": receipt.project_id,
        "amount": receipt.amount,
        "payment_mode": receipt.payment_mode,
        "account_id": receipt.account_id,
        "created_at": {"$gte": recent_cutoff},
        "status": {"$ne": "cancelled"}
    }, {"_id": 0})
    if duplicate_check:
        raise HTTPException(
            status_code=409, 
            detail=f"Duplicate receipt detected. Receipt {duplicate_check.get('receipt_number')} was created within the last 60 seconds with same details."
        )
    
    # Validate project
    project = await db.projects.find_one({"project_id": receipt.project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    # Validate account
    account = await db.accounting_accounts.find_one({"account_id": receipt.account_id})
    if not account:
        raise HTTPException(status_code=404, detail="Account not found")
    
    # Validate payment mode
    if receipt.payment_mode not in PAYMENT_MODES:
        raise HTTPException(status_code=400, detail=f"Invalid payment mode. Must be one of: {', '.join(PAYMENT_MODES)}")
    
    now = datetime.now(timezone.utc)
    payment_date = receipt.payment_date or now.strftime("%Y-%m-%d")
    
    # Generate receipt number (RCP-YYYYMMDD-XXXX)
    date_part = now.strftime("%Y%m%d")
    count = await db.finance_receipts.count_documents({"receipt_number": {"$regex": f"^RCP-{date_part}"}})
    receipt_number = f"RCP-{date_part}-{count + 1:04d}"
    
    # Calculate totals
    existing_receipts = await db.finance_receipts.find(
        {"project_id": receipt.project_id, "status": {"$ne": "cancelled"}},
        {"_id": 0, "amount": 1}
    ).to_list(100)
    total_before = sum(r.get("amount", 0) for r in existing_receipts)
    contract_value = project.get("project_value", 0) or 0
    
    receipt_doc = {
        "receipt_id": f"rcp_{secrets.token_hex(4)}",
        "receipt_number": receipt_number,
        "idempotency_key": receipt.idempotency_key,  # Store for future duplicate checks
        "project_id": receipt.project_id,
        "amount": receipt.amount,
        "payment_mode": receipt.payment_mode,
        "account_id": receipt.account_id,
        "stage_name": receipt.stage_name,
        "payment_date": payment_date,
        "notes": receipt.notes,
        "status": "active",
        "total_before": total_before,
        "total_after": total_before + receipt.amount,
        "balance_remaining": contract_value - total_before - receipt.amount,
        "created_by": user.user_id,
        "created_by_name": user.name,
        "created_at": now
    }
    
    # Also create a cashbook transaction (inflow)
    txn_doc = {
        "transaction_id": f"txn_{secrets.token_hex(4)}",
        "transaction_date": payment_date,  # CRITICAL: Must match receipt payment date
        "transaction_type": "inflow",
        "amount": receipt.amount,
        "mode": receipt.payment_mode,
        "category_id": "customer_payment",  # Customer payment category
        "account_id": receipt.account_id,
        "project_id": receipt.project_id,
        "paid_to": None,
        "received_from": project.get("client_name"),
        "remarks": f"Payment receipt {receipt_number} - {receipt.stage_name or 'Customer Payment'}",
        "receipt_id": receipt_doc["receipt_id"],
        "is_receipt_linked": True,  # Mark as receipt-linked to prevent duplicates
        "is_verified": False,
        "created_by": user.user_id,
        "created_by_name": user.name,
        "created_at": now,
        "updated_at": now
    }
    
    await db.finance_receipts.insert_one(receipt_doc)
    await db.accounting_transactions.insert_one(txn_doc)
    
    # Update account balance
    await db.accounting_accounts.update_one(
        {"account_id": receipt.account_id},
        {"$inc": {"current_balance": receipt.amount}}
    )
    
    # Audit log for receipt creation
    await create_audit_log(
        entity_type="receipt",
        entity_id=receipt_doc["receipt_id"],
        action="create",
        user_id=user.user_id,
        user_name=user.name,
        new_value={"amount": receipt.amount, "project_id": receipt.project_id, "receipt_number": receipt_number},
        details=f"Created receipt {receipt_number} for ₹{receipt.amount:,.0f}"
    )
    
    receipt_doc.pop("_id", None)
    return receipt_doc


@api_router.post("/finance/receipts/{receipt_id}/cancel")
async def cancel_receipt(receipt_id: str, reason: str, request: Request):
    """Cancel a receipt"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.issue_refund"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    receipt = await db.finance_receipts.find_one({"receipt_id": receipt_id})
    if not receipt:
        raise HTTPException(status_code=404, detail="Receipt not found")
    
    if receipt.get("status") == "cancelled":
        raise HTTPException(status_code=400, detail="Receipt already cancelled")
    
    now = datetime.now(timezone.utc)
    
    await db.finance_receipts.update_one(
        {"receipt_id": receipt_id},
        {"$set": {
            "status": "cancelled",
            "cancelled_by": user.user_id,
            "cancelled_by_name": user.name,
            "cancelled_at": now,
            "cancellation_reason": reason
        }}
    )
    
    # Also cancel the linked transaction
    await db.accounting_transactions.update_one(
        {"receipt_id": receipt_id},
        {"$set": {"is_cancelled": True, "cancelled_at": now, "cancellation_reason": reason}}
    )
    
    return {"success": True, "message": "Receipt cancelled"}


