@api_router.get("/hr/classification-summary")
async def get_classification_summary(request: Request):
    """Get summary of employees by classification with payment workflow guidance"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "hr.view"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    # Get all active employees
    employees = await db.users.find(
        {"status": {"$ne": "inactive"}},
        {"_id": 0, "user_id": 1, "name": 1, "email": 1, "role": 1, "employee_classification": 1}
    ).to_list(500)
    
    # Build summary
    summary = {
        "total_employees": len(employees),
        "by_classification": {},
        "workflow_guidance": {
            "permanent": {"payment_method": "Salary", "statutory_deductions": "PF, ESI, Professional Tax (auto-calculated)", "can_receive": ["Salary", "Incentives"]},
            "probation": {"payment_method": "Salary", "statutory_deductions": "PF, ESI (auto-calculated)", "can_receive": ["Salary", "Incentives"]},
            "trainee": {"payment_method": "Stipend", "statutory_deductions": "None (exempt)", "can_receive": ["Stipend", "Incentives"]},
            "freelancer": {"payment_method": "Commission/Professional Fee", "statutory_deductions": "None (exempt)", "can_receive": ["Commission"]},
            "channel_partner": {"payment_method": "Commission", "statutory_deductions": "None (exempt)", "can_receive": ["Commission"]}
        }
    }
    
    for classification in EMPLOYEE_CLASSIFICATIONS:
        emps_in_class = [e for e in employees if e.get("employee_classification", "permanent") == classification]
        summary["by_classification"][classification] = {
            "count": len(emps_in_class),
            "employees": emps_in_class,
            "is_salary_eligible": classification in SALARY_ELIGIBLE_CLASSIFICATIONS,
            "is_stipend_eligible": classification in STIPEND_ELIGIBLE_CLASSIFICATIONS,
            "is_incentive_eligible": classification in INCENTIVE_ELIGIBLE_CLASSIFICATIONS,
            "is_statutory_exempt": classification in STATUTORY_EXEMPT_CLASSIFICATIONS
        }
    
    return summary


# ============ ENHANCED SALARY PROCESSING WITH DEDUCTIONS ============

@api_router.post("/finance/salary-processing")
async def process_salary_with_deductions(data: SalaryProcessingRequest, request: Request):
    """
    Process salary with structured deductions.
    Creates proper ledger entries for different deduction types.
    ENFORCED: Classification-based statutory deduction rules
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.salaries.pay"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    # Verify employee exists
    employee = await db.users.find_one({"user_id": data.employee_id})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    # Get employee classification and validate
    emp_classification = employee.get("employee_classification", "permanent")
    
    # Classification-based validation for salary processing
    if emp_classification not in SALARY_ELIGIBLE_CLASSIFICATIONS:
        classification_guidance = {
            "trainee": "Trainees should receive Stipend payments. Use the Stipend workflow.",
            "freelancer": "Freelancers should receive Professional Fee payments via Commission workflow.",
            "channel_partner": "Channel Partners should receive Commission payments."
        }
        guidance = classification_guidance.get(emp_classification, f"Classification '{emp_classification}' is not eligible for salary processing.")
        raise HTTPException(
            status_code=400,
            detail=f"Employee '{employee.get('name')}' is classified as '{emp_classification}'. {guidance}"
        )
    
    # Verify salary master exists
    salary_master = await db.finance_salary_master.find_one({"employee_id": data.employee_id})
    if not salary_master:
        raise HTTPException(status_code=404, detail="Salary record not found")
    
    now = datetime.now(timezone.utc)
    
    # Get default statutory deductions for this classification
    default_statutory = DEFAULT_STATUTORY_DEDUCTIONS.get(emp_classification, [])
    provided_deduction_types = [d.deduction_type for d in data.deductions]
    
    # FIX: Do NOT auto-add statutory deductions unless explicitly requested
    # Manual deductions should ONLY deduct the exact entered amount
    # Statutory deductions (PF/ESI/PT) must be explicitly selected by user
    auto_added_deductions = []
    
    # REMOVED: Auto-addition of PF/ESI/Professional Tax
    # Previously, the system would auto-add these deductions if:
    # 1. Employee was permanent/probation
    # 2. No statutory deductions were explicitly provided
    # This caused ₹1,000 manual deduction to become ₹2,012 (₹1000 + PF + ESI + PT)
    #
    # NEW BEHAVIOR: 
    # - Manual deductions reduce Net Payable by EXACT entered amount
    # - Statutory deductions must be explicitly added by user via the deduction form
    # - No hidden calculations unless user explicitly selects statutory deductions
    
    # Validate statutory deductions for exempt classifications
    if emp_classification in STATUTORY_EXEMPT_CLASSIFICATIONS:
        statutory_in_request = [d for d in data.deductions if DEDUCTION_TYPES.get(d.deduction_type, {}).get("statutory", False)]
        if statutory_in_request:
            statutory_names = [DEDUCTION_TYPES[d.deduction_type]["name"] for d in statutory_in_request]
            raise HTTPException(
                status_code=400,
                detail=f"Employee '{employee.get('name')}' is classified as '{emp_classification}' and is exempt from statutory deductions. Remove: {', '.join(statutory_names)}"
            )
    
    # Use ONLY provided deductions (no auto-additions)
    all_deductions = list(data.deductions)
    
    # Calculate deductions breakdown
    deduction_breakdown = []
    total_deductions = 0
    statutory_deductions = 0
    non_statutory_deductions = 0
    
    for ded in all_deductions:
        if ded.deduction_type not in DEDUCTION_TYPES:
            raise HTTPException(status_code=400, detail=f"Invalid deduction type: {ded.deduction_type}")
        
        ded_info = DEDUCTION_TYPES[ded.deduction_type]
        deduction_record = {
            "deduction_id": f"ded_{uuid.uuid4().hex[:8]}",
            "type": ded.deduction_type,
            "type_name": ded_info["name"] if ded.deduction_type != "custom" else ded.custom_label,
            "amount": ded.amount,
            "reason": ded.reason,
            "ledger_impact": ded_info["ledger_impact"],
            "statutory": ded_info["statutory"],
            "auto_calculated": getattr(ded, 'auto_calculated', False),
            "created_at": now.isoformat()
        }
        deduction_breakdown.append(deduction_record)
        total_deductions += ded.amount
        
        if ded_info["statutory"]:
            statutory_deductions += ded.amount
        else:
            non_statutory_deductions += ded.amount
    
    # Calculate net payable
    net_payable = data.gross_salary - total_deductions
    if net_payable < 0:
        raise HTTPException(status_code=400, detail="Net payable cannot be negative")
    
    # Get or create salary cycle
    cycle = await db.finance_salary_cycles.find_one({
        "employee_id": data.employee_id,
        "month_year": data.month_year
    })
    
    if not cycle:
        cycle = {
            "cycle_id": f"cycle_{uuid.uuid4().hex[:12]}",
            "employee_id": data.employee_id,
            "employee_name": employee.get("name", "Unknown"),
            "month_year": data.month_year,
            "gross_salary": data.gross_salary,
            "monthly_salary": salary_master.get("monthly_salary", data.gross_salary),
            "deductions": deduction_breakdown,
            "total_deductions": total_deductions,
            "statutory_deductions": statutory_deductions,
            "non_statutory_deductions": non_statutory_deductions,
            "net_payable": net_payable,
            "total_advances": 0,
            "total_salary_paid": 0,
            "balance_payable": net_payable,
            "carry_forward_recovery": 0,
            "status": "open",
            "processing_notes": data.notes,
            "processed_by": user.user_id,
            "processed_by_name": user_doc.get("name", "Unknown"),
            "created_at": now,
            "updated_at": now
        }
        await db.finance_salary_cycles.insert_one(cycle)
    else:
        if cycle.get("status") == "closed":
            raise HTTPException(status_code=400, detail="Salary cycle already closed")
        
        # Update existing cycle with new deductions
        existing_deductions = cycle.get("deductions", [])
        existing_deductions.extend(deduction_breakdown)
        
        new_total_deductions = cycle.get("total_deductions", 0) + total_deductions
        new_net_payable = data.gross_salary - new_total_deductions
        total_paid = cycle.get("total_advances", 0) + cycle.get("total_salary_paid", 0)
        
        await db.finance_salary_cycles.update_one(
            {"employee_id": data.employee_id, "month_year": data.month_year},
            {"$set": {
                "gross_salary": data.gross_salary,
                "deductions": existing_deductions,
                "total_deductions": new_total_deductions,
                "statutory_deductions": cycle.get("statutory_deductions", 0) + statutory_deductions,
                "non_statutory_deductions": cycle.get("non_statutory_deductions", 0) + non_statutory_deductions,
                "net_payable": new_net_payable,
                "balance_payable": max(0, new_net_payable - total_paid),
                "processing_notes": data.notes,
                "updated_at": now
            }}
        )
    
    updated_cycle = await db.finance_salary_cycles.find_one(
        {"employee_id": data.employee_id, "month_year": data.month_year},
        {"_id": 0}
    )
    
    return {
        "success": True,
        "cycle": updated_cycle,
        "summary": {
            "gross_salary": data.gross_salary,
            "total_deductions": total_deductions,
            "statutory_deductions": statutory_deductions,
            "non_statutory_deductions": non_statutory_deductions,
            "net_payable": net_payable
        },
        "deduction_breakdown": deduction_breakdown
    }


