@api_router.post("/finance/incentives/{incentive_id}/payout")
async def payout_incentive(incentive_id: str, data: IncentivePayoutRequest, request: Request):
    """Process incentive payout"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.incentives.pay") and not has_permission(user_doc, "finance.salaries.pay"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    incentive = await db.finance_incentives.find_one({"incentive_id": incentive_id})
    if not incentive:
        raise HTTPException(status_code=404, detail="Incentive not found")
    
    # Can only payout from approved status (or pending for backward compatibility)
    if incentive.get("status") not in ["pending", "pending_approval", "approved"]:
        raise HTTPException(status_code=400, detail=f"Incentive status is '{incentive.get('status')}'. Can only pay when status is 'approved'.")
    
    # Verify account
    account = await db.accounting_accounts.find_one({"account_id": data.account_id})
    if not account:
        raise HTTPException(status_code=404, detail="Account not found")
    
    now = datetime.now(timezone.utc)
    payment_id = f"incp_{uuid.uuid4().hex[:12]}"
    transaction_id = f"txn_{uuid.uuid4().hex[:12]}"
    
    # Determine category based on incentive type
    category_id = "project_expense" if incentive.get("project_linked") else "hr_expense"
    
    # Ensure category exists
    category = await db.accounting_categories.find_one({"category_id": category_id})
    if not category:
        await db.accounting_categories.insert_one({
            "category_id": category_id,
            "name": "Project Expense" if category_id == "project_expense" else "HR Expense",
            "type": "expense",
            "created_at": now.isoformat()
        })
    
    # Create cashbook entry
    cashbook_entry = {
        "transaction_id": transaction_id,
        "transaction_date": data.payment_date,
        "transaction_type": "outflow",
        "category_id": category_id,
        "amount": incentive.get("amount", 0),
        "mode": "bank_transfer",
        "account_id": data.account_id,
        "project_id": incentive.get("project_id"),
        "paid_to": incentive.get("employee_name", "Employee"),
        "remarks": data.notes or f"Incentive payout: {incentive.get('incentive_type_name')} - {incentive.get('employee_name')}",
        "system_generated": True,
        "source_module": "incentive",
        "source_id": incentive_id,
        "reference_type": "incentive_payout",
        "reference_id": payment_id,
        # FIX: Explicit flags for proper cashbook AND daybook inclusion
        "is_cashbook_entry": True,
        "is_daybook_entry": True,
        # Additional metadata
        "employee_id": incentive.get("employee_id"),
        "employee_name": incentive.get("employee_name", "Employee"),
        "payment_category": "incentive",
        "incentive_type": incentive.get("incentive_type"),
        "created_at": now.isoformat(),
        "created_by": user.user_id,
        "created_by_name": user_doc.get("name", "Unknown")
    }
    
    # Check if day is locked
    day_closing = await db.accounting_daily_closings.find_one({"date": data.payment_date, "is_locked": True})
    if day_closing:
        raise HTTPException(status_code=400, detail=f"Day {data.payment_date} is locked")
    
    await db.accounting_transactions.insert_one(cashbook_entry)
    
    # Update account balance
    await db.accounting_accounts.update_one(
        {"account_id": data.account_id},
        {"$inc": {"current_balance": -incentive.get("amount", 0)}}
    )
    
    # Add history entry for payout
    history_entry = {
        "action": "paid",
        "status": "paid",
        "by": user.user_id,
        "by_name": user_doc.get("name", "Unknown"),
        "at": now.isoformat(),
        "notes": f"Paid ₹{incentive.get('amount', 0)} via {data.account_id}"
    }
    
    # Update incentive record
    await db.finance_incentives.update_one(
        {"incentive_id": incentive_id},
        {
            "$set": {
                "status": "paid",
                "payment_id": payment_id,
                "transaction_id": transaction_id,
                "paid_by": user.user_id,
                "paid_by_name": user_doc.get("name", "Unknown"),
                "paid_at": now,
                "payment_date": data.payment_date,
                "payment_account_id": data.account_id,
                "payment_notes": data.notes,
                "updated_at": now
            },
            "$push": {"history": history_entry}
        }
    )
    
    return {
        "success": True,
        "payment_id": payment_id,
        "transaction_id": transaction_id,
        "amount": incentive.get("amount", 0)
    }


# ============ EXTERNAL COMMISSION MANAGEMENT ============

@api_router.post("/finance/commissions")
async def create_commission(data: CommissionRequest, request: Request):
    """Create commission record for external parties (referrals, channel partners)"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.commissions.create") and not has_permission(user_doc, "finance.salaries.manage"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    if data.commission_type not in COMMISSION_TYPES:
        raise HTTPException(status_code=400, detail=f"Invalid commission type. Must be one of: {list(COMMISSION_TYPES.keys())}")
    
    commission_info = COMMISSION_TYPES[data.commission_type]
    
    # Verify project if linked
    project = None
    if data.project_id:
        project = await db.projects.find_one({"project_id": data.project_id})
    
    now = datetime.now(timezone.utc)
    commission_id = f"com_{uuid.uuid4().hex[:12]}"
    
    # Calculate amount if percentage-based
    final_amount = data.amount
    if data.calculation_type == "percentage" and data.percentage_of:
        final_amount = (data.percentage_of * data.amount) / 100
    
    # Determine initial status (draft if explicitly set, else pending_approval)
    initial_status = data.status or "pending_approval"
    if initial_status not in ["draft", "pending_approval"]:
        initial_status = "pending_approval"
    
    commission_record = {
        "commission_id": commission_id,
        "recipient_type": data.recipient_type,
        "recipient_id": data.recipient_id,
        "recipient_name": data.recipient_name,
        "recipient_contact": data.recipient_contact,
        "commission_type": data.commission_type,
        "commission_type_name": commission_info["name"],
        "ledger_category": commission_info["ledger"],
        "project_id": data.project_id,
        "project_name": project.get("project_name") if project else None,
        "calculation_type": data.calculation_type,
        "percentage_of": data.percentage_of,
        "calculated_amount": final_amount,
        "amount": final_amount,
        "notes": data.notes,
        # Enhanced status: draft, pending_approval, approved, paid, rejected
        "status": initial_status,
        "payment_id": None,
        "transaction_id": None,
        # Audit fields
        "approved_by": None,
        "approved_by_name": None,
        "approved_at": None,
        "rejected_by": None,
        "rejected_by_name": None,
        "rejected_at": None,
        "rejection_reason": None,
        "paid_by": None,
        "paid_by_name": None,
        "paid_at": None,
        # History log
        "history": [{
            "action": "created",
            "status": initial_status,
            "by": user.user_id,
            "by_name": user_doc.get("name", "Unknown"),
            "at": now.isoformat(),
            "notes": f"Created as {initial_status}"
        }],
        "created_by": user.user_id,
        "created_by_name": user_doc.get("name", "Unknown"),
        "created_at": now,
        "updated_at": now
    }
    
    await db.finance_commissions.insert_one(commission_record)
    del commission_record["_id"]
    
    return {
        "success": True,
        "commission": commission_record
    }


@api_router.get("/finance/commissions")
async def get_commissions(
    request: Request,
    project_id: Optional[str] = None,
    status: Optional[str] = None,
    commission_type: Optional[str] = None
):
    """Get commission records with filters"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.commissions.view") and not has_permission(user_doc, "finance.salaries.view_all"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    query = {}
    if project_id:
        query["project_id"] = project_id
    if status:
        query["status"] = status
    if commission_type:
        query["commission_type"] = commission_type
    
    commissions = await db.finance_commissions.find(query, {"_id": 0}).sort("created_at", -1).to_list(500)
    
    total_pending = sum(c.get("amount", 0) for c in commissions if c.get("status") in ["pending", "pending_approval"])
    total_approved = sum(c.get("amount", 0) for c in commissions if c.get("status") == "approved")
    total_paid = sum(c.get("amount", 0) for c in commissions if c.get("status") == "paid")
    
    return {
        "commissions": commissions,
        "summary": {
            "total_pending": total_pending,
            "total_approved": total_approved,
            "total_paid": total_paid,
            "total_count": len(commissions)
        }
    }


@api_router.put("/finance/commissions/{commission_id}/approve")
async def approve_commission(commission_id: str, request: Request):
    """Approve a pending commission"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.commissions.approve") and not has_permission(user_doc, "finance.salaries.manage"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    commission = await db.finance_commissions.find_one({"commission_id": commission_id})
    if not commission:
        raise HTTPException(status_code=404, detail="Commission not found")
    
    if commission.get("status") not in ["draft", "pending", "pending_approval"]:
        raise HTTPException(status_code=400, detail=f"Commission status is '{commission.get('status')}', cannot approve. Only draft/pending can be approved.")
    
    now = datetime.now(timezone.utc)
    
    history_entry = {
        "action": "approved",
        "status": "approved",
        "by": user.user_id,
        "by_name": user_doc.get("name", "Unknown"),
        "at": now.isoformat(),
        "notes": "Approved for payment"
    }
    
    await db.finance_commissions.update_one(
        {"commission_id": commission_id},
        {
            "$set": {
                "status": "approved",
                "approved_by": user.user_id,
                "approved_by_name": user_doc.get("name", "Unknown"),
                "approved_at": now,
                "updated_at": now
            },
            "$push": {"history": history_entry}
        }
    )
    
    return {"success": True, "message": "Commission approved"}


@api_router.put("/finance/commissions/{commission_id}/reject")
async def reject_commission(commission_id: str, request: Request):
    """Reject a commission with reason"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.commissions.approve") and not has_permission(user_doc, "finance.salaries.manage"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    body = await request.json()
    rejection_reason = body.get("reason", "")
    
    commission = await db.finance_commissions.find_one({"commission_id": commission_id})
    if not commission:
        raise HTTPException(status_code=404, detail="Commission not found")
    
    if commission.get("status") not in ["draft", "pending", "pending_approval", "approved"]:
        raise HTTPException(status_code=400, detail=f"Commission status is '{commission.get('status')}', cannot reject.")
    
    now = datetime.now(timezone.utc)
    
    history_entry = {
        "action": "rejected",
        "status": "rejected",
        "by": user.user_id,
        "by_name": user_doc.get("name", "Unknown"),
        "at": now.isoformat(),
        "notes": rejection_reason or "Rejected"
    }
    
    await db.finance_commissions.update_one(
        {"commission_id": commission_id},
        {
            "$set": {
                "status": "rejected",
                "rejected_by": user.user_id,
                "rejected_by_name": user_doc.get("name", "Unknown"),
                "rejected_at": now,
                "rejection_reason": rejection_reason,
                "updated_at": now
            },
            "$push": {"history": history_entry}
        }
    )
    
    return {"success": True, "message": "Commission rejected"}


@api_router.put("/finance/commissions/{commission_id}")
async def update_commission(commission_id: str, request: Request):
    """Edit a commission (only allowed for draft, pending_approval, or rejected status)"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.commissions.create") and not has_permission(user_doc, "finance.salaries.manage"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    commission = await db.finance_commissions.find_one({"commission_id": commission_id})
    if not commission:
        raise HTTPException(status_code=404, detail="Commission not found")
    
    editable_statuses = ["draft", "pending", "pending_approval", "rejected"]
    if commission.get("status") not in editable_statuses:
        raise HTTPException(
            status_code=400,
            detail=f"Commission status is '{commission.get('status')}'. Can only edit when status is: {', '.join(editable_statuses)}"
        )
    
    body = await request.json()
    now = datetime.now(timezone.utc)
    
    update_fields = {}
    allowed_fields = ["amount", "notes", "calculation_type", "percentage_of", "recipient_name", "recipient_contact"]
    for field in allowed_fields:
        if field in body:
            update_fields[field] = body[field]
    
    # Recalculate amount if percentage-based
    if "calculation_type" in update_fields or "percentage_of" in update_fields or "amount" in update_fields:
        calc_type = update_fields.get("calculation_type", commission.get("calculation_type"))
        pct_of = update_fields.get("percentage_of", commission.get("percentage_of"))
        amount = update_fields.get("amount", commission.get("amount"))
        
        if calc_type == "percentage" and pct_of:
            final_amount = (pct_of * amount) / 100
            update_fields["calculated_amount"] = final_amount
            update_fields["amount"] = final_amount
    
    # If rejected, move back to pending_approval on edit
    new_status = commission.get("status")
    if commission.get("status") == "rejected":
        new_status = "pending_approval"
        update_fields["status"] = new_status
        update_fields["rejected_by"] = None
        update_fields["rejected_by_name"] = None
        update_fields["rejected_at"] = None
        update_fields["rejection_reason"] = None
    
    update_fields["updated_at"] = now
    
    history_entry = {
        "action": "edited",
        "status": new_status,
        "by": user.user_id,
        "by_name": user_doc.get("name", "Unknown"),
        "at": now.isoformat(),
        "notes": f"Updated fields: {', '.join(update_fields.keys())}"
    }
    
    await db.finance_commissions.update_one(
        {"commission_id": commission_id},
        {
            "$set": update_fields,
            "$push": {"history": history_entry}
        }
    )
    
    updated = await db.finance_commissions.find_one({"commission_id": commission_id}, {"_id": 0})
    return {"success": True, "commission": updated}


