AUDIT_ENTITY_TYPES = ["cashbook", "receipt", "liability", "project_finance"]
AUDIT_ACTION_TYPES = ["create", "edit", "delete", "verify", "review", "settle", "download", "lock_override", "freeze", "allow_overrun"]

class AuditLogEntry(BaseModel):
    entity_type: str
    entity_id: str
    action: str
    old_value: Optional[dict] = None
    new_value: Optional[dict] = None
    details: Optional[str] = None


async def create_audit_log(
    entity_type: str,
    entity_id: str,
    action: str,
    user_id: str,
    user_name: str,
    old_value: dict = None,
    new_value: dict = None,
    details: str = None
):
    """Create an audit log entry for finance actions"""
    audit_entry = {
        "audit_id": f"aud_{uuid.uuid4().hex[:12]}",
        "entity_type": entity_type,
        "entity_id": entity_id,
        "action": action,
        "old_value": old_value,
        "new_value": new_value,
        "details": details,
        "user_id": user_id,
        "user_name": user_name,
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "ip_address": None  # Can be added from request if needed
    }
    await db.finance_audit_log.insert_one(audit_entry)
    return audit_entry


# ============ CENTRALIZED TRANSACTION SERVICE ============
# All accounting transaction writes MUST go through this function

async def create_accounting_transaction(
    transaction_data: dict,
    user_id: str,
    user_name: str,
    source_module: str,
    skip_balance_update: bool = False,
    skip_party_posting: bool = False
) -> dict:
    """
    Centralized accounting transaction creation with validation.
    
    ALL transaction writes must use this function to ensure:
    - Consistent validation
    - Proper audit logging
    - Balance updates
    - Party sub-ledger posting
    
    Args:
        transaction_data: Dict with transaction fields:
            - transaction_date (required): ISO date string
            - transaction_type (required): "inflow" or "outflow"
            - amount (required): Positive number, max 10 crore
            - category_id (required): Category ID
            - account_id (required): Bank/cash account ID
            - remarks (required): Max 1000 chars
            - mode (optional): Payment mode
            - project_id (optional): Linked project
            - vendor_id (optional): Linked vendor
            - paid_to (optional): Recipient name
            - reference_number (optional): External reference
            - attachment_url (optional): File URL
        user_id: ID of user creating transaction
        user_name: Name of user creating transaction
        source_module: Module creating this (e.g., "cashbook", "salary", "journal_entry")
        skip_balance_update: Skip account balance update (for reversals)
        skip_party_posting: Skip party sub-ledger posting
    
    Returns:
        dict: Created transaction document (without _id)
    
    Raises:
        HTTPException: If validation fails
    """
    now = datetime.now(timezone.utc)
    
    # ========== VALIDATION ==========
    
    # Required fields
    required_fields = ["transaction_date", "transaction_type", "amount", "category_id", "account_id"]
    for field in required_fields:
        if field not in transaction_data or transaction_data[field] is None:
            raise HTTPException(status_code=400, detail=f"Missing required field: {field}")
    
    # Validate transaction_type
    txn_type = transaction_data.get("transaction_type")
    if txn_type not in VALID_TRANSACTION_TYPES:
        raise HTTPException(
            status_code=400, 
            detail=f"Invalid transaction_type: {txn_type}. Must be 'inflow' or 'outflow'"
        )
    
    # Validate amount
    amount = transaction_data.get("amount")
    try:
        amount = float(amount)
    except (TypeError, ValueError):
        raise HTTPException(status_code=400, detail="Amount must be a valid number")
    
    if amount <= 0:
        raise HTTPException(status_code=400, detail="Amount must be positive")
    
    if amount > TRANSACTION_MAX_AMOUNT:
        raise HTTPException(
            status_code=400, 
            detail=f"Amount exceeds maximum limit of ₹{TRANSACTION_MAX_AMOUNT:,.0f}"
        )
    
    # Validate remarks length
    remarks = transaction_data.get("remarks", "")
    if remarks and len(remarks) > TRANSACTION_MAX_REMARKS_LENGTH:
        raise HTTPException(
            status_code=400, 
            detail=f"Remarks exceeds maximum length of {TRANSACTION_MAX_REMARKS_LENGTH} characters"
        )
    
    # Validate transaction_date format
    txn_date = transaction_data.get("transaction_date", "")
    try:
        # Basic ISO date validation
        if len(txn_date) >= 10:
            datetime.strptime(txn_date[:10], "%Y-%m-%d")
    except ValueError:
        raise HTTPException(status_code=400, detail="Invalid transaction_date format. Use YYYY-MM-DD")
    
    # Validate account exists
    account_id = transaction_data.get("account_id")
    account = await db.accounting_accounts.find_one({"account_id": account_id})
    if not account:
        raise HTTPException(status_code=400, detail=f"Invalid account_id: {account_id}")
    
    # ========== CREATE TRANSACTION ==========
    
    txn_id = f"txn_{uuid.uuid4().hex[:12]}"
    
    # Get vendor info if vendor_id provided
    vendor_id = transaction_data.get("vendor_id")
    paid_to = transaction_data.get("paid_to", "")
    if vendor_id and not paid_to:
        vendor = await db.accounting_vendors.find_one({"vendor_id": vendor_id}, {"_id": 0, "vendor_name": 1})
        if vendor:
            paid_to = vendor.get("vendor_name", "")
    
    new_txn = {
        "transaction_id": txn_id,
        "transaction_date": txn_date,
        "transaction_type": txn_type,
        "amount": amount,
        "mode": transaction_data.get("mode", "other"),
        "category_id": transaction_data.get("category_id"),
        "account_id": account_id,
        "project_id": transaction_data.get("project_id"),
        "vendor_id": vendor_id,
        "paid_to": paid_to,
        "remarks": remarks[:TRANSACTION_MAX_REMARKS_LENGTH] if remarks else "",
        "reference_number": transaction_data.get("reference_number", ""),
        "attachment_url": transaction_data.get("attachment_url"),
        
        # Accountability
        "requested_by": transaction_data.get("requested_by"),
        "requested_by_name": transaction_data.get("requested_by_name"),
        "approved_by": transaction_data.get("approved_by"),
        "approved_by_name": transaction_data.get("approved_by_name"),
        "expense_request_id": transaction_data.get("expense_request_id"),
        
        # Metadata
        "source_module": source_module,
        "created_by": user_id,
        "created_by_name": user_name,
        "created_at": now.isoformat(),
        "updated_at": now.isoformat(),
        
        # Verification status
        "is_verified": transaction_data.get("is_verified", False),
        "verified_by": transaction_data.get("verified_by"),
        "verified_at": transaction_data.get("verified_at"),
        
        # Additional fields from transaction_data (for module-specific data)
        "liability_id": transaction_data.get("liability_id"),
        "salary_record_id": transaction_data.get("salary_record_id"),
        "incentive_id": transaction_data.get("incentive_id"),
        "commission_id": transaction_data.get("commission_id"),
        "journal_entry_id": transaction_data.get("journal_entry_id"),
        "receipt_id": transaction_data.get("receipt_id"),
        "refund_id": transaction_data.get("refund_id"),
        "purchase_return_id": transaction_data.get("purchase_return_id"),
        "sales_return_id": transaction_data.get("sales_return_id"),
        "credit_note_id": transaction_data.get("credit_note_id"),
        "debit_note_id": transaction_data.get("debit_note_id"),
        "invoice_id": transaction_data.get("invoice_id"),
    }
    
    # Remove None values to keep document clean
    new_txn = {k: v for k, v in new_txn.items() if v is not None}
    
    # Insert transaction
    await db.accounting_transactions.insert_one(new_txn)
    
    # ========== UPDATE ACCOUNT BALANCE ==========
    if not skip_balance_update:
        balance_change = amount if txn_type == "inflow" else -amount
        await db.accounting_accounts.update_one(
            {"account_id": account_id},
            {"$inc": {"current_balance": balance_change}}
        )
    
    # ========== PARTY SUB-LEDGER POSTING ==========
    if not skip_party_posting:
        # Post to vendor sub-ledger if vendor_id provided (outflow = credit vendor)
        if vendor_id and txn_type == "outflow":
            try:
                vendor_account = await get_party_subledger_account("vendor", vendor_id)
                if vendor_account:
                    await post_party_transaction(
                        party_account_id=vendor_account["account_id"],
                        transaction_type="credit",
                        amount=amount,
                        transaction_id=txn_id,
                        remarks=f"{source_module}: {remarks[:100] if remarks else 'No remarks'}",
                        transaction_date=txn_date,
                        user_id=user_id,
                        user_name=user_name,
                        source_module=source_module
                    )
            except Exception as e:
                logger.warning(f"Failed to post vendor sub-ledger for txn {txn_id}: {e}")
        
        # Post to customer sub-ledger if project_id provided (inflow = credit customer)
        project_id = transaction_data.get("project_id")
        if project_id and txn_type == "inflow":
            try:
                customer_account = await get_party_subledger_account("customer", project_id)
                if customer_account:
                    await post_party_transaction(
                        party_account_id=customer_account["account_id"],
                        transaction_type="credit",
                        amount=amount,
                        transaction_id=txn_id,
                        remarks=f"{source_module}: {remarks[:100] if remarks else 'No remarks'}",
                        transaction_date=txn_date,
                        user_id=user_id,
                        user_name=user_name,
                        source_module=source_module
                    )
            except Exception as e:
                logger.warning(f"Failed to post customer sub-ledger for txn {txn_id}: {e}")
    
    # ========== AUDIT LOG ==========
    await create_audit_log(
        entity_type="transaction",
        entity_id=txn_id,
        action="create",
        user_id=user_id,
        user_name=user_name,
        new_value={"amount": amount, "type": txn_type, "source": source_module},
        details=f"Created {txn_type} of ₹{amount:,.0f} via {source_module}"
    )
    
    # Remove MongoDB _id before returning
    new_txn.pop("_id", None)
    return new_txn


# ============ PARTY SUB-LEDGER HELPER FUNCTIONS ============

async def ensure_control_accounts_exist():
    """Ensure all control accounts exist in the system"""
    for key, ctrl in CONTROL_ACCOUNTS.items():
        existing = await db.party_subledger_accounts.find_one({"account_id": ctrl["account_id"]})
        if not existing:
            await db.party_subledger_accounts.insert_one({
                **ctrl,
                "is_control": True,
                "parent_account_id": None,
                "party_id": None,
                "opening_balance": 0,
                "current_balance": 0,
                "is_active": True,
                "created_at": datetime.now(timezone.utc).isoformat(),
                "created_by": "system"
            })
            logger.info(f"Created control account: {ctrl['account_name']}")


async def create_party_subledger_account(
    party_type: str,
    party_id: str,
    party_name: str,
    user_id: str = "system",
    user_name: str = "System"
) -> dict:
    """
    Create a sub-ledger account for a party (vendor/customer/employee).
    Links to the appropriate control account.
    
    Returns the created account or existing account if already exists.
    """
    # Check if account already exists for this party
    existing = await db.party_subledger_accounts.find_one({
        "party_type": party_type,
        "party_id": party_id,
        "is_control": {"$ne": True}
    })
    if existing:
        existing.pop("_id", None)
        return existing
    
    # Determine control account based on party type
    if party_type == "vendor":
        control = CONTROL_ACCOUNTS["accounts_payable"]
        ledger_type = "liability"
        prefix = "Vendor"
    elif party_type == "customer":
        control = CONTROL_ACCOUNTS["accounts_receivable"]
        ledger_type = "asset"
        prefix = "Customer"
    elif party_type == "employee":
        control = CONTROL_ACCOUNTS["employee_control"]
        ledger_type = "liability"  # Default to payable
        prefix = "Employee"
    else:
        raise ValueError(f"Invalid party_type: {party_type}")
    
    now = datetime.now(timezone.utc).isoformat()
    account_id = f"party_{party_type[:3]}_{uuid.uuid4().hex[:8]}"
    
    new_account = {
        "account_id": account_id,
        "account_name": f"{prefix} – {party_name}",
        "account_type": "party_subledger",
        "ledger_type": ledger_type,
        "party_type": party_type,
        "party_id": party_id,
        "party_name": party_name,
        "parent_account_id": control["account_id"],
        "is_control": False,
        "opening_balance": 0,
        "current_balance": 0,
        "is_active": True,
        "created_at": now,
        "created_by": user_id,
        "created_by_name": user_name
    }
    
    await db.party_subledger_accounts.insert_one(new_account)
    
    # Audit log
    await db.finance_audit_log.insert_one({
        "audit_id": f"aud_{uuid.uuid4().hex[:12]}",
        "entity_type": "party_subledger",
        "entity_id": account_id,
        "action": "create",
        "details": f"Created {party_type} sub-ledger account: {party_name}",
        "user_id": user_id,
        "user_name": user_name,
        "timestamp": now
    })
    
    new_account.pop("_id", None)
    return new_account


async def get_party_subledger_account(party_type: str, party_id: str) -> Optional[dict]:
    """Get the sub-ledger account for a party"""
    account = await db.party_subledger_accounts.find_one({
        "party_type": party_type,
        "party_id": party_id,
        "is_control": {"$ne": True}
    }, {"_id": 0})
    return account


async def update_party_subledger_balance(account_id: str, amount_change: float):
    """Update the balance of a party sub-ledger account"""
    await db.party_subledger_accounts.update_one(
        {"account_id": account_id},
        {"$inc": {"current_balance": amount_change}}
    )
    
    # Also update parent control account
    account = await db.party_subledger_accounts.find_one({"account_id": account_id})
    if account and account.get("parent_account_id"):
        await db.party_subledger_accounts.update_one(
            {"account_id": account["parent_account_id"]},
            {"$inc": {"current_balance": amount_change}}
        )


async def post_party_transaction(
    party_account_id: str,
    transaction_type: str,  # "debit" or "credit"
    amount: float,
    transaction_id: str,
    remarks: str,
    transaction_date: str,
    user_id: str,
    user_name: str,
    source_module: str = "manual"
):
    """
    Post a transaction to a party sub-ledger.
    This creates a double-entry style record.
    """
    now = datetime.now(timezone.utc).isoformat()
    entry_id = f"ple_{uuid.uuid4().hex[:8]}"
    
    party_account = await db.party_subledger_accounts.find_one({"account_id": party_account_id})
    if not party_account:
        raise ValueError(f"Party account not found: {party_account_id}")
    
    ledger_entry = {
        "entry_id": entry_id,
        "party_account_id": party_account_id,
        "party_type": party_account.get("party_type"),
        "party_id": party_account.get("party_id"),
        "party_name": party_account.get("party_name"),
        "transaction_type": transaction_type,
        "amount": amount,
        "linked_transaction_id": transaction_id,
        "transaction_date": transaction_date,
        "remarks": remarks,
        "source_module": source_module,
        "created_at": now,
        "created_by": user_id,
        "created_by_name": user_name
    }
    
    await db.party_ledger_entries.insert_one(ledger_entry)
    
    # Update balance - credits increase liability/decrease asset, debits decrease liability/increase asset
    balance_change = amount if transaction_type == "credit" else -amount
    if party_account.get("ledger_type") == "asset":
        # For assets (receivables): debit increases, credit decreases
        balance_change = -balance_change
    
    await update_party_subledger_balance(party_account_id, balance_change)
    
    return entry_id


@api_router.get("/finance/audit-log")
async def get_audit_log(
    request: Request,
    entity_type: Optional[str] = None,
    entity_id: Optional[str] = None,
    action: Optional[str] = None,
    user_id: Optional[str] = None,
    date_from: Optional[str] = None,
    date_to: Optional[str] = None,
    limit: int = 100,
    skip: int = 0
):
    """Get audit log entries (Admin/Founder only)"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # Only Admin and Founder can view audit log
    if user_doc.get("role") not in ["Admin", "Founder"]:
        raise HTTPException(status_code=403, detail="Only Admin and Founder can view audit log")
    
    # Build query
    query = {}
    if entity_type:
        query["entity_type"] = entity_type
    if entity_id:
        query["entity_id"] = entity_id
    if action:
        query["action"] = action
    if user_id:
        query["user_id"] = user_id
    if date_from or date_to:
        date_query = {}
        if date_from:
            date_query["$gte"] = date_from
        if date_to:
            date_query["$lte"] = date_to + "T23:59:59"
        query["timestamp"] = date_query
    
    # Get total count
    total = await db.finance_audit_log.count_documents(query)
    
    # Get entries
    entries = await db.finance_audit_log.find(
        query,
        {"_id": 0}
    ).sort("timestamp", -1).skip(skip).limit(limit).to_list(limit)
    
    return {
        "entries": entries,
        "total": total,
        "limit": limit,
        "skip": skip
    }


@api_router.get("/finance/audit-log/entity/{entity_type}/{entity_id}")
async def get_entity_audit_history(entity_type: str, entity_id: str, request: Request):
    """Get audit history for a specific entity"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if user_doc.get("role") not in ["Admin", "Founder", "SeniorAccountant"]:
        raise HTTPException(status_code=403, detail="Access denied")
    
    entries = await db.finance_audit_log.find(
        {"entity_type": entity_type, "entity_id": entity_id},
        {"_id": 0}
    ).sort("timestamp", -1).to_list(100)
    
    return {"entries": entries, "count": len(entries)}


# ============ 2. SCHEDULED BACKUPS ============

import subprocess
import gzip
import shutil
from apscheduler.schedulers.asyncio import AsyncIOScheduler
from apscheduler.triggers.cron import CronTrigger

BACKUP_DIR = ROOT_DIR / "backups"
BACKUP_DIR.mkdir(parents=True, exist_ok=True)

# Initialize scheduler (will be started on app startup)
backup_scheduler = AsyncIOScheduler()

# Collections to backup
BACKUP_COLLECTIONS = [
    "finance_audit_log",
    "finance_attachments",
    "finance_liabilities",
    "finance_receipts",
    "finance_salary_master",
    "finance_salary_payments",
    "finance_lock_config",
    "finance_vendors",
    "accounting_transactions",
    "accounting_accounts",
    "accounting_categories",
    "projects",
    "leads",
    "users",
    "presales",
    "import_audit_log",
    "recurring_templates",
    "payment_reminders"
]


async def run_scheduled_backup():
    """Run automated daily backup - called by scheduler at midnight"""
    try:
        backup_id = f"backup_{datetime.now(timezone.utc).strftime('%Y%m%d_%H%M%S')}_auto"
        backup_path = BACKUP_DIR / backup_id
        backup_path.mkdir(parents=True, exist_ok=True)
        
        backup_data = {
            "backup_id": backup_id,
            "created_at": datetime.now(timezone.utc).isoformat(),
            "created_by": "system",
            "created_by_name": "Scheduled Backup",
            "collections": {},
            "status": "in_progress",
            "backup_type": "scheduled"
        }
        
        # Export each collection to JSON
        for collection_name in BACKUP_COLLECTIONS:
            try:
                collection = db[collection_name]
                docs = await collection.find({}, {"_id": 0}).to_list(100000)
                
                # Save to file
                file_path = backup_path / f"{collection_name}.json"
                async with aiofiles.open(file_path, 'w') as f:
                    await f.write(json.dumps(docs, default=str, indent=2))
                
                backup_data["collections"][collection_name] = {
                    "count": len(docs),
                    "file": f"{collection_name}.json"
                }
            except Exception as e:
                backup_data["collections"][collection_name] = {
                    "error": str(e)
                }
        
        backup_data["status"] = "completed"
        backup_data["completed_at"] = datetime.now(timezone.utc).isoformat()
        
        # Save backup metadata
        meta_path = backup_path / "backup_meta.json"
        async with aiofiles.open(meta_path, 'w') as f:
            await f.write(json.dumps(backup_data, indent=2))
        
        # Create audit log for scheduled backup
        await create_audit_log(
            entity_type="system",
            entity_id=backup_id,
            action="backup_created",
            user_id="system",
            user_name="Scheduled Backup",
            details=f"Automated daily backup with {len(backup_data['collections'])} collections"
        )
        
        logger.info(f"Scheduled backup completed: {backup_id} ({len(backup_data['collections'])} collections)")
        
    except Exception as e:
        logger.error(f"Scheduled backup failed: {str(e)}")


# DISABLED: Auto-seeding removed to prevent duplicate admin conflicts
# The first user to log in via Google OAuth with Admin-designated email becomes Admin
# @app.on_event("startup")
# async def seed_initial_admin():
#     """DISABLED - Use Google OAuth for admin creation"""
#     pass


@app.on_event("startup")
async def start_backup_scheduler():
    """Start the backup scheduler on application startup"""
    # Schedule daily backup at midnight (00:00 server time)
    backup_scheduler.add_job(
        run_scheduled_backup,
        CronTrigger(hour=0, minute=0),
        id="daily_backup",
        name="Daily Database Backup",
        replace_existing=True
    )
    backup_scheduler.start()
    logger.info("Backup scheduler started - daily backups at midnight")


@app.on_event("shutdown")
async def stop_backup_scheduler():
    """Stop the backup scheduler on application shutdown"""
    if backup_scheduler.running:
        backup_scheduler.shutdown(wait=False)
        logger.info("Backup scheduler stopped")


