@api_router.put("/finance/sales-returns/{return_id}/replacement")
async def update_sales_return_replacement(
    return_id: str,
    request: Request,
    replacement_status: str = "delivered",
    replacement_delivered_date: Optional[str] = None,
    replacement_cost: Optional[float] = None,
    notes: Optional[str] = None
):
    """Mark replacement as delivered for a sales return"""
    user = await get_current_user(request)
    
    return_doc = await db.finance_returns.find_one({"return_id": return_id, "return_type": "sales"})
    if not return_doc:
        raise HTTPException(status_code=404, detail="Sales return not found")
    
    if not return_doc.get("requires_replacement"):
        raise HTTPException(status_code=400, detail="This return does not require replacement")
    
    now = datetime.now(timezone.utc)
    
    update_data = {
        "replacement_status": replacement_status,
        "replacement_delivered_date": replacement_delivered_date or now.strftime("%Y-%m-%d"),
        "updated_at": now.isoformat()
    }
    
    if replacement_cost is not None:
        update_data["replacement_cost"] = replacement_cost
    if notes:
        update_data["replacement_notes"] = notes
    
    await db.finance_returns.update_one(
        {"return_id": return_id},
        {"$set": update_data}
    )
    
    updated = await db.finance_returns.find_one({"return_id": return_id}, {"_id": 0})
    return {"success": True, "return": updated}


# ============ RETURNED ITEMS REGISTER ============

@api_router.get("/finance/returned-items-register")
async def get_returned_items_register(
    request: Request,
    return_type: Optional[str] = None,  # "purchase" | "sales" | None for all
    item_disposition: Optional[str] = None,
    refund_status: Optional[str] = None,
    project_id: Optional[str] = None,
    from_date: Optional[str] = None,
    to_date: Optional[str] = None
):
    """
    Returned Items Register - Aggregated view of all returns (Purchase + Sales).
    Tracks both refund status and item disposition independently.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.view_cashbook"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    query = {}
    
    if return_type:
        query["return_type"] = return_type
    if item_disposition:
        query["item_disposition"] = item_disposition
    if refund_status:
        query["refund_status"] = refund_status
    if project_id:
        query["project_id"] = project_id
    if from_date:
        query["return_date"] = {"$gte": from_date}
    if to_date:
        query.setdefault("return_date", {})["$lte"] = to_date
    
    returns = await db.finance_returns.find(query, {"_id": 0}).sort("return_date", -1).to_list(1000)
    
    # Flatten items for register view
    register_items = []
    for ret in returns:
        items = ret.get("items_returned", [])
        for item in items:
            register_items.append({
                "return_id": ret.get("return_id"),
                "return_date": ret.get("return_date"),
                "return_type": ret.get("return_type"),
                "project_id": ret.get("project_id"),
                "vendor_id": ret.get("vendor_id"),
                "vendor_name": ret.get("vendor_name"),
                "customer_id": ret.get("customer_id"),
                "customer_name": ret.get("customer_name"),
                "item_name": item.get("item_name"),
                "qty": item.get("qty"),
                "rate": item.get("rate"),
                "amount": item.get("amount"),
                "item_disposition": ret.get("item_disposition"),
                "disposition_location": ret.get("disposition_location"),
                "refund_status": ret.get("refund_status"),
                "refund_mode": ret.get("refund_mode"),
                "return_reason": ret.get("return_reason"),
                "remarks": ret.get("remarks")
            })
    
    # Calculate summary
    total_with_company = sum(
        r.get("total_return_value", 0) for r in returns 
        if r.get("item_disposition") in ["with_company_office", "with_company_site", "pending_decision"]
    )
    total_returned_to_vendor = sum(
        r.get("total_return_value", 0) for r in returns 
        if r.get("item_disposition") == "returned_to_vendor"
    )
    total_scrapped = sum(
        r.get("total_return_value", 0) for r in returns 
        if r.get("item_disposition") in ["scrapped", "vendor_rejected"]
    )
    total_pending_refund = sum(
        r.get("expected_refund_amount", r.get("refund_amount", 0)) for r in returns 
        if r.get("refund_status") == "pending"
    )
    total_loss = sum(r.get("loss_amount", 0) for r in returns if r.get("is_loss_entry"))
    
    return {
        "items": register_items,
        "summary": {
            "total_returns": len(returns),
            "total_items": len(register_items),
            "items_with_company": {
                "count": len([r for r in returns if r.get("item_disposition") in ["with_company_office", "with_company_site", "pending_decision"]]),
                "value": total_with_company
            },
            "items_returned_to_vendor": {
                "count": len([r for r in returns if r.get("item_disposition") == "returned_to_vendor"]),
                "value": total_returned_to_vendor
            },
            "items_scrapped": {
                "count": len([r for r in returns if r.get("item_disposition") in ["scrapped", "vendor_rejected"]]),
                "value": total_scrapped
            },
            "pending_refunds": total_pending_refund,
            "total_loss": total_loss
        },
        "filters_applied": {
            "return_type": return_type,
            "item_disposition": item_disposition,
            "refund_status": refund_status,
            "project_id": project_id,
            "from_date": from_date,
            "to_date": to_date
        }
    }


# ============ RETURNS EXCEPTIONS PANEL API ============

@api_router.get("/finance/returns/exceptions")
async def get_returns_exceptions(request: Request):
    """
    Get actionable exceptions for Returns module.
    Returns only items that need attention - no summaries or counts.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.view_cashbook"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    from datetime import datetime, timedelta
    today = datetime.now(timezone.utc).date()
    
    exceptions = []
    
    # 1. Pending Purchase Return refunds (by aging)
    purchase_returns = await db.finance_returns.find({
        "return_type": "purchase",
        "refund_status": "pending",
        "expected_refund_amount": {"$gt": 0}
    }, {"_id": 0}).to_list(100)
    
    for pr in purchase_returns:
        return_date = pr.get("return_date", "")
        if return_date:
            try:
                rd = datetime.strptime(return_date, "%Y-%m-%d").date()
                days_pending = (today - rd).days
                aging_label = f"{days_pending}d" if days_pending > 0 else "Today"
            except:
                aging_label = "N/A"
                days_pending = 0
        else:
            aging_label = "N/A"
            days_pending = 0
        
        exceptions.append({
            "type": "purchase_refund_pending",
            "category": "Pending Purchase Refunds",
            "text": f"{pr.get('vendor_name', 'Unknown Vendor')} - ₹{pr.get('expected_refund_amount', 0):,.0f}",
            "aging": aging_label,
            "days_pending": days_pending,
            "reference_id": pr.get("return_id"),
            "navigate_to": f"/finance/purchase-returns?highlight={pr.get('return_id')}"
        })
    
    # 2. Pending Sales Return refunds
    sales_returns = await db.finance_returns.find({
        "return_type": "sales",
        "refund_status": "pending",
        "refund_amount": {"$gt": 0}
    }, {"_id": 0}).to_list(100)
    
    for sr in sales_returns:
        return_date = sr.get("return_date", "")
        if return_date:
            try:
                rd = datetime.strptime(return_date, "%Y-%m-%d").date()
                days_pending = (today - rd).days
                aging_label = f"{days_pending}d" if days_pending > 0 else "Today"
            except:
                aging_label = "N/A"
                days_pending = 0
        else:
            aging_label = "N/A"
            days_pending = 0
        
        exceptions.append({
            "type": "sales_refund_pending",
            "category": "Pending Sales Refunds",
            "text": f"{sr.get('customer_name', 'Unknown Customer')} - ₹{sr.get('refund_amount', 0):,.0f}",
            "aging": aging_label,
            "days_pending": days_pending,
            "reference_id": sr.get("return_id"),
            "navigate_to": f"/finance/sales-returns?highlight={sr.get('return_id')}"
        })
    
    # 3. Returned items "With Company" awaiting disposition
    with_company_returns = await db.finance_returns.find({
        "item_disposition": {"$in": ["with_company_office", "with_company_site", "pending_decision"]}
    }, {"_id": 0}).to_list(100)
    
    for ret in with_company_returns:
        disposition = ret.get("item_disposition", "pending_decision")
        location = ret.get("disposition_location", "")
        loc_text = f" at {location}" if location else ""
        disp_label = {
            "with_company_office": "Office",
            "with_company_site": "Site",
            "pending_decision": "Pending Decision"
        }.get(disposition, disposition)
        
        return_type = ret.get("return_type", "purchase")
        route = "purchase-returns" if return_type == "purchase" else "sales-returns"
        
        exceptions.append({
            "type": "awaiting_disposition",
            "category": "Items Awaiting Disposition",
            "text": f"{ret.get('vendor_name') or ret.get('customer_name', 'Unknown')} - {disp_label}{loc_text}",
            "aging": "",
            "days_pending": 0,
            "reference_id": ret.get("return_id"),
            "navigate_to": f"/finance/{route}?highlight={ret.get('return_id')}"
        })
    
    # 4. Pending replacement deliveries
    pending_replacements = await db.finance_replacement_orders.find({
        "status": {"$in": ["pending", "processing", "dispatched"]}
    }, {"_id": 0}).to_list(100)
    
    for repl in pending_replacements:
        status = repl.get("status", "pending")
        status_label = {"pending": "Not Started", "processing": "Processing", "dispatched": "In Transit"}.get(status, status)
        priority = repl.get("priority", "normal")
        priority_marker = "🔴 " if priority == "urgent" else ""
        
        exceptions.append({
            "type": "replacement_pending",
            "category": "Pending Replacements",
            "text": f"{priority_marker}{repl.get('customer_name', 'Unknown Customer')} - {status_label}",
            "aging": "",
            "days_pending": 0,
            "reference_id": repl.get("order_id"),
            "navigate_to": f"/finance/replacement-orders?highlight={repl.get('order_id')}"
        })
    
    # 5. Unused vendor credits (from debit notes)
    unused_debit_notes = await db.finance_debit_notes.find({
        "balance_amount": {"$gt": 0},
        "status": {"$ne": "cancelled"}
    }, {"_id": 0}).to_list(100)
    
    for dn in unused_debit_notes:
        exceptions.append({
            "type": "unused_vendor_credit",
            "category": "Unused Vendor Credits",
            "text": f"{dn.get('vendor_name', 'Unknown Vendor')} - ₹{dn.get('balance_amount', 0):,.0f}",
            "aging": "",
            "days_pending": 0,
            "reference_id": dn.get("debit_note_id"),
            "navigate_to": f"/finance/debit-notes?highlight={dn.get('debit_note_id')}"
        })
    
    # 6. Unused customer credits (from credit notes)
    unused_credit_notes = await db.finance_credit_notes.find({
        "balance_amount": {"$gt": 0},
        "status": {"$ne": "cancelled"}
    }, {"_id": 0}).to_list(100)
    
    for cn in unused_credit_notes:
        exceptions.append({
            "type": "unused_customer_credit",
            "category": "Unused Customer Credits",
            "text": f"{cn.get('customer_name', 'Unknown Customer')} - ₹{cn.get('balance_amount', 0):,.0f}",
            "aging": "",
            "days_pending": 0,
            "reference_id": cn.get("credit_note_id"),
            "navigate_to": f"/finance/credit-notes?highlight={cn.get('credit_note_id')}"
        })
    
    # Sort by priority: aging first, then by category
    exceptions.sort(key=lambda x: (-x.get("days_pending", 0), x.get("category", "")))
    
    return {
        "exceptions": exceptions,
        "has_exceptions": len(exceptions) > 0
    }


# ============ PHASE 2: CREDIT NOTES, DEBIT NOTES & ENHANCED RETURNS ============

class ItemLevelDisposition(BaseModel):
    """Update disposition for a specific item in a return"""
    item_index: int  # Index of the item in items_returned array
    disposition: str  # "returned_to_vendor" | "with_company_office" | "with_company_site" | "scrapped" | "vendor_rejected" | "pending_decision" | "reused_other_project"
    location: Optional[str] = None
    notes: Optional[str] = None


class CreditNoteCreate(BaseModel):
    """Create a Credit Note (Sales Return - we owe customer)"""
    linked_return_id: str  # Link to sales return
    credit_note_date: str
    amount: float
    gst_amount: Optional[float] = 0
    reason: str
    remarks: Optional[str] = None


class DebitNoteCreate(BaseModel):
    """Create a Debit Note (Purchase Return - vendor owes us)"""
    linked_return_id: str  # Link to purchase return
    debit_note_date: str
    amount: float
    gst_amount: Optional[float] = 0
    reason: str
    remarks: Optional[str] = None


class ReplacementOrderCreate(BaseModel):
    """Create a replacement order for a sales return"""
    linked_return_id: str
    replacement_items: List[dict]  # [{item_name, qty, specifications, notes}]
    expected_dispatch_date: Optional[str] = None
    delivery_address: Optional[str] = None
    priority: str = "normal"  # "urgent" | "normal" | "low"
    remarks: Optional[str] = None


class ReplacementStatusUpdate(BaseModel):
    """Update replacement order status"""
    status: str  # "pending" | "processing" | "dispatched" | "delivered" | "cancelled"
    dispatch_date: Optional[str] = None
    delivery_date: Optional[str] = None
    tracking_number: Optional[str] = None
    delivered_by: Optional[str] = None
    delivery_proof: Optional[str] = None  # File URL
    remarks: Optional[str] = None


@api_router.put("/finance/returns/{return_id}/item-disposition")
async def update_item_level_disposition(
    return_id: str,
    updates: List[ItemLevelDisposition],
    request: Request
):
    """
    Phase 2: Update disposition for individual items in a return.
    Allows each item to have its own disposition status.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.liabilities.create") and not has_permission(user_doc, "finance.invoices.create"):
        raise HTTPException(status_code=403, detail="Access denied")
    
    return_doc = await db.finance_returns.find_one({"return_id": return_id})
    if not return_doc:
        raise HTTPException(status_code=404, detail="Return not found")
    
    items = return_doc.get("items_returned", [])
    now = datetime.now(timezone.utc)
    
    for update in updates:
        if update.item_index < 0 or update.item_index >= len(items):
            raise HTTPException(status_code=400, detail=f"Invalid item index: {update.item_index}")
        
        items[update.item_index]["disposition"] = update.disposition
        items[update.item_index]["disposition_location"] = update.location
        items[update.item_index]["disposition_notes"] = update.notes
        items[update.item_index]["disposition_updated_at"] = now.isoformat()
        items[update.item_index]["disposition_updated_by"] = user.user_id
    
    # Update document
    await db.finance_returns.update_one(
        {"return_id": return_id},
        {
            "$set": {
                "items_returned": items,
                "updated_at": now.isoformat()
            }
        }
    )
    
    return {"success": True, "message": f"Updated disposition for {len(updates)} items"}


@api_router.post("/finance/credit-notes")
async def create_credit_note(data: CreditNoteCreate, request: Request):
    """
    Phase 2: Create a Credit Note for a Sales Return.
    Credit notes reduce the amount customer owes or create a liability to customer.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    if not has_permission(user_doc, "finance.invoices.create"):
        raise HTTPException(status_code=403, detail="Access denied - requires finance.invoices.create permission")
    
    # Validate linked return
    return_doc = await db.finance_returns.find_one({"return_id": data.linked_return_id})
    if not return_doc:
        raise HTTPException(status_code=404, detail="Linked return not found")
    
    if return_doc.get("return_type") != "sales":
        raise HTTPException(status_code=400, detail="Credit notes can only be created for sales returns")
    
    # Check if credit note already exists
    existing = await db.finance_credit_notes.find_one({"linked_return_id": data.linked_return_id})
    if existing:
        raise HTTPException(status_code=400, detail="Credit note already exists for this return")
    
    now = datetime.now(timezone.utc)
    credit_note_id = f"CN-{now.strftime('%Y%m')}-{uuid.uuid4().hex[:6].upper()}"
    
    credit_note_doc = {
        "credit_note_id": credit_note_id,
        "linked_return_id": data.linked_return_id,
        "linked_invoice_id": return_doc.get("linked_invoice_id"),
        "project_id": return_doc.get("project_id"),
        "customer_id": return_doc.get("customer_id"),
        "customer_name": return_doc.get("customer_name"),
        "credit_note_date": data.credit_note_date,
        "amount": data.amount,
        "gst_amount": data.gst_amount,
        "total_amount": data.amount + data.gst_amount,
        "reason": data.reason,
        "status": "issued",
        "utilized_amount": 0,
        "balance_amount": data.amount + data.gst_amount,
        "remarks": data.remarks,
        "created_by": user.user_id,
        "created_by_name": user_doc.get("name", "Unknown"),
        "created_at": now.isoformat(),
        "updated_at": now.isoformat()
    }
    
    await db.finance_credit_notes.insert_one(credit_note_doc)
    
    # Update the return with credit note link
    await db.finance_returns.update_one(
        {"return_id": data.linked_return_id},
        {
            "$set": {
                "linked_credit_note_id": credit_note_id,
                "updated_at": now.isoformat()
            }
        }
    )
    
    # Create accounting transaction
    txn_id = f"txn_{uuid.uuid4().hex[:12]}"
    await db.accounting_transactions.insert_one({
        "transaction_id": txn_id,
        "transaction_date": data.credit_note_date,
        "transaction_type": "credit_note",
        "entry_type": "credit_note_issued",
        "amount": data.amount + data.gst_amount,
        "description": f"Credit Note {credit_note_id} - {data.reason}",
        "project_id": return_doc.get("project_id"),
        "customer_id": return_doc.get("customer_id"),
        "reference_type": "credit_note",
        "reference_id": credit_note_id,
        "created_by": user.user_id,
        "created_at": now.isoformat()
    })
    
    credit_note_doc.pop("_id", None)
    return {"success": True, "credit_note": credit_note_doc}


