@api_router.get("/finance/execution-ledger/export/{project_id}")
async def export_execution_ledger(project_id: str, request: Request, format: str = "csv"):
    """Export execution ledger for a project (CSV or Excel)"""
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    # BUG FIX: Use permission check instead of role check
    if not has_permission(user_doc, "finance.reports.export") and not has_permission(user_doc, "finance.export_data"):
        raise HTTPException(status_code=403, detail="Access denied - requires finance.reports.export or finance.export_data permission")
    
    project = await db.projects.find_one({"project_id": project_id})
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    
    entries = await db.execution_ledger.find(
        {"project_id": project_id},
        {"_id": 0}
    ).sort("execution_date", -1).to_list(5000)
    
    if not entries:
        raise HTTPException(status_code=404, detail="No execution entries found for this project")
    
    # Prepare export data
    export_rows = []
    for entry in entries:
        export_rows.append({
            "Execution ID": entry.get("execution_id", ""),
            "Date": entry.get("execution_date", ""),
            "Category": entry.get("category", ""),
            "Material/Service": entry.get("material_name", ""),
            "Specification": entry.get("specification", ""),
            "Brand": entry.get("brand", ""),
            "Size/Unit": entry.get("size_unit", ""),
            "Quantity": entry.get("quantity", 0),
            "Rate": entry.get("rate_per_unit", 0),
            "Total Value": entry.get("total_value", 0),
            "Vendor": entry.get("vendor", ""),
            "Remarks": entry.get("remarks", ""),
            "Created By": entry.get("created_by_name", ""),
            "Created At": entry.get("created_at", "")
        })
    
    project_name = project.get("project_name", "Project").replace(" ", "_")
    
    if format.lower() == "excel":
        from openpyxl import Workbook
        from io import BytesIO
        
        wb = Workbook()
        ws = wb.active
        ws.title = "Execution Ledger"
        
        # Header
        headers = list(export_rows[0].keys()) if export_rows else []
        ws.append(headers)
        
        # Data
        for row in export_rows:
            ws.append(list(row.values()))
        
        # Auto-width columns
        for col in ws.columns:
            max_length = 0
            column = col[0].column_letter
            for cell in col:
                try:
                    if len(str(cell.value)) > max_length:
                        max_length = len(str(cell.value))
                except:
                    pass
            ws.column_dimensions[column].width = min(max_length + 2, 50)
        
        output = BytesIO()
        wb.save(output)
        output.seek(0)
        
        return StreamingResponse(
            output,
            media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            headers={"Content-Disposition": f"attachment; filename=Execution_Ledger_{project_name}.xlsx"}
        )
    else:
        # CSV format
        from io import StringIO
        import csv
        
        output = StringIO()
        if export_rows:
            writer = csv.DictWriter(output, fieldnames=export_rows[0].keys())
            writer.writeheader()
            writer.writerows(export_rows)
        
        return StreamingResponse(
            iter([output.getvalue()]),
            media_type="text/csv",
            headers={"Content-Disposition": f"attachment; filename=Execution_Ledger_{project_name}.csv"}
        )


# ============ DOCUMENT ATTACHMENT (PROOF) LAYER ============

# Finance attachments directory
FINANCE_UPLOADS_DIR = ROOT_DIR / "uploads" / "finance"
FINANCE_UPLOADS_DIR.mkdir(parents=True, exist_ok=True)

# Allowed file types and max size
ALLOWED_ATTACHMENT_TYPES = {
    "application/pdf": ".pdf",
    "image/jpeg": ".jpg",
    "image/png": ".png",
    "image/jpg": ".jpg"
}
MAX_ATTACHMENT_SIZE = 15 * 1024 * 1024  # 15MB

# Valid entity types for attachments
VALID_ATTACHMENT_ENTITIES = ["cashbook", "expense", "project", "liability", "execution"]


class AttachmentMetadata(BaseModel):
    description: Optional[str] = None


@api_router.post("/finance/attachments/upload")
async def upload_finance_attachment(
    request: Request,
    file: UploadFile = File(...),
    entity_type: str = "cashbook",
    entity_id: str = "",
    description: str = ""
):
    """
    Upload a document attachment for finance entities.
    Supports: Cashbook, Expense Requests, Project Finance, Liabilities
    Max size: 15MB
    Allowed types: PDF, JPG, PNG
    """
    user = await get_current_user(request)
    
    # Validate entity type
    if entity_type not in VALID_ATTACHMENT_ENTITIES:
        raise HTTPException(
            status_code=400, 
            detail=f"Invalid entity type. Must be one of: {VALID_ATTACHMENT_ENTITIES}"
        )
    
    # Validate entity_id is provided
    if not entity_id:
        raise HTTPException(status_code=400, detail="entity_id is required")
    
    # Use centralized file validation (PDF, JPG, PNG only)
    finance_allowed_extensions = {".pdf", ".jpg", ".jpeg", ".png"}
    content, safe_filename, file_ext = await validated_file_upload(
        file=file,
        allowed_extensions=finance_allowed_extensions,
        max_size_bytes=MAX_ATTACHMENT_SIZE,  # 15MB
        validate_content=True,
        context="finance attachment"
    )
    
    # Generate unique filename with entity context
    now = datetime.now(timezone.utc)
    year_month = now.strftime("%Y/%m")
    unique_id = uuid.uuid4().hex[:12]
    final_filename = f"{entity_type}_{entity_id}_{unique_id}{file_ext}"
    
    # Create directory structure
    upload_dir = FINANCE_UPLOADS_DIR / year_month
    upload_dir.mkdir(parents=True, exist_ok=True)
    
    file_path = upload_dir / final_filename
    relative_path = f"finance/{year_month}/{final_filename}"
    
    # Save file
    async with aiofiles.open(file_path, 'wb') as f:
        await f.write(content)
    
    # Map extension to mime type
    ext_to_mime = {".pdf": "application/pdf", ".jpg": "image/jpeg", ".jpeg": "image/jpeg", ".png": "image/png"}
    mime_type = ext_to_mime.get(file_ext, "application/octet-stream")
    
    # Create attachment metadata
    attachment_id = f"att_{uuid.uuid4().hex[:12]}"
    original_filename = file.filename or "unknown"
    
    attachment_doc = {
        "attachment_id": attachment_id,
        "entity_type": entity_type,
        "entity_id": entity_id,
        "file_name": original_filename,
        "file_path": relative_path,
        "file_size": len(content),
        "mime_type": mime_type,
        "description": description,
        "uploaded_by": user.user_id,
        "uploaded_by_name": user.name,
        "uploaded_at": now.isoformat()
    }
    
    await db.finance_attachments.insert_one(attachment_doc)
    
    # Return without _id
    attachment_doc.pop("_id", None)
    
    return {
        "success": True,
        "message": "Attachment uploaded successfully",
        "attachment": attachment_doc
    }


@api_router.get("/finance/attachments/download/{attachment_id}")
async def download_finance_attachment(attachment_id: str, request: Request):
    """
    Download an attachment file.
    """
    user = await get_current_user(request)
    
    attachment = await db.finance_attachments.find_one(
        {"attachment_id": attachment_id},
        {"_id": 0}
    )
    
    if not attachment:
        raise HTTPException(status_code=404, detail="Attachment not found")
    
    file_path = ROOT_DIR / "uploads" / attachment["file_path"]
    
    if not file_path.exists():
        raise HTTPException(status_code=404, detail="File not found on server")
    
    return FileResponse(
        path=str(file_path),
        filename=attachment["file_name"],
        media_type=attachment["mime_type"]
    )


@api_router.get("/finance/attachments/by-ids")
async def get_attachments_by_ids(
    request: Request,
    ids: str = ""  # Comma-separated attachment IDs
):
    """
    Get attachment metadata by multiple IDs (for exports).
    """
    user = await get_current_user(request)
    
    if not ids:
        return {"attachments": []}
    
    attachment_ids = [aid.strip() for aid in ids.split(",") if aid.strip()]
    
    attachments = await db.finance_attachments.find(
        {"attachment_id": {"$in": attachment_ids}},
        {"_id": 0}
    ).to_list(100)
    
    return {"attachments": attachments}


@api_router.get("/finance/attachments/{entity_type}/{entity_id}")
async def list_finance_attachments(
    entity_type: str,
    entity_id: str,
    request: Request
):
    """
    List all attachments for a specific entity.
    """
    user = await get_current_user(request)
    
    if entity_type not in VALID_ATTACHMENT_ENTITIES:
        raise HTTPException(
            status_code=400,
            detail=f"Invalid entity type. Must be one of: {VALID_ATTACHMENT_ENTITIES}"
        )
    
    attachments = await db.finance_attachments.find(
        {"entity_type": entity_type, "entity_id": entity_id},
        {"_id": 0}
    ).sort("uploaded_at", -1).to_list(100)
    
    return {"attachments": attachments, "count": len(attachments)}


@api_router.delete("/finance/attachments/{attachment_id}")
async def delete_finance_attachment(attachment_id: str, request: Request):
    """
    Delete an attachment. Only uploader or admin can delete.
    """
    user = await get_current_user(request)
    user_doc = await db.users.find_one({"user_id": user.user_id})
    
    attachment = await db.finance_attachments.find_one(
        {"attachment_id": attachment_id},
        {"_id": 0}
    )
    
    if not attachment:
        raise HTTPException(status_code=404, detail="Attachment not found")
    
    # Check permission: uploader or admin
    if attachment["uploaded_by"] != user.user_id and user_doc.get("role") != "Admin":
        raise HTTPException(status_code=403, detail="You can only delete your own attachments")
    
    # Delete file from filesystem
    file_path = ROOT_DIR / "uploads" / attachment["file_path"]
    if file_path.exists():
        file_path.unlink()
    
    # Delete from database
    await db.finance_attachments.delete_one({"attachment_id": attachment_id})
    
    return {"success": True, "message": "Attachment deleted successfully"}


